/* AUTO-GENERATED — Illinois Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["IL"] = {"code":"IL","name":"Illinois","agency":"Illinois SOS","agencyShort":"SOS","handbook":"https://www.ilsos.gov/publications/motorist/comdrivers.html","links":{},"en":[{"q":"On Illinois highways, what is the maximum width of a commercial vehicle, exclusive of approved safety devices and mirrors?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"answer":0,"explanation":"Illinois limits vehicle width to 8 feet 6 inches (102 inches), not counting mirrors and other approved safety devices. Source: 625 ILCS 5/15-102; Illinois CDL/Rules of the Road.","handbook":"","hbref":""},{"q":"What is the maximum height of a vehicle, including its load, allowed on Illinois highways?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","12 feet 6 inches"],"answer":0,"explanation":"Illinois caps total height, measured from the road surface to the top of the load, at 13 feet 6 inches. Source: 625 ILCS 5/15-103.","handbook":"","hbref":""},{"q":"What is the maximum gross weight of a vehicle combination of five or more axles operating on Illinois highways without a permit?","options":["80,000 pounds","73,280 pounds","84,000 pounds","88,000 pounds"],"answer":0,"explanation":"Illinois adopts the federal maximum of 80,000 pounds gross weight for combinations of five or more axles. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a single axle on Illinois highways?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"answer":0,"explanation":"Illinois limits a single axle to 20,000 pounds, matching the federal standard. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tandem axle group on Illinois highways?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"answer":0,"explanation":"Illinois limits a tandem axle to 34,000 pounds, with no single axle within the tandem exceeding 20,000 pounds. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"What is the maximum length of a single straight (rigid) truck on Illinois highways?","options":["42 feet","40 feet","45 feet","53 feet"],"answer":0,"explanation":"A single vehicle such as a straight truck may not exceed 42 feet in overall length in Illinois. Source: 625 ILCS 5/15-107.","handbook":"","hbref":""},{"q":"On the designated highway (National Network) system in Illinois, what is the maximum length of a single semitrailer operated in a tractor-semitrailer combination?","options":["53 feet","48 feet","57 feet","60 feet"],"answer":0,"explanation":"Illinois permits semitrailers up to 53 feet in a tractor-semitrailer combination, consistent with the federal National Network standard. Source: 625 ILCS 5/15-107.","handbook":"","hbref":""},{"q":"Which formula does Illinois use to determine the maximum allowable gross weight based on axle spacing and the number of axles?","options":["The Federal Bridge Formula (weight-distance formula)","The Gross Combination Rating formula","The Tire-Load Index formula","The Registered Weight Class formula"],"answer":0,"explanation":"Illinois uses the Federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], to set maximum gross weight by axle spacing (L) and number of axles (N). Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"In Illinois, who issues a state oversize/overweight permit for a load that exceeds legal size or weight limits on a state-maintained highway?","options":["The Illinois Department of Transportation (IDOT)","The Illinois Secretary of State","The Illinois State Police","The Federal Motor Carrier Safety Administration"],"answer":0,"explanation":"IDOT issues oversize/overweight permits for movements on state-maintained highways under its statutory authority. Source: 625 ILCS 5/15-301; IDOT Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"An Illinois oversize/overweight permit is generally required when a vehicle or load exceeds which of the following?","options":["8 feet 6 inches wide, 13 feet 6 inches high, or 80,000 pounds gross weight","8 feet 0 inches wide, 13 feet 0 inches high, or 73,280 pounds gross weight","9 feet 0 inches wide, 14 feet 0 inches high, or 84,000 pounds gross weight","10 feet 0 inches wide, 15 feet 0 inches high, or 90,000 pounds gross weight"],"answer":0,"explanation":"When a load exceeds legal limits (over 8'6\" wide, over 13'6\" high, over legal length, or over 80,000 lb gross), an IDOT permit is required to move it on state highways. Source: 625 ILCS 5/15-301; IDOT.","handbook":"","hbref":""},{"q":"What is the maximum load Illinois allows per inch of tire width (for the tire in contact with the road)?","options":["800 pounds per inch of tire width","500 pounds per inch of tire width","1,000 pounds per inch of tire width","600 pounds per inch of tire width"],"answer":0,"explanation":"Illinois limits load to 800 pounds per inch of tire width to protect pavement, in addition to the axle weight limits. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"What online system does IDOT use for applying for Illinois oversize/overweight and harvest permits?","options":["ITAP (Illinois Transportation Automated Permits system)","IRP (International Registration Plan portal)","CDLIS (Commercial Driver License Information System)","SAFER (Safety and Fitness Electronic Records)"],"answer":0,"explanation":"Applicants apply through IDOT's ITAP system, which provides 24/7 online access to oversize/overweight and harvest permits. Source: IDOT Oversize/Overweight Permits (webapps.dot.illinois.gov/ITAP).","handbook":"","hbref":""},{"q":"By approximately what percentage over legal limits does the free Illinois Harvest Permit allow a vehicle to exceed gross, axle, and registered weights during harvest season?","options":["Up to 10 percent","Up to 5 percent","Up to 15 percent","Up to 25 percent"],"answer":0,"explanation":"The Illinois Harvest Permit allows up to 10 percent over legal gross, axle, and registered weights for hauling agricultural commodities during harvest. Source: IDOT Harvest Permit; Illinois Farm Bureau.","handbook":"","hbref":""},{"q":"On which roads does the Illinois Harvest Permit issued by IDOT allow overweight agricultural travel?","options":["State-maintained routes only (not interstates or local roads unless separately authorized)","All interstate highways within Illinois","Any public road in Illinois, including local township roads","Only county and township roads, never state routes"],"answer":0,"explanation":"The IDOT Harvest Permit covers state routes only; it does not authorize interstate travel, and local roads require separate local authorization. Source: IDOT Harvest Permit; Illinois Farm Bureau.","handbook":"","hbref":""},{"q":"How much does the standard Illinois Harvest Permit cost a qualifying farmer or agricultural hauler?","options":["It is free","$15 per vehicle","$100 per season","$50 per route authorization"],"answer":0,"explanation":"Illinois offers the Harvest Permit free of charge to qualifying agricultural haulers, obtained through IDOT's ITAP system. Source: IDOT Harvest Permit; Illinois Farm Bureau.","handbook":"","hbref":""},{"q":"What additional gross weight allowance does Illinois grant a vehicle powered primarily by natural gas (to offset the heavier fuel system), and where does it NOT apply?","options":["Up to 2,000 pounds extra, but not on the Interstate system","Up to 5,000 pounds extra on all highways including Interstates","Up to 1,000 pounds extra only on local roads","Up to 4,000 pounds extra only on Interstates"],"answer":0,"explanation":"Illinois allows up to 2,000 pounds of additional gross weight for natural-gas-powered vehicles, except on Interstate highways. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"Within a legal tandem axle group in Illinois, no single axle of the tandem may exceed what weight?","options":["20,000 pounds","17,000 pounds","18,000 pounds","22,000 pounds"],"answer":0,"explanation":"Even though a tandem may carry 34,000 pounds total, no single axle within that tandem may exceed 20,000 pounds. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"In the Federal Bridge Formula W = 500[(LN/(N-1)) + 12N + 36] used in Illinois, what does the variable 'L' represent?","options":["The distance in feet between the extreme (outermost) axles of the group being measured","The total length of the trailer in feet","The legal load limit per tire","The licensed gross weight of the vehicle"],"answer":0,"explanation":"In the bridge formula, L is the spacing in feet between the extreme axles of the group, N is the number of axles, and W is the maximum allowable weight. Source: 625 ILCS 5/15-111.","handbook":"","hbref":""},{"q":"A local authority in Illinois may legally post and allow gross weights higher than the statutory limit on a highway under its jurisdiction only if it does what?","options":["Erects appropriate regulatory signs giving notice, without exceeding the single- or tandem-axle maximums","Obtains written approval from the Federal Highway Administration","Increases the single-axle maximum to 24,000 pounds","Waives the Federal Bridge Formula entirely for that road"],"answer":0,"explanation":"Local authorities may permit increased loads on designated local highways only when proper regulatory signs are posted, and they still cannot exceed the single- or tandem-axle maximums. Source: 625 ILCS 5/15-111 and related local-authority provisions.","handbook":"","hbref":""},{"q":"A driver hauling a load 9 feet wide and 14 feet high across an Illinois state highway has no permit. What is the correct characterization of this movement?","options":["It is illegal; both the width (over 8'6\") and height (over 13'6\") exceed legal limits and require an IDOT oversize permit","It is legal because agricultural loads are exempt from all size limits","It is legal because only weight, not dimensions, requires a permit","It is legal because the load is under 80,000 pounds gross weight"],"answer":0,"explanation":"Exceeding 8'6\" width or 13'6\" height makes the movement illegal without an IDOT oversize permit; dimensional limits apply independently of gross weight. Source: 625 ILCS 5/15-102, 15-103, and 15-301.","handbook":"","hbref":""},{"q":"In Illinois, which CDL class is required to operate a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 lbs or more, where the vehicle being towed has a GVWR of more than 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Illinois defines a Class A CDL as a combination of vehicles with a GCWR of 26,001 lbs or more, provided the towed unit has a GVWR greater than 10,000 lbs. Source: Illinois SOS CDL Study Guide / ilsos.gov CDL classes page; 92 Ill. Admin. Code 1030.","handbook":"","hbref":""},{"q":"Under Illinois rules, a Class B CDL authorizes operation of which of the following?","options":["Any single vehicle with a GVWR of 26,001 lbs or more (towing a unit not over 10,000 lbs)","Any combination towing a unit over 10,000 lbs","Only vehicles under 16,000 lbs GVWR","Only vehicles designed to carry 16+ passengers"],"answer":0,"explanation":"Illinois defines a Class B CDL as any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing another not in excess of 10,000 lbs (e.g., straight trucks, large buses). Source: Illinois SOS CDL Study Guide / ilsos.gov.","handbook":"","hbref":""},{"q":"An Illinois driver wants to operate a small van designed to transport 16 or more passengers (including the driver) that weighs under 26,001 lbs. Which CDL class applies?","options":["Class C","Class A","Class B","No CDL is needed"],"answer":0,"explanation":"Illinois Class C covers any vehicle not meeting Class A or B that is designed to transport 16 or more passengers including the driver, or that carries placarded hazardous materials. Source: Illinois SOS CDL Study Guide / ilsos.gov.","handbook":"","hbref":""},{"q":"Which CDL endorsement is required in Illinois to drive a vehicle carrying hazardous materials in amounts that require placarding?","options":["H (HazMat)","N (Tanker)","T (Doubles/Triples)","P (Passenger)"],"answer":0,"explanation":"The H endorsement is required for any vehicle carrying hazardous materials that require placarding. Illinois additionally requires a TSA security threat assessment and ELDT before the H knowledge test. Source: ilsos.gov Hazardous Materials Endorsement page.","handbook":"","hbref":""},{"q":"In Illinois, which endorsement is required to operate a tank vehicle hauling liquids or gases in bulk?","options":["N (Tanker)","H (HazMat)","T (Doubles/Triples)","S (School Bus)"],"answer":0,"explanation":"The N endorsement authorizes operation of a tank vehicle that transports liquids or gases. It requires passing the tank vehicle knowledge test. Source: Illinois SOS CDL Study Guide / ilsos.gov endorsements.","handbook":"","hbref":""},{"q":"The Illinois T endorsement (Doubles/Triples) may be added only to which class of CDL?","options":["Class A","Class B","Class C","Any class"],"answer":0,"explanation":"In Illinois the T (Doubles/Triples) endorsement applies only to a Class A CDL, since pulling more than one trailer requires a combination license. Note: triple trailers are not legal on Illinois highways. Source: Illinois SOS CDL materials / ilsos.gov endorsements.","handbook":"","hbref":""},{"q":"Which statement about triple trailers in Illinois is correct?","options":["Triple trailers are not permitted on Illinois highways","Triple trailers are allowed only on interstates","Triple trailers are allowed with a P endorsement","Triple trailers require only a Class B CDL"],"answer":0,"explanation":"Although the endorsement is called Doubles/Triples (T), Illinois law does not permit triple-trailer combinations on its highways. Source: Illinois SOS CDL endorsement information / ilsos.gov.","handbook":"","hbref":""},{"q":"In Illinois, which endorsement is required to drive a vehicle designed to carry 16 or more passengers, including the driver?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"answer":0,"explanation":"The P (Passenger) endorsement is required to operate a vehicle designed to carry 16 or more people including the driver; it requires a knowledge test and a skills test in a representative vehicle. Source: Illinois SOS CDL Study Guide / ilsos.gov.","handbook":"","hbref":""},{"q":"To drive a yellow school bus transporting students (12th grade and under) in Illinois, the driver needs which endorsement in addition to a CDL?","options":["S (School Bus)","P only","N (Tanker)","H (HazMat)"],"answer":0,"explanation":"The S (School Bus) endorsement is required to transport students to/from school or school activities; Illinois requires knowledge, skills, and a drive test (a P endorsement is also a prerequisite). Source: ilsos.gov School Bus endorsement.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Illinois CDL or CLP to operate ONLY within Illinois (intrastate)?","options":["18","21","19","16"],"answer":0,"explanation":"Illinois requires an applicant to be at least 18 to obtain a CDL/CLP for intrastate operation. Source: ilsos.gov CDL/CLP page; 625 ILCS 5/6-507.","handbook":"","hbref":""},{"q":"What minimum age does Illinois require to operate a commercial motor vehicle in interstate commerce or to transport passengers?","options":["21","18","19","25"],"answer":0,"explanation":"Illinois requires a driver to be at least 21 to operate in interstate commerce or to transport passengers; 18-20 year-olds are limited to intrastate operation. Source: ilsos.gov CDL/CLP page; 49 CFR 391.11 as adopted by Illinois.","handbook":"","hbref":""},{"q":"Under federal rules adopted by Illinois, how long must a driver hold a Commercial Learner's Permit (CLP) before taking the CDL skills (road) test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Both federal and Illinois rules require the CLP be held for a minimum of 14 days before the skills test; you may schedule in advance, but the test date must fall after the 14-day hold. Source: ilsos.gov CDL/CLP page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is an Illinois Commercial Learner's Permit (CLP) valid?","options":["180 days","90 days","1 year","30 days"],"answer":0,"explanation":"An Illinois CLP is valid for 180 days, consistent with the federal CLP standard. Source: ilsos.gov CDL/CLP page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"For which of the following does Illinois require Entry-Level Driver Training (ELDT) before the knowledge or skills test?","options":["An initial H (HazMat), P (Passenger), or S (School Bus) endorsement","Only the N (Tanker) endorsement","Renewing any existing endorsement","Adding a motorcycle endorsement"],"answer":0,"explanation":"ELDT applies to obtaining a first Class A or B CDL, an upgrade, and an INITIAL H, P, or S endorsement. The HazMat (H) theory training must precede the H knowledge test. Source: ilsos.gov ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which set of documents must an Illinois CLP/CDL applicant present at a Secretary of State facility?","options":["Proof of identity, written proof of Social Security number, proof of legal/lawful presence, and two proofs of Illinois residency","Only a Social Security card","Only a U.S. passport","Only two utility bills"],"answer":0,"explanation":"Illinois requires proof of identity, written proof of SSN (e.g., the actual card or W-2; no photocopies), proof of lawful presence, and two proofs of Illinois residency. Source: ilsos.gov CDL/CLP and legal presence pages.","handbook":"","hbref":""},{"q":"How many proofs of Illinois residency does the Secretary of State require for a CDL/CLP application?","options":["Two","One","Three","None"],"answer":0,"explanation":"Illinois requires two acceptable proofs of Illinois residency, in addition to proof of identity, SSN, and lawful presence. Source: ilsos.gov Driver's License/CDL document requirements.","handbook":"","hbref":""},{"q":"When applying for an Illinois CDL, which self-certification category requires the driver to provide a valid federal DOT Medical Examiner's Certificate?","options":["Non-excepted interstate (NI)","Excepted intrastate (EA)","Excepted interstate (EI)","Non-excepted intrastate (NA)"],"answer":0,"explanation":"Illinois recognizes four self-certification categories (NI, EI, NA, EA). A non-excepted interstate (NI) driver must meet federal DOT medical standards and submit a Medical Examiner's Certificate (Form MCSA-5876). Source: ilsos.gov CDL page; 92 Ill. Admin. Code 1030.22.","handbook":"","hbref":""},{"q":"Which list correctly names the four medical self-certification categories Illinois CDL/CLP applicants must choose from?","options":["Non-excepted interstate, Excepted interstate, Non-excepted intrastate, Excepted intrastate","Interstate, Intrastate, Farm, Military","Class A, Class B, Class C, Class D","Local, Regional, National, International"],"answer":0,"explanation":"Illinois uses the four federal self-certification categories: Non-excepted interstate (NI), Excepted interstate (EI), Non-excepted intrastate (NA), and Excepted intrastate (EA). Source: ilsos.gov CDL page; 92 Ill. Admin. Code 1030.22.","handbook":"","hbref":""},{"q":"For an Illinois CDL holder with a HazMat (H) endorsement, how often must the TSA security threat assessment be renewed to keep the endorsement?","options":["Every 5 years","Every 2 years","Every 10 years","Only once, never renewed"],"answer":0,"explanation":"A TSA security threat assessment for the HazMat endorsement is valid for 5 years; Illinois requires the assessment and the HazMat knowledge test at each renewal, and drivers should begin renewal about 60 days before expiration. Source: ilsos.gov Hazardous Materials Endorsement; 49 CFR 1572.","handbook":"","hbref":""},{"q":"Under Illinois law, what is the maximum blood-alcohol concentration (BAC) a CDL holder may have while operating a commercial motor vehicle (CMV)?","options":["0.04 percent","0.08 percent","0.02 percent","0.00 percent"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1) states a CDL holder may not operate a CMV with a BAC of .04 percent or more, which is half the .08 limit for other vehicles. Source: Illinois CDL Study Guide; 625 ILCS 5/11-501.","handbook":"","hbref":""},{"q":"When a driver operates a vehicle on Illinois highways, the state's implied-consent law means the driver has agreed in advance to do what?","options":["Submit to chemical tests to determine blood-alcohol concentration","Allow a search of the vehicle's cargo at any time","Pay a fine before contesting any traffic citation","Surrender the CDL upon any moving violation"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1) states drivers operating a CMV or non-CMV on highways have impliedly consented to submit to chemical tests to determine BAC. Source: Illinois CDL Study Guide; 625 ILCS 5/11-501.1.","handbook":"","hbref":""},{"q":"In Illinois, a driver who refuses to submit to chemical testing or tests over the legal limit faces a disqualification of at least how long for a first offense (non-HazMat)?","options":["12 months","60 days","6 months","3 years"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): any driver who refuses chemical testing or tests in excess of the legal limit is disqualified for a minimum of 12 months. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"If a driver commits a first major alcohol offense WHILE transporting placarded hazardous materials, what is the minimum Illinois disqualification period?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): if the violation takes place while transporting placarded hazardous materials, the driver is disqualified for a minimum of three years. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"A driver commits two separate major offenses (such as two DUIs) arising from two or more incidents. What Illinois disqualification results?","options":["Lifetime disqualification","Three-year disqualification","Five-year disqualification","120-day disqualification"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): any driver who commits two of the listed major violations, arising from two or more incidents, is disqualified for life. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"In Illinois, any CDL holder operating a CMV who is found to have ANY alcohol in their system (below 0.04) is placed out of service for a minimum of how long?","options":["24 hours","1 hour","12 hours","72 hours"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): any CDL holder operating a CMV found to have any alcohol in his/her system is placed out of service for a minimum of 24 hours. Source: Illinois CDL Study Guide; 49 CFR 392.5.","handbook":"","hbref":""},{"q":"What is the maximum allowable BAC for a school bus driver operating a school bus in Illinois?","options":["0.00 percent","0.04 percent","0.02 percent","0.08 percent"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): a school bus driver may not operate a school bus with a BAC of more than .00 percent. Source: Illinois CDL Study Guide.","handbook":"","hbref":""},{"q":"Knowingly and willfully leaving the scene of an accident while operating a CMV results in an Illinois disqualification of at least how long?","options":["12 months","60 days","120 days","3 years"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): knowingly and willfully leaving the scene of an accident while operating a CMV or non-CMV results in disqualification for a minimum of 12 months. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"Using a commercial or non-commercial motor vehicle to commit a felony involving manufacturing or distributing a controlled substance results in what Illinois penalty?","options":["Lifetime disqualification","One-year disqualification","Three-year disqualification","120-day disqualification"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): use of a CMV or non-CMV in a felony involving manufacturing, distributing or dispensing a controlled substance results in a lifetime disqualification. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"For a FIRST conviction of violating railroad-highway grade crossing regulations in a CMV, what is the Illinois disqualification period?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): railroad-highway grade crossing violation first conviction is a 60-day disqualification. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"A SECOND railroad-highway grade crossing violation within a three-year period results in what Illinois disqualification?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): second railroad-highway grade crossing conviction within three years is a 120-day disqualification. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"A THIRD or subsequent railroad-highway grade crossing violation within a three-year period results in what Illinois disqualification?","options":["1 year","120 days","60 days","Lifetime"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): third and subsequent railroad-highway grade crossing conviction within three years is a one-year disqualification. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a three-year period trigger a 60-day disqualification in Illinois?","options":["Two","Three","One","Four"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): two serious traffic violations within a three-year period result in a 60-day disqualification. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"Three serious traffic violations within a three-year period result in what Illinois disqualification period?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): three serious traffic violations in a three-year period result in a 120-day disqualification. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"At what speed over the posted limit does a single speeding offense count as a 'serious traffic violation' for an Illinois CDL holder?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","25 mph or more over the limit"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): excessive speeding is any single offense of 15 mph or more above the posted speed limit. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for an Illinois CDL holder?","options":["Improper or erratic traffic lane changes","An expired vehicle registration sticker","A parking violation downtown","An overweight axle on a permit load"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3) lists improper/erratic lane changes, following too closely, reckless driving, excessive speeding and CMV texting as serious traffic violations. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"Per the Illinois CDL Study Guide, what is the disqualification for a FIRST violation of an out-of-service order?","options":["At least 90 days","At least 30 days","At least 60 days","At least 1 year"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): you lose your CDL for at least 90 days for a first violation of an out-of-service order. Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"A driver commits THREE or more out-of-service order violations within a 10-year period. What is the minimum Illinois disqualification?","options":["3 years","1 year","90 days","Lifetime"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): at least three years for three or more out-of-service order violations within a 10-year period (second violation in 10 years is at least one year). Source: Illinois CDL Study Guide; 625 ILCS 5/6-514.","handbook":"","hbref":""},{"q":"How does Illinois classify a CMV driver texting or using a hand-held cellphone while driving a CMV?","options":["As a serious traffic violation","As a major offense causing lifetime disqualification","As a parking-type violation with no CDL effect","As an out-of-service order violation"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): texting or using a hand-held cellphone while driving a CMV is a serious traffic violation; the FMCSA driver fine can reach $2,750. Source: Illinois CDL Study Guide; 625 ILCS 5/12-610.2; 49 CFR 392.80/392.82.","handbook":"","hbref":""},{"q":"A court in Illinois may impose what maximum fine for driving a commercial motor vehicle without a valid CDL, or for holding more than one license?","options":["Up to $5,000 or jail time","Up to $1,000 only","Up to $500 only","Up to $10,000 or jail time"],"answer":0,"explanation":"Illinois SOS CDL Study Guide (Sec. 1.6): a court may impose a fine of up to $5,000 or jail time for driving a CMV without a CDL or for having more than one license. Source: Illinois CDL Study Guide; 625 ILCS 5/6-507.","handbook":"","hbref":""},{"q":"Illinois's 'Move Over' law (Scott's Law) requires a driver approaching a stopped emergency or maintenance vehicle that is displaying flashing warning lights to do what?","options":["Change into a non-adjacent lane if possible, or otherwise slow down and proceed with caution","Come to a complete stop and wait until the emergency vehicle leaves","Maintain speed but sound the horn while passing","Pull onto the shoulder behind the emergency vehicle and stop"],"answer":0,"explanation":"Under Scott's Law, 625 ILCS 5/11-907(c), a driver approaching a stationary emergency, maintenance, or tow vehicle with flashing lights must change to a lane not adjacent to it when safe, and if changing lanes is not possible, must reduce speed and proceed with caution. Source: 625 ILCS 5/11-907; Illinois State Police Move Over Law page.","handbook":"","hbref":""},{"q":"The law named after Lt. Scott Gillen, requiring Illinois drivers to yield to stationary emergency vehicles, is commonly known as what?","options":["The Steve's Law","Scott's Law","The Dan Ryan Act","The Yellow Light Law"],"answer":1,"explanation":"Illinois's Move Over law is officially nicknamed 'Scott's Law,' after Chicago Fire Department Lt. Scott Gillen, who was struck and killed on the Dan Ryan Expressway in 2000. Source: 625 ILCS 5/11-907; Illinois State Police.","handbook":"","hbref":""},{"q":"A school bus and a placarded hazardous-materials vehicle that must stop at an Illinois railroad crossing are required to stop within what distance of the nearest rail?","options":["Between 5 and 25 feet","Between 10 and 35 feet","Between 15 and 50 feet","Between 25 and 75 feet"],"answer":2,"explanation":"The Illinois CDL handbook directs that a bus driver 'Stop your bus between 15 and 50 feet before railroad crossings,' and that a placarded vehicle 'must stop 15 to 50 feet before the nearest rail.' Source: Illinois SOS CDL Study Guide, Sections 4.3.5 and 9.6.12.","handbook":"","hbref":""},{"q":"Under Illinois law, what is the maximum legal height of a vehicle, including its load, on any highway in the state without a permit?","options":["12 feet 6 inches","13 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"answer":1,"explanation":"Illinois limits vehicle height, measured from the underside of the tire to the top of the vehicle including load, to 13 feet 6 inches on any highway. Source: 625 ILCS 5/15-103.","handbook":"","hbref":""},{"q":"When a commercial vehicle must stop on or alongside a one-way or divided highway in Illinois, the driver must place the three warning devices at approximately what distances toward approaching traffic?","options":["10, 100, and 200 feet","10, 50, and 100 feet","25, 100, and 250 feet","5, 75, and 150 feet"],"answer":0,"explanation":"On a one-way or divided highway, the Illinois CDL handbook requires warning devices placed 10 feet, 100 feet, and 200 feet toward the approaching traffic. Source: Illinois SOS CDL Study Guide, Subsection 2.5 (Warning Devices).","handbook":"","hbref":""},{"q":"In Cook, DuPage, Kane, Lake, McHenry, and Will counties, a second-division truck registered for more than 8,000 pounds is limited to what speed on roads, highways, and streets that are NOT tollway interstates?","options":["65 mph","60 mph","55 mph","45 mph"],"answer":2,"explanation":"In those six counties, trucks over 8,000 pounds are capped at 60 mph on Illinois Tollway interstate highways and 55 mph on all other roads, highways, or streets. Source: 625 ILCS 5/11-601(e).","handbook":"","hbref":""},{"q":"Outside an urban district on a rural Illinois interstate posted at 70 mph (and outside the six Chicago-area collar counties), a large truck under current Illinois law may travel at what maximum speed?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":3,"explanation":"Since the 2014 change to 625 ILCS 5/11-601, trucks on rural interstates outside the six collar counties may travel at the same posted limit as cars, up to 70 mph; only in Cook, DuPage, Kane, Lake, McHenry, and Will counties are they held to lower truck-specific limits. Source: 625 ILCS 5/11-601(d-1), (e).","handbook":"","hbref":""},{"q":"While crossing railroad tracks in Illinois, a CDL driver should do which of the following?","options":["Shift to a lower gear halfway across for extra power","Not shift gears while crossing the tracks","Shift to neutral and coast across","Shift up to clear the tracks as quickly as possible"],"answer":1,"explanation":"The Illinois CDL handbook states plainly: 'Do not shift gears while crossing railroad tracks,' because a missed or grinding shift could stall the vehicle on the tracks. Source: Illinois SOS CDL Study Guide, Subsection 2.15 and 9.6.12.","handbook":"","hbref":""},{"q":"On an Illinois highway with four or more lanes that permits at least two lanes of traffic to travel in opposite directions, a driver meeting a school bus stopped in the OPPOSING roadway must do what?","options":["Stop and remain stopped until the bus's red lights stop flashing","Stop only if children are visible","Need not stop, but should remain alert","Slow to 20 mph and continue past the bus"],"answer":2,"explanation":"Illinois law provides that a driver on a highway with 4 or more lanes permitting at least 2 lanes of traffic in opposite directions need not stop upon MEETING a school bus stopped in the opposing roadway. Source: 625 ILCS 5/11-1414(e).","handbook":"","hbref":""},{"q":"Except for the divided-highway exception, when a school bus is stopped on an Illinois roadway with its visual signal lights flashing to load or unload pupils, what must approaching drivers do?","options":["Stop before meeting or overtaking the bus from either direction","Stop only if approaching from behind the bus","Pass slowly on the left at no more than 10 mph","Stop only when a crossing guard signals them to"],"answer":0,"explanation":"Illinois requires drivers to stop the vehicle before meeting or overtaking, from either direction, any school bus that has stopped and is displaying its visual signal lights to receive or discharge pupils. Source: 625 ILCS 5/11-1414(a).","handbook":"","hbref":""},{"q":"In addition to placarded vehicles, which of the following must always make a stop before crossing railroad tracks in Illinois?","options":["Any straight truck weighing over 10,000 pounds","Any vehicle carrying any amount of chlorine","Any vehicle pulling a flatbed trailer","Any vehicle registered out of state"],"answer":1,"explanation":"The Illinois CDL handbook lists three categories that must stop before a railroad crossing: vehicles that are placarded, vehicles carrying any amount of chlorine, and cargo tanks (loaded or empty) used for hazardous materials. Source: Illinois SOS CDL Study Guide, Subsection 9.6.12.","handbook":"","hbref":""},{"q":"What is the maximum legal width (excluding mirrors and certain safety devices) for a vehicle or its load on Illinois highways without a permit?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Illinois limits the total outside width of a vehicle or load to 8 feet 6 inches; anything wider requires an oversize permit from IDOT. Source: 625 ILCS 5/15-102.","handbook":"","hbref":""},{"q":"When a CDL driver must stop on the shoulder or roadway of any Illinois highway, within how many minutes must the emergency warning devices be placed?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"answer":1,"explanation":"The Illinois CDL handbook requires that warning devices be put out within 10 minutes of stopping on a road or shoulder. Source: Illinois SOS CDL Study Guide, Subsection 2.5.","handbook":"","hbref":""},{"q":"How many red reflective warning triangles must a commercial vehicle carry to satisfy the warning-device requirement in Illinois?","options":["Two","Three","Four","Six"],"answer":1,"explanation":"The Illinois CDL handbook requires three reflective warning triangles (or, alternatively, six fuses or three liquid-burning flares) as part of required emergency equipment. Source: Illinois SOS CDL Study Guide, Subsection 2.1.","handbook":"","hbref":""},{"q":"A driver carrying placarded hazardous materials who is convicted of a railroad-highway grade crossing violation in Illinois faces what consequence?","options":["A written warning only","A 24-hour out-of-service order","CDL disqualification","Points but no disqualification"],"answer":2,"explanation":"Railroad-highway grade crossing violations are disqualifying offenses for CDL holders in Illinois, with escalating disqualification periods (60 days, 120 days, then one year) for repeat violations within three years. Source: Illinois SOS CDL Study Guide, Subsection 1.2 (Disqualifications); 49 CFR 383.51 as adopted by Illinois.","handbook":"","hbref":""},{"q":"A first-offense violation of Scott's Law (Illinois's Move Over law) carries a fine of at least how much?","options":["$100","$250","$500","$1,000"],"answer":1,"explanation":"After Public Act 101-0173, a Scott's Law violation is a business offense with a fine of not less than $250 and up to $10,000 for a first offense. Source: 625 ILCS 5/11-907(c).","handbook":"","hbref":""},{"q":"On Chicago's Lake Shore Drive, which is legally classified as a boulevard/parkway, what is generally prohibited?","options":["Vehicles with truck (commercial) license plates designed to carry freight","All vehicles during weekday rush hours","Passenger cars towing trailers only","Vehicles without an Illinois I-PASS transponder"],"answer":0,"explanation":"Lake Shore Drive is designated a boulevard, and vehicles bearing truck plates designed to carry freight or commercial goods are barred from it, a distinctive Chicago routing restriction rooted in its 'pleasure drive' origins. Source: Chicago Municipal Code boulevard restrictions; CDOT Lake Shore Drive truck travel permit guidance.","handbook":"","hbref":""},{"q":"At a railroad crossing where a stop is otherwise required, an Illinois bus driver does NOT have to come to a full stop, but must slow down and check carefully, in which situation?","options":["When the crossing is on a gravel road","When a police officer or flagman is directing traffic","When the bus is empty of passengers","When the bus is more than 40 feet long"],"answer":1,"explanation":"The Illinois CDL handbook states a bus need not stop, but must slow down and carefully check, at streetcar crossings, where a policeman or flagman is directing traffic, or when a traffic signal shows green. Source: Illinois SOS CDL Study Guide, Subsection 4.3.5.","handbook":"","hbref":""},{"q":"Because Illinois terrain is largely flat, traditional gravity-style runaway truck escape ramps are uncommon. What does this mean for a CDL driver descending a long grade or bridge approach in Illinois?","options":["They can rely on finding an escape ramp at the bottom of any grade","They should not depend on an escape ramp and must control speed with proper braking and gearing","Illinois law forbids using engine brakes on all grades","Escape ramps are mandatory on every Illinois interstate downgrade"],"answer":1,"explanation":"Unlike mountainous states, Illinois's flat terrain means escape ramps are rare, so drivers must manage downgrades with proper low gears and braking technique rather than expecting a runaway ramp. Source: Illinois SOS CDL Study Guide, Subsection 2.16 (Mountain Driving / controlling speed on downgrades).","handbook":"","hbref":""},{"q":"An Illinois driver approaching a stopped school bus on a TWO-LANE undivided highway, traveling in either direction, must do what?","options":["Continue at reduced speed past the bus","Stop before reaching the bus and remain stopped until the signals are turned off","Stop only if approaching from the same direction as the bus","Pass on the left after sounding the horn"],"answer":1,"explanation":"On a two-lane undivided highway the divided-highway exception does not apply, so drivers approaching from either direction must stop before meeting or overtaking a school bus displaying its red signals and stay stopped until the signals stop and the bus resumes motion. Source: 625 ILCS 5/11-1414(a) and (b).","handbook":"","hbref":""},{"q":"In Illinois, which state agency issues Commercial Driver's Licenses and administers the CDL knowledge and skills tests?","options":["The Illinois Secretary of State","The Illinois Department of Transportation (IDOT)","The Illinois State Police","The Illinois Department of Motor Vehicles"],"answer":0,"explanation":"Illinois does not have a 'DMV'; the Office of the Illinois Secretary of State (SOS) is the state driver-licensing authority that issues CDLs and administers testing at its Driver Services CDL facilities. Source: Illinois SOS CDL Study Guide (DSD CDL) and ilsos.gov CDL pages.","handbook":"","hbref":""},{"q":"Where does an Illinois applicant take the CDL knowledge tests and the skills (drive) test?","options":["At a Secretary of State Driver Services CDL facility","At any local Illinois State Police post","Only at an FMCSA federal testing center","At an Illinois Department of Transportation weigh station"],"answer":0,"explanation":"CDL written and skills testing is conducted by the Secretary of State at designated Driver Services CDL facilities. Source: Illinois SOS CDL Study Guide and ilsos.gov CDL testing/scheduling pages.","handbook":"","hbref":""},{"q":"How many self-certification categories must an Illinois CDL/CLP applicant choose from when declaring the type of commerce they operate in?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Illinois follows the federal CDL rule requiring drivers to self-certify into one of four categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. Source: Illinois SOS CDL Study Guide; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"An Illinois driver who operates across state lines and is NOT exempt from the federal physical-qualification rules must self-certify as which category?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"A driver in interstate commerce who must meet the federal DOT medical standards self-certifies as Non-Excepted Interstate (NI) and must maintain a valid medical examiner's certificate. Source: Illinois SOS CDL Study Guide; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which self-certification category applies to an Illinois driver who operates ONLY within Illinois and is not required to meet the medical certification requirements?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"answer":0,"explanation":"A driver operating solely in intrastate (in-Illinois) commerce who does not have to meet medical certification requirements self-certifies as Excepted Intrastate (EA). Source: Illinois SOS CDL Study Guide; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which federal form is the Medical Examiner's Certificate that an Illinois Non-Excepted Interstate CDL holder must keep current?","options":["Form MCSA-5876","Form MCSA-5875","Form SS-CDL-2","Form DL-180"],"answer":0,"explanation":"The official Medical Examiner's Certificate is FMCSA Form MCSA-5876, issued by a certified medical examiner. Non-excepted drivers must keep a valid certificate on file with the state. Source: FMCSA; Illinois SOS CDL pages.","handbook":"","hbref":""},{"q":"As of the 2025 change in Illinois, how does a CDL holder's Medical Examiner's Certificate normally reach the Secretary of State?","options":["The certified medical examiner submits it electronically through the FMCSA National Registry","The driver mails a paper copy to the Secretary of State","The driver faxes it to a CDL facility within 15 days","The driver hand-delivers the paper card at any CDL facility"],"answer":0,"explanation":"Effective with Illinois joining the FMCSA National Registry integration (mid-2025), certified medical examiners electronically transmit exam results to FMCSA, which provides them to the SOS; the state no longer accepts paper medical cards at CDL facilities. Source: Illinois SOS CDL pages; FMCSA National Registry.","handbook":"","hbref":""},{"q":"How often must an Illinois Non-Excepted Interstate CDL holder generally update self-certification and provide a current medical certificate?","options":["At least every 2 years (or sooner if the certificate's expiration is shorter)","Every 5 years with license renewal","Every 4 years with license renewal","Only once, at initial licensing"],"answer":0,"explanation":"A Medical Examiner's Certificate is valid for a maximum of 2 years (less if the examiner specifies), so non-excepted interstate drivers must keep current medical certification on at least a 2-year cycle, independent of the 4-year license cycle. Source: Illinois SOS CDL pages; 49 CFR 391.45.","handbook":"","hbref":""},{"q":"Before being scheduled for the CDL skills test in Illinois, an applicant for an initial Class A or Class B must complete which training requirement?","options":["Entry-Level Driver Training (ELDT) from an FMCSA-registered provider","A 30-hour Illinois defensive-driving course","An Illinois Secretary of State classroom safety seminar","A state-administered apprenticeship of 6 months"],"answer":0,"explanation":"Federal ELDT rules, adopted in Illinois, require initial Class A/Class B applicants (and certain upgrades/endorsements) to complete Entry-Level Driver Training from a provider listed on the FMCSA Training Provider Registry before testing. Source: Illinois SOS ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Under the Illinois ELDT requirement, the theory portion of training must be completed before which step?","options":["Taking the CDL knowledge (written) test for the new class or endorsement","Applying for a base Illinois driver's license","Renewing an existing non-CDL license","Scheduling a vision screening"],"answer":0,"explanation":"Illinois requires applicants seeking an initial Class A or B CDL, an upgrade, or an initial S, P, or H endorsement to complete ELDT theory training from a registered provider before taking the related knowledge test. Source: Illinois SOS ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which of these endorsements requires completing ELDT before an Illinois applicant can be tested for it?","options":["Passenger (P), School bus (S), and Hazardous materials (H)","Double/triple trailers (T) only","Tank vehicle (N) only","No endorsements require ELDT in Illinois"],"answer":0,"explanation":"ELDT applies to initial issuance of the School bus (S), Passenger (P), and Hazardous materials (H) endorsements, in addition to initial Class A/B licenses and upgrades. Source: Illinois SOS ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"What must an Illinois driver obtain first as the step that allows behind-the-wheel practice before taking the CDL skills test?","options":["A Commercial Learner's Permit (CLP)","A temporary interstate waiver","A provisional commercial endorsement card","An FMCSA road-test exemption"],"answer":0,"explanation":"After passing the required knowledge test(s), the applicant is issued a Commercial Learner's Permit (CLP), which authorizes supervised practice in a representative vehicle prior to the skills test. Source: Illinois SOS CDL Study Guide; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"After an Illinois CLP is issued, how long must the holder wait before being allowed to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","There is no waiting period"],"answer":0,"explanation":"Federal law adopted by Illinois requires a minimum 14-day hold from the CLP issue date before the skills test may be administered; an applicant may schedule in advance but cannot pick a date inside the 14 days. Source: Illinois SOS CDL pages; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Illinois CDL skills test is given in three parts. What is the correct order in which they are administered?","options":["Pre-trip (vehicle) inspection, then basic control skills, then on-road drive test","On-road drive test, then basic control skills, then pre-trip inspection","Basic control skills, then on-road drive test, then pre-trip inspection","Pre-trip inspection, then on-road drive test, then basic control skills"],"answer":0,"explanation":"The skills test is conducted in the order: (1) Pre-Trip (Vehicle) Inspection, (2) Basic Control Skills, and (3) On-Road Drive Test. Source: Illinois SOS CDL Study Guide and ilsos.gov CDL pages.","handbook":"","hbref":""},{"q":"During the pre-trip inspection portion of the Illinois skills test, the applicant must primarily demonstrate the ability to:","options":["Identify components that should be checked and explain why each is important to safe operation","Disassemble and reassemble the brake system","Recite the entire Illinois Vehicle Code from memory","Replace a tire within a fixed time limit"],"answer":0,"explanation":"The vehicle inspection test requires the applicant to locate items, state what is being checked, and explain why the check matters to safe operation. Source: Illinois SOS CDL Study Guide (Section 11, Vehicle Inspection Test).","handbook":"","hbref":""},{"q":"Which of the following is part of the Basic Control Skills portion of the Illinois CDL skills test?","options":["Controlled backing maneuvers such as straight-line and offset backing","Merging onto an interstate highway at full speed","Answering 50 written multiple-choice questions","Coupling a hazardous materials placard to the trailer"],"answer":0,"explanation":"Basic Control Skills evaluates precise low-speed vehicle control through maneuvers like straight-line backing, offset backing, and parking, typically on a range. Source: Illinois SOS CDL Study Guide (Basic Vehicle Control Skills Test).","handbook":"","hbref":""},{"q":"What minimum score must an applicant achieve to pass each Illinois CDL knowledge (written) test?","options":["80% correct","70% correct","75% correct","90% correct"],"answer":0,"explanation":"Illinois CDL knowledge tests require a minimum of 80% correct to pass, consistent with the federal standard. Source: Illinois SOS CDL Study Guide; 49 CFR 383.135.","handbook":"","hbref":""},{"q":"What is the standard renewal cycle for an Illinois Commercial Driver's License for a driver in the normal age range?","options":["Every 4 years","Every 2 years","Every 5 years","Every 8 years"],"answer":0,"explanation":"A standard Illinois CDL is issued on a 4-year cycle, generally expiring on the holder's birthday; renewal also requires current self-certification and, for non-excepted drivers, valid medical certification. Source: Illinois SOS CDL pages and Driver Services renewal information.","handbook":"","hbref":""},{"q":"What is the minimum age to apply for an Illinois CDL to drive in INTERSTATE commerce or to carry passengers, versus driving only intrastate?","options":["21 for interstate or passengers; 18 for intrastate only","18 for interstate or passengers; 16 for intrastate only","25 for interstate or passengers; 21 for intrastate only","21 for both interstate and intrastate"],"answer":0,"explanation":"An applicant must be at least 21 to operate in interstate commerce or transport passengers, and at least 18 to obtain a CDL/CLP for intrastate-only operation. Source: Illinois SOS CDL Study Guide and ilsos.gov CDL pages.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная ширина коммерческого транспортного средства на автомагистралях штата Иллинойс, без учёта одобренных устройств безопасности и зеркал?","options":["8 футов 6 дюймов (102 inches)","8 футов 0 дюймов (96 inches)","9 футов 0 дюймов (108 inches)","10 футов 0 дюймов (120 inches)"],"explanation":"Иллинойс ограничивает ширину транспортного средства величиной 8 футов 6 дюймов (102 inches), не считая зеркал и других одобренных устройств безопасности. Источник: 625 ILCS 5/15-102; Illinois CDL/Rules of the Road."},"1":{"q":"Какова максимальная высота транспортного средства, включая груз, разрешённая на автомагистралях штата Иллинойс?","options":["13 футов 6 дюймов","13 футов 0 дюймов","14 футов 0 дюймов","12 футов 6 дюймов"],"explanation":"Иллинойс ограничивает общую высоту, измеряемую от поверхности дороги до верха груза, величиной 13 футов 6 дюймов. Источник: 625 ILCS 5/15-103."},"2":{"q":"Какова максимальная полная масса автопоезда из пяти или более осей, эксплуатируемого на автомагистралях штата Иллинойс без специального разрешения?","options":["80,000 pounds","73,280 pounds","84,000 pounds","88,000 pounds"],"explanation":"Иллинойс принимает федеральный максимум полной массы в 80,000 pounds для составов из пяти или более осей. Источник: 625 ILCS 5/15-111."},"3":{"q":"Какая максимальная нагрузка разрешена на одиночную ось на автомагистралях штата Иллинойс?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Иллинойс ограничивает одиночную ось величиной 20,000 pounds, что соответствует федеральному стандарту. Источник: 625 ILCS 5/15-111."},"4":{"q":"Какая максимальная нагрузка разрешена на группу спаренных осей (тандем) на автомагистралях штата Иллинойс?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Иллинойс ограничивает тандемную ось величиной 34,000 pounds, при этом ни одна одиночная ось в тандеме не должна превышать 20,000 pounds. Источник: 625 ILCS 5/15-111."},"5":{"q":"Какова максимальная длина одиночного прямого (жёсткого) грузовика на автомагистралях штата Иллинойс?","options":["42 feet","40 feet","45 feet","53 feet"],"explanation":"Одиночное транспортное средство, такое как прямой грузовик, не может превышать 42 feet общей длины в Иллинойсе. Источник: 625 ILCS 5/15-107."},"6":{"q":"На системе обозначенных автомагистралей (National Network) в Иллинойсе какова максимальная длина одиночного полуприцепа, эксплуатируемого в составе тягач-полуприцеп?","options":["53 feet","48 feet","57 feet","60 feet"],"explanation":"Иллинойс разрешает полуприцепы длиной до 53 feet в составе тягач-полуприцеп, что соответствует федеральному стандарту National Network. Источник: 625 ILCS 5/15-107."},"7":{"q":"Какую формулу использует Иллинойс для определения максимально допустимой полной массы на основе расстояния между осями и числа осей?","options":["Федеральную мостовую формулу (формулу вес-расстояние)","Формулу полной массы автопоезда (Gross Combination Rating)","Формулу индекса нагрузки на шину (Tire-Load Index)","Формулу класса зарегистрированной массы (Registered Weight Class)"],"explanation":"Иллинойс использует Федеральную мостовую формулу W = 500[(LN/(N-1)) + 12N + 36] для установления максимальной полной массы по расстоянию между осями (L) и числу осей (N). Источник: 625 ILCS 5/15-111."},"8":{"q":"В Иллинойсе кто выдаёт государственное разрешение на негабаритный/перегруженный груз, превышающий допустимые размеры или весовые ограничения, на автомагистрали, обслуживаемой штатом?","options":["Департамент транспорта Иллинойса (IDOT)","Illinois SOS","Полиция штата Иллинойс","Federal Motor Carrier Safety Administration"],"explanation":"IDOT выдаёт разрешения на негабаритные/перегруженные грузы для перевозок по автомагистралям, обслуживаемым штатом, в рамках своих установленных законом полномочий. Источник: 625 ILCS 5/15-301; IDOT Oversize/Overweight Permits."},"9":{"q":"Разрешение Иллинойса на негабаритный/перегруженный груз обычно требуется, когда транспортное средство или груз превышает один из следующих параметров?","options":["8 футов 6 дюймов в ширину, 13 футов 6 дюймов в высоту или 80,000 pounds полной массы","8 футов 0 дюймов в ширину, 13 футов 0 дюймов в высоту или 73,280 pounds полной массы","9 футов 0 дюймов в ширину, 14 футов 0 дюймов в высоту или 84,000 pounds полной массы","10 футов 0 дюймов в ширину, 15 футов 0 дюймов в высоту или 90,000 pounds полной массы"],"explanation":"Когда груз превышает допустимые ограничения (более 8'6\" в ширину, более 13'6\" в высоту, более допустимой длины или более 80,000 lb полной массы), для его перевозки по автомагистралям штата требуется разрешение IDOT. Источник: 625 ILCS 5/15-301; IDOT."},"10":{"q":"Какую максимальную нагрузку Иллинойс допускает на дюйм ширины шины (для шины, контактирующей с дорогой)?","options":["800 pounds на дюйм ширины шины","500 pounds на дюйм ширины шины","1,000 pounds на дюйм ширины шины","600 pounds на дюйм ширины шины"],"explanation":"Иллинойс ограничивает нагрузку величиной 800 pounds на дюйм ширины шины для защиты дорожного покрытия, в дополнение к ограничениям нагрузки на ось. Источник: 625 ILCS 5/15-111."},"11":{"q":"Какую онлайн-систему использует IDOT для подачи заявок на разрешения Иллинойса на негабаритные/перегруженные грузы и на уборочные работы?","options":["ITAP (Illinois Transportation Automated Permits system)","IRP (International Registration Plan portal)","CDLIS (Commercial Driver License Information System)","SAFER (Safety and Fitness Electronic Records)"],"explanation":"Заявители подают заявки через систему IDOT ITAP, которая обеспечивает круглосуточный онлайн-доступ к разрешениям на негабаритные/перегруженные грузы и на уборочные работы. Источник: IDOT Oversize/Overweight Permits (webapps.dot.illinois.gov/ITAP)."},"12":{"q":"Примерно на сколько процентов сверх допустимых ограничений бесплатное уборочное разрешение Иллинойса (Harvest Permit) позволяет транспортному средству превышать полную, осевую и зарегистрированную массу в период уборки урожая?","options":["До 10 процентов","До 5 процентов","До 15 процентов","До 25 процентов"],"explanation":"Уборочное разрешение Иллинойса (Harvest Permit) допускает превышение до 10 процентов над допустимой полной, осевой и зарегистрированной массой при перевозке сельскохозяйственной продукции во время уборки урожая. Источник: IDOT Harvest Permit; Illinois Farm Bureau."},"13":{"q":"По каким дорогам уборочное разрешение Иллинойса (Harvest Permit), выдаваемое IDOT, допускает перегруженные сельскохозяйственные перевозки?","options":["Только по маршрутам, обслуживаемым штатом (не по межштатным или местным дорогам, если это не разрешено отдельно)","По всем межштатным автомагистралям в пределах Иллинойса","По любой дороге общего пользования в Иллинойсе, включая местные тауншиповые дороги","Только по окружным и тауншиповым дорогам, никогда по маршрутам штата"],"explanation":"Уборочное разрешение IDOT (Harvest Permit) распространяется только на маршруты штата; оно не разрешает движение по межштатным автомагистралям, а для местных дорог требуется отдельное местное разрешение. Источник: IDOT Harvest Permit; Illinois Farm Bureau."},"14":{"q":"Сколько стоит стандартное уборочное разрешение Иллинойса (Harvest Permit) для соответствующего требованиям фермера или сельскохозяйственного перевозчика?","options":["Оно бесплатное","$15 за транспортное средство","$100 за сезон","$50 за разрешение на маршрут"],"explanation":"Иллинойс предоставляет уборочное разрешение (Harvest Permit) бесплатно соответствующим требованиям сельскохозяйственным перевозчикам; оно оформляется через систему IDOT ITAP. Источник: IDOT Harvest Permit; Illinois Farm Bureau."},"15":{"q":"Какую дополнительную надбавку к полной массе Иллинойс предоставляет транспортному средству, работающему преимущественно на природном газе (чтобы компенсировать более тяжёлую топливную систему), и где она НЕ применяется?","options":["До 2,000 pounds дополнительно, но не на системе межштатных автомагистралей","До 5,000 pounds дополнительно на всех автомагистралях, включая межштатные","До 1,000 pounds дополнительно только на местных дорогах","До 4,000 pounds дополнительно только на межштатных автомагистралях"],"explanation":"Иллинойс допускает до 2,000 pounds дополнительной полной массы для транспортных средств, работающих на природном газе, за исключением межштатных автомагистралей. Источник: 625 ILCS 5/15-111."},"16":{"q":"В пределах допустимой группы спаренных осей (тандема) в Иллинойсе ни одна одиночная ось тандема не может превышать какую массу?","options":["20,000 pounds","17,000 pounds","18,000 pounds","22,000 pounds"],"explanation":"Хотя тандем может нести в общей сложности 34,000 pounds, ни одна одиночная ось в этом тандеме не может превышать 20,000 pounds. Источник: 625 ILCS 5/15-111."},"17":{"q":"В Федеральной мостовой формуле W = 500[(LN/(N-1)) + 12N + 36], используемой в Иллинойсе, что обозначает переменная 'L'?","options":["Расстояние в футах между крайними (наиболее удалёнными) осями измеряемой группы","Общую длину прицепа в футах","Допустимое ограничение нагрузки на шину","Лицензированную полную массу транспортного средства"],"explanation":"В мостовой формуле L — это расстояние в футах между крайними осями группы, N — число осей, а W — максимально допустимая масса. Источник: 625 ILCS 5/15-111."},"18":{"q":"Местный орган власти в Иллинойсе может на законных основаниях устанавливать и разрешать полную массу выше установленного законом предела на автомагистрали, находящейся в его юрисдикции, только если он делает что?","options":["Устанавливает соответствующие регулирующие знаки, уведомляющие об этом, не превышая при этом максимумов для одиночной или тандемной оси","Получает письменное одобрение от Federal Highway Administration","Увеличивает максимум для одиночной оси до 24,000 pounds","Полностью отменяет Федеральную мостовую формулу для этой дороги"],"explanation":"Местные органы власти могут разрешать увеличенные нагрузки на обозначенных местных автомагистралях только при установке надлежащих регулирующих знаков, и при этом они всё равно не могут превышать максимумы для одиночной или тандемной оси. Источник: 625 ILCS 5/15-111 и связанные положения о полномочиях местных органов власти."},"19":{"q":"Водитель перевозит груз шириной 9 футов и высотой 14 футов по автомагистрали штата Иллинойс без разрешения. Какова правильная характеристика этой перевозки?","options":["Она незаконна; как ширина (более 8'6\"), так и высота (более 13'6\") превышают допустимые ограничения и требуют разрешения IDOT на негабаритный груз","Она законна, потому что сельскохозяйственные грузы освобождены от всех ограничений по размеру","Она законна, потому что разрешение требуется только для массы, а не для габаритов","Она законна, потому что груз меньше 80,000 pounds полной массы"],"explanation":"Превышение ширины 8'6\" или высоты 13'6\" делает перевозку незаконной без разрешения IDOT на негабаритный груз; габаритные ограничения применяются независимо от полной массы. Источник: 625 ILCS 5/15-102, 15-103 и 15-301."},"20":{"q":"В Иллинойсе какой класс CDL требуется для управления составом транспортных средств с полной массой автопоезда (GCWR) 26,001 lbs или более, где буксируемое транспортное средство имеет GVWR более 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"explanation":"Иллинойс определяет CDL класса A как состав транспортных средств с GCWR 26,001 lbs или более, при условии что буксируемая единица имеет GVWR более 10,000 lbs. Источник: Illinois SOS CDL Study Guide / страница классов CDL ilsos.gov; 92 Ill. Admin. Code 1030."},"21":{"q":"Согласно правилам Иллинойса, CDL класса B разрешает управление каким из следующих?","options":["Любым одиночным транспортным средством с GVWR 26,001 lbs или более (буксирующим единицу не более 10,000 lbs)","Любым составом, буксирующим единицу более 10,000 lbs","Только транспортными средствами менее 16,000 lbs GVWR","Только транспортными средствами, рассчитанными на перевозку 16+ пассажиров"],"explanation":"Иллинойс определяет CDL класса B как любое одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее другое не более 10,000 lbs (например, прямые грузовики, крупные автобусы). Источник: Illinois SOS CDL Study Guide / ilsos.gov."},"22":{"q":"Водитель из Иллинойса хочет управлять небольшим фургоном, рассчитанным на перевозку 16 или более пассажиров (включая водителя), который весит менее 26,001 lbs. Какой класс CDL применяется?","options":["Class C","Class A","Class B","CDL не требуется"],"explanation":"Класс C в Иллинойсе охватывает любое транспортное средство, не соответствующее классам A или B, которое рассчитано на перевозку 16 или более пассажиров, включая водителя, либо которое перевозит опасные материалы, требующие нанесения табличек (placards). Источник: Illinois SOS CDL Study Guide / ilsos.gov."},"23":{"q":"Какая отметка CDL (endorsement) требуется в Иллинойсе для управления транспортным средством, перевозящим опасные материалы в количествах, требующих нанесения табличек (placards)?","options":["H (HazMat)","N (Tanker)","T (Doubles/Triples)","P (Passenger)"],"explanation":"Отметка H требуется для любого транспортного средства, перевозящего опасные материалы, требующие нанесения табличек (placards). Иллинойс дополнительно требует прохождения оценки угрозы безопасности TSA и ELDT перед сдачей теоретического экзамена на отметку H. Источник: страница ilsos.gov Hazardous Materials Endorsement."},"24":{"q":"В Иллинойсе какая отметка (endorsement) требуется для управления автоцистерной, перевозящей жидкости или газы наливом/насыпью?","options":["N (Tanker)","H (HazMat)","T (Doubles/Triples)","S (School Bus)"],"explanation":"Отметка N разрешает управление автоцистерной, перевозящей жидкости или газы. Она требует сдачи теоретического экзамена по автоцистернам. Источник: Illinois SOS CDL Study Guide / отметки ilsos.gov."},"25":{"q":"Отметка T в Иллинойсе (Doubles/Triples) может быть добавлена только к какому классу CDL?","options":["Class A","Class B","Class C","К любому классу"],"explanation":"В Иллинойсе отметка T (Doubles/Triples) применяется только к CDL класса A, поскольку буксировка более одного прицепа требует лицензии на составы. Примечание: тройные прицепы не разрешены на автомагистралях Иллинойса. Источник: материалы Illinois SOS CDL / отметки ilsos.gov."},"26":{"q":"Какое утверждение о тройных прицепах в Иллинойсе является верным?","options":["Тройные прицепы не разрешены на автомагистралях Иллинойса","Тройные прицепы разрешены только на межштатных автомагистралях","Тройные прицепы разрешены с отметкой P","Тройные прицепы требуют только CDL класса B"],"explanation":"Хотя отметка называется Doubles/Triples (T), закон Иллинойса не разрешает составы с тройными прицепами на своих автомагистралях. Источник: информация об отметках Illinois SOS CDL / ilsos.gov."},"27":{"q":"В Иллинойсе какая отметка (endorsement) требуется для управления транспортным средством, рассчитанным на перевозку 16 или более пассажиров, включая водителя?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"explanation":"Отметка P (Passenger) требуется для управления транспортным средством, рассчитанным на перевозку 16 или более человек, включая водителя; она требует сдачи теоретического экзамена и экзамена по навыкам на репрезентативном транспортном средстве. Источник: Illinois SOS CDL Study Guide / ilsos.gov."},"28":{"q":"Чтобы управлять жёлтым школьным автобусом, перевозящим учащихся (12 класса и младше) в Иллинойсе, водителю нужна какая отметка в дополнение к CDL?","options":["S (School Bus)","Только P","N (Tanker)","H (HazMat)"],"explanation":"Отметка S (School Bus) требуется для перевозки учащихся в школу/из школы или на школьные мероприятия; Иллинойс требует теоретический экзамен, экзамен по навыкам и дорожный экзамен (отметка P также является обязательным условием). Источник: ilsos.gov School Bus endorsement."},"29":{"q":"Каков минимальный возраст для получения CDL или CLP в Иллинойсе для управления ТОЛЬКО в пределах Иллинойса (внутриштатные перевозки)?","options":["18","21","19","16"],"explanation":"Иллинойс требует, чтобы заявителю было не менее 18 лет для получения CDL/CLP для внутриштатных перевозок. Источник: страница CDL/CLP ilsos.gov; 625 ILCS 5/6-507."},"30":{"q":"Какой минимальный возраст требует Иллинойс для управления коммерческим транспортным средством в межштатных перевозках или для перевозки пассажиров?","options":["21","18","19","25"],"explanation":"Иллинойс требует, чтобы водителю было не менее 21 года для работы в межштатных перевозках или для перевозки пассажиров; лица в возрасте 18-20 лет ограничены внутриштатными перевозками. Источник: страница CDL/CLP ilsos.gov; 49 CFR 391.11 в редакции, принятой Иллинойсом."},"31":{"q":"Согласно федеральным правилам, принятым Иллинойсом, как долго водитель должен владеть ученическим коммерческим разрешением (CLP) перед сдачей экзамена по навыкам (дорожного экзамена) на CDL?","options":["Не менее 14 days","Не менее 30 days","Не менее 7 days","Не менее 60 days"],"explanation":"Как федеральные правила, так и правила Иллинойса требуют владеть CLP минимум 14 days перед экзаменом по навыкам; вы можете записаться заранее, но дата экзамена должна приходиться на период после 14-дневного срока ожидания. Источник: страница CDL/CLP ilsos.gov; 49 CFR 383.25."},"32":{"q":"Как долго действует ученическое коммерческое разрешение (CLP) в Иллинойсе?","options":["180 days","90 days","1 year","30 days"],"explanation":"CLP в Иллинойсе действует 180 days, что соответствует федеральному стандарту CLP. Источник: страница CDL/CLP ilsos.gov; 49 CFR 383.25."},"33":{"q":"Для чего из следующего Иллинойс требует обучение для водителей начального уровня (ELDT) перед теоретическим экзаменом или экзаменом по навыкам?","options":["Первоначальной отметки H (HazMat), P (Passenger) или S (School Bus)","Только отметки N (Tanker)","Продления любой существующей отметки","Добавления мотоциклетной отметки"],"explanation":"ELDT применяется к получению первого CDL класса A или B, повышению класса и ПЕРВОНАЧАЛЬНОЙ отметки H, P или S. Теоретическое обучение по HazMat (H) должно предшествовать теоретическому экзамену на отметку H. Источник: страница ELDT ilsos.gov; 49 CFR Part 380."},"34":{"q":"Какой набор документов должен предъявить заявитель на CLP/CDL в Иллинойсе в учреждении Secretary of State?","options":["Подтверждение личности, письменное подтверждение номера Social Security, подтверждение законного/правомерного присутствия и два подтверждения проживания в Иллинойсе","Только карту Social Security","Только паспорт США","Только два счёта за коммунальные услуги"],"explanation":"Иллинойс требует подтверждение личности, письменное подтверждение SSN (например, саму карту или W-2; без фотокопий), подтверждение правомерного присутствия и два подтверждения проживания в Иллинойсе. Источник: страницы ilsos.gov по CDL/CLP и законному присутствию."},"35":{"q":"Сколько подтверждений проживания в Иллинойсе требует Secretary of State для заявления на CDL/CLP?","options":["Два","Одно","Три","Ни одного"],"explanation":"Иллинойс требует два приемлемых подтверждения проживания в Иллинойсе, в дополнение к подтверждению личности, SSN и правомерного присутствия. Источник: требования к документам для водительских прав/CDL ilsos.gov."},"36":{"q":"При подаче заявления на CDL в Иллинойсе какая категория самосертификации требует от водителя предоставить действительный федеральный медицинский сертификат DOT (Medical Examiner's Certificate)?","options":["Non-excepted interstate (NI)","Excepted intrastate (EA)","Excepted interstate (EI)","Non-excepted intrastate (NA)"],"explanation":"Иллинойс признаёт четыре категории самосертификации (NI, EI, NA, EA). Водитель категории Non-excepted interstate (NI) должен соответствовать федеральным медицинским стандартам DOT и подать медицинский сертификат (Form MCSA-5876). Источник: страница CDL ilsos.gov; 92 Ill. Admin. Code 1030.22."},"37":{"q":"В каком списке правильно названы четыре категории медицинской самосертификации, из которых должны выбирать заявители на CDL/CLP в Иллинойсе?","options":["Non-excepted interstate, Excepted interstate, Non-excepted intrastate, Excepted intrastate","Interstate, Intrastate, Farm, Military","Class A, Class B, Class C, Class D","Local, Regional, National, International"],"explanation":"Иллинойс использует четыре федеральные категории самосертификации: Non-excepted interstate (NI), Excepted interstate (EI), Non-excepted intrastate (NA) и Excepted intrastate (EA). Источник: страница CDL ilsos.gov; 92 Ill. Admin. Code 1030.22."},"38":{"q":"Для держателя CDL в Иллинойсе с отметкой HazMat (H) как часто должна продлеваться оценка угрозы безопасности TSA, чтобы сохранить отметку?","options":["Каждые 5 years","Каждые 2 years","Каждые 10 years","Только один раз, без продления"],"explanation":"Оценка угрозы безопасности TSA для отметки HazMat действительна 5 years; Иллинойс требует прохождения оценки и теоретического экзамена по HazMat при каждом продлении, и водителям следует начинать продление примерно за 60 days до истечения срока. Источник: ilsos.gov Hazardous Materials Endorsement; 49 CFR 1572."},"39":{"q":"Согласно закону Иллинойса, какова максимальная концентрация алкоголя в крови (BAC), которую может иметь держатель CDL при управлении коммерческим транспортным средством (CMV)?","options":["0.04 percent","0.08 percent","0.02 percent","0.00 percent"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1) гласит, что держатель CDL не может управлять CMV с BAC .04 percent или более, что составляет половину предела .08 для других транспортных средств. Источник: Illinois CDL Study Guide; 625 ILCS 5/11-501."},"40":{"q":"Когда водитель управляет транспортным средством на автомагистралях Иллинойса, закон штата о подразумеваемом согласии означает, что водитель заранее согласился сделать что?","options":["Пройти химические тесты для определения концентрации алкоголя в крови","Разрешить досмотр груза транспортного средства в любое время","Оплатить штраф перед оспариванием любой дорожной квитанции","Сдать CDL при любом нарушении правил движения"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1) гласит, что водители, управляющие CMV или не-CMV на автомагистралях, подразумеваемо согласились пройти химические тесты для определения BAC. Источник: Illinois CDL Study Guide; 625 ILCS 5/11-501.1."},"41":{"q":"В Иллинойсе водитель, который отказывается пройти химическое тестирование или показывает результат выше допустимого предела, сталкивается с дисквалификацией на какой минимальный срок за первое нарушение (не HazMat)?","options":["12 months","60 days","6 months","3 years"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): любой водитель, который отказывается от химического тестирования или показывает результат выше допустимого предела, дисквалифицируется минимум на 12 months. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"42":{"q":"Если водитель совершает первое серьёзное алкогольное нарушение ВО ВРЕМЯ перевозки опасных материалов, требующих нанесения табличек (placards), каков минимальный срок дисквалификации в Иллинойсе?","options":["3 years","1 year","5 years","Пожизненно"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): если нарушение происходит во время перевозки опасных материалов, требующих нанесения табличек (placards), водитель дисквалифицируется минимум на три года. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"43":{"q":"Водитель совершает два отдельных серьёзных нарушения (например, два DUI), возникающих из двух или более инцидентов. Какая дисквалификация следует в Иллинойсе?","options":["Пожизненная дисквалификация","Трёхлетняя дисквалификация","Пятилетняя дисквалификация","Дисквалификация на 120-day"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): любой водитель, который совершает два из перечисленных серьёзных нарушений, возникающих из двух или более инцидентов, дисквалифицируется пожизненно. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"44":{"q":"В Иллинойсе любой держатель CDL, управляющий CMV, у которого обнаружено НАЛИЧИЕ алкоголя в организме (ниже 0.04), выводится из эксплуатации (out of service) минимум на какой срок?","options":["24 hours","1 hour","12 hours","72 hours"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): любой держатель CDL, управляющий CMV, у которого обнаружено наличие любого количества алкоголя в организме, выводится из эксплуатации минимум на 24 hours. Источник: Illinois CDL Study Guide; 49 CFR 392.5."},"45":{"q":"Каков максимально допустимый BAC для водителя школьного автобуса, управляющего школьным автобусом в Иллинойсе?","options":["0.00 percent","0.04 percent","0.02 percent","0.08 percent"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): водитель школьного автобуса не может управлять школьным автобусом с BAC более .00 percent. Источник: Illinois CDL Study Guide."},"46":{"q":"Сознательное и умышленное оставление места происшествия при управлении CMV приводит к дисквалификации в Иллинойсе на какой минимальный срок?","options":["12 months","60 days","120 days","3 years"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): сознательное и умышленное оставление места происшествия при управлении CMV или не-CMV приводит к дисквалификации минимум на 12 months. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"47":{"q":"Использование коммерческого или некоммерческого транспортного средства для совершения тяжкого преступления, связанного с производством или распространением контролируемого вещества, приводит к какому наказанию в Иллинойсе?","options":["Пожизненная дисквалификация","Дисквалификация на один год","Дисквалификация на три года","Дисквалификация на 120-day"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): использование CMV или не-CMV в тяжком преступлении, связанном с производством, распространением или сбытом контролируемого вещества, приводит к пожизненной дисквалификации. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"48":{"q":"За ПЕРВОЕ осуждение за нарушение правил на железнодорожном переезде в CMV каков срок дисквалификации в Иллинойсе?","options":["60 days","30 days","120 days","1 year"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): первое осуждение за нарушение на железнодорожном переезде влечёт дисквалификацию на 60 days. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"49":{"q":"ВТОРОЕ нарушение правил на железнодорожном переезде в течение трёхлетнего периода приводит к какой дисквалификации в Иллинойсе?","options":["120 days","60 days","1 year","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): второе осуждение за нарушение на железнодорожном переезде в течение трёх лет влечёт дисквалификацию на 120 days. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"50":{"q":"ТРЕТЬЕ или последующее нарушение правил на железнодорожном переезде в течение трёхлетнего периода приводит к какой дисквалификации в Иллинойсе?","options":["1 year","120 days","60 days","Пожизненно"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): третье и последующее осуждение за нарушение на железнодорожном переезде в течение трёх лет влечёт дисквалификацию на один год. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"51":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение трёхлетнего периода влекут дисквалификацию на 60 дней в Иллинойсе?","options":["Два","Три","Одно","Четыре"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): два серьёзных нарушения правил дорожного движения в течение трёхлетнего периода влекут дисквалификацию на 60 days. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"52":{"q":"Три серьёзных нарушения правил дорожного движения в течение трёхлетнего периода влекут какой срок дисквалификации в Иллинойсе?","options":["120 days","60 days","1 year","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): три серьёзных нарушения правил дорожного движения в течение трёхлетнего периода влекут дисквалификацию на 120 days. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"53":{"q":"При какой скорости сверх установленного предела одиночное нарушение скоростного режима считается 'серьёзным нарушением правил дорожного движения' для держателя CDL в Иллинойсе?","options":["15 mph или более сверх предела","10 mph или более сверх предела","20 mph или более сверх предела","25 mph или более сверх предела"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): чрезмерное превышение скорости — это любое одиночное нарушение на 15 mph или более сверх установленного ограничения скорости. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"54":{"q":"Что из следующего классифицируется как 'серьёзное нарушение правил дорожного движения' для держателя CDL в Иллинойсе?","options":["Неправильная или беспорядочная смена полос движения","Просроченная наклейка регистрации транспортного средства","Нарушение правил парковки в центре города","Перегруженная ось на грузе с разрешением"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3) перечисляет неправильную/беспорядочную смену полос, слишком близкое следование, безрассудное вождение, чрезмерное превышение скорости и набор текстовых сообщений в CMV как серьёзные нарушения правил дорожного движения. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"55":{"q":"Согласно Illinois CDL Study Guide, какова дисквалификация за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order)?","options":["Не менее 90 days","Не менее 30 days","Не менее 60 days","Не менее 1 year"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): вы теряете свой CDL минимум на 90 days за первое нарушение предписания о выводе из эксплуатации. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"56":{"q":"Водитель совершает ТРИ или более нарушения предписаний о выводе из эксплуатации в течение 10-летнего периода. Каков минимальный срок дисквалификации в Иллинойсе?","options":["3 years","1 year","90 days","Пожизненно"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): не менее трёх лет за три или более нарушения предписаний о выводе из эксплуатации в течение 10-летнего периода (второе нарушение за 10 лет — не менее одного года). Источник: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"57":{"q":"Как Иллинойс классифицирует водителя CMV, который набирает текстовые сообщения или использует ручной мобильный телефон во время управления CMV?","options":["Как серьёзное нарушение правил дорожного движения","Как серьёзное правонарушение, влекущее пожизненную дисквалификацию","Как нарушение типа парковки без влияния на CDL","Как нарушение предписания о выводе из эксплуатации"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): набор текстовых сообщений или использование ручного мобильного телефона во время управления CMV является серьёзным нарушением правил дорожного движения; штраф FMCSA для водителя может достигать $2,750. Источник: Illinois CDL Study Guide; 625 ILCS 5/12-610.2; 49 CFR 392.80/392.82."},"58":{"q":"Какой максимальный штраф может наложить суд в Иллинойсе за управление коммерческим транспортным средством без действительного CDL или за владение более чем одной лицензией?","options":["До $5,000 или тюремное заключение","Только до $1,000","Только до $500","До $10,000 или тюремное заключение"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.6): суд может наложить штраф до $5,000 или тюремное заключение за управление CMV без CDL или за владение более чем одной лицензией. Источник: Illinois CDL Study Guide; 625 ILCS 5/6-507."},"59":{"q":"Закон Иллинойса «Уступи дорогу» (закон Скотта) требует, чтобы водитель, приближающийся к стоящему аварийному или ремонтному автомобилю с включёнными мигающими предупредительными огнями, сделал что?","options":["По возможности перестроиться в несоседнюю полосу, а если это невозможно — снизить скорость и продолжать движение с осторожностью","Полностью остановиться и ждать, пока аварийный автомобиль не уедет","Сохранять скорость, но сигналить клаксоном во время проезда","Съехать на обочину позади аварийного автомобиля и остановиться"],"explanation":"Согласно закону Скотта, 625 ILCS 5/11-907(c), водитель, приближающийся к стоящему аварийному, ремонтному или эвакуационному автомобилю с мигающими огнями, должен, когда это безопасно, перестроиться в полосу, не соседствующую с ним, а если перестроение невозможно — снизить скорость и продолжать движение с осторожностью. Источник: 625 ILCS 5/11-907; страница закона «Уступи дорогу» полиции штата Иллинойс."},"60":{"q":"Закон, названный в честь лейтенанта Скотта Гиллена и требующий, чтобы водители Иллинойса уступали дорогу стоящим аварийным автомобилям, широко известен как что?","options":["Закон Стива","Закон Скотта","Акт Дэна Райана","Закон жёлтого света"],"explanation":"Закон Иллинойса «Уступи дорогу» официально носит прозвище «закон Скотта» — в честь лейтенанта пожарной службы Чикаго Скотта Гиллена, который был сбит и погиб на скоростной автомагистрали Дэна Райана в 2000 году. Источник: 625 ILCS 5/11-907; полиция штата Иллинойс."},"61":{"q":"Школьный автобус и автомобиль с табличками опасных грузов, которые обязаны останавливаться на железнодорожном переезде в Иллинойсе, должны остановиться в пределах какого расстояния от ближайшего рельса?","options":["Между 5 и 25 футами","Между 10 и 35 футами","Между 15 и 50 футами","Между 25 и 75 футами"],"explanation":"Руководство по CDL штата Иллинойс предписывает водителю автобуса «Остановите автобус в пределах от 15 до 50 футов перед железнодорожными переездами», а автомобиль с табличками «должен остановиться в пределах от 15 до 50 футов перед ближайшим рельсом». Источник: Учебное руководство по CDL Illinois SOS, разделы 4.3.5 и 9.6.12."},"62":{"q":"Согласно закону Иллинойса, какова максимальная допустимая высота транспортного средства, включая груз, на любой автомагистрали штата без специального разрешения?","options":["12 футов 6 дюймов","13 футов 6 дюймов","14 футов 0 дюймов","13 футов 0 дюймов"],"explanation":"Иллинойс ограничивает высоту транспортного средства, измеряемую от нижней части шины до верха транспортного средства, включая груз, значением 13 футов 6 дюймов на любой автомагистрали. Источник: 625 ILCS 5/15-103."},"63":{"q":"Когда коммерческое транспортное средство вынуждено остановиться на дороге с односторонним движением или на разделённой автомагистрали в Иллинойсе или рядом с ней, водитель должен разместить три предупреждающих устройства примерно на каких расстояниях в сторону приближающегося транспорта?","options":["10, 100 и 200 футов","10, 50 и 100 футов","25, 100 и 250 футов","5, 75 и 150 футов"],"explanation":"На дороге с односторонним движением или на разделённой автомагистрали руководство по CDL штата Иллинойс требует размещения предупреждающих устройств на расстоянии 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта. Источник: Учебное руководство по CDL Illinois SOS, подраздел 2.5 («Предупреждающие устройства»)."},"64":{"q":"В округах Кук, Дюпейдж, Кейн, Лейк, Макгенри и Уилл грузовик второго разряда, зарегистрированный на массу более 8 000 фунтов, ограничен какой скоростью на дорогах, автомагистралях и улицах, которые НЕ являются платными межштатными автомагистралями?","options":["65 mph","60 mph","55 mph","45 mph"],"explanation":"В этих шести округах грузовики массой более 8 000 фунтов ограничены 60 mph на платных межштатных автомагистралях Иллинойса (Illinois Tollway) и 55 mph на всех прочих дорогах, автомагистралях или улицах. Источник: 625 ILCS 5/11-601(e)."},"65":{"q":"За пределами городской зоны на сельской межштатной автомагистрали Иллинойса с установленным ограничением 70 mph (и за пределами шести пригородных округов Чикаго) крупный грузовик согласно действующему законодательству Иллинойса может двигаться с какой максимальной скоростью?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"После изменения 625 ILCS 5/11-601 в 2014 году грузовики на сельских межштатных автомагистралях за пределами шести пригородных округов могут двигаться с тем же установленным ограничением, что и легковые автомобили, до 70 mph; только в округах Кук, Дюпейдж, Кейн, Лейк, Макгенри и Уилл они ограничены более низкими лимитами, специфичными для грузовиков. Источник: 625 ILCS 5/11-601(d-1), (e)."},"66":{"q":"При пересечении железнодорожных путей в Иллинойсе водитель с CDL должен сделать что из перечисленного?","options":["Переключиться на пониженную передачу на полпути для дополнительной мощности","Не переключать передачи во время пересечения путей","Переключиться на нейтраль и проехать накатом","Переключиться на повышенную передачу, чтобы освободить пути как можно быстрее"],"explanation":"Руководство по CDL штата Иллинойс прямо гласит: «Не переключайте передачи при пересечении железнодорожных путей», поскольку неудачное или скрежещущее переключение может привести к остановке транспортного средства на путях. Источник: Учебное руководство по CDL Illinois SOS, подразделы 2.15 и 9.6.12."},"67":{"q":"На автомагистрали Иллинойса с четырьмя или более полосами, допускающей движение по крайней мере двух полос транспорта в противоположных направлениях, водитель, встречающий школьный автобус, остановившийся на ВСТРЕЧНОЙ проезжей части, должен сделать что?","options":["Остановиться и оставаться на месте, пока красные огни автобуса не перестанут мигать","Остановиться, только если видны дети","Останавливаться не обязан, но должен сохранять бдительность","Снизить скорость до 20 mph и продолжить движение мимо автобуса"],"explanation":"Закон Иллинойса предусматривает, что водитель на автомагистрали с 4 или более полосами, допускающей движение по крайней мере 2 полос транспорта в противоположных направлениях, не обязан останавливаться при ВСТРЕЧЕ со школьным автобусом, остановившимся на встречной проезжей части. Источник: 625 ILCS 5/11-1414(e)."},"68":{"q":"За исключением случая разделённой автомагистрали, когда школьный автобус остановился на проезжей части Иллинойса с мигающими сигнальными огнями для посадки или высадки учеников, что должны сделать приближающиеся водители?","options":["Остановиться, прежде чем встретить или обогнать автобус с любого направления","Остановиться, только если приближаются сзади автобуса","Медленно проехать слева со скоростью не более 10 mph","Остановиться только тогда, когда регулировщик подаст им знак"],"explanation":"Иллинойс требует, чтобы водители останавливали транспортное средство, прежде чем встретить или обогнать с любого направления любой школьный автобус, который остановился и отображает свои визуальные сигнальные огни для посадки или высадки учеников. Источник: 625 ILCS 5/11-1414(a)."},"69":{"q":"Помимо автомобилей с табличками, какой из следующих обязан всегда останавливаться перед пересечением железнодорожных путей в Иллинойсе?","options":["Любой бортовой грузовик массой более 10 000 фунтов","Любое транспортное средство, перевозящее любое количество хлора","Любое транспортное средство, буксирующее платформенный прицеп","Любое транспортное средство, зарегистрированное за пределами штата"],"explanation":"Руководство по CDL штата Иллинойс перечисляет три категории, которые должны останавливаться перед железнодорожным переездом: транспортные средства с табличками, транспортные средства, перевозящие любое количество хлора, и грузовые цистерны (заполненные или пустые), используемые для опасных материалов. Источник: Учебное руководство по CDL Illinois SOS, подраздел 9.6.12."},"70":{"q":"Какова максимальная допустимая ширина (исключая зеркала и определённые устройства безопасности) для транспортного средства или его груза на автомагистралях Иллинойса без специального разрешения?","options":["8 футов 0 дюймов","8 футов 6 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Иллинойс ограничивает общую наружную ширину транспортного средства или груза значением 8 футов 6 дюймов; всё, что шире, требует разрешения на негабаритный груз от IDOT. Источник: 625 ILCS 5/15-102."},"71":{"q":"Когда водитель с CDL вынужден остановиться на обочине или проезжей части любой автомагистрали Иллинойса, в течение какого числа минут должны быть размещены аварийные предупреждающие устройства?","options":["5 минут","10 минут","15 минут","30 минут"],"explanation":"Руководство по CDL штата Иллинойс требует, чтобы предупреждающие устройства были выставлены в течение 10 минут после остановки на дороге или обочине. Источник: Учебное руководство по CDL Illinois SOS, подраздел 2.5."},"72":{"q":"Сколько красных светоотражающих предупреждающих треугольников должно перевозить коммерческое транспортное средство, чтобы выполнить требование о предупреждающих устройствах в Иллинойсе?","options":["Два","Три","Четыре","Шесть"],"explanation":"Руководство по CDL штата Иллинойс требует три светоотражающих предупреждающих треугольника (либо, как альтернативу, шесть факелов или три фальшфейера с жидким горючим) в составе обязательного аварийного оборудования. Источник: Учебное руководство по CDL Illinois SOS, подраздел 2.1."},"73":{"q":"Водитель, перевозящий опасные материалы с табличками, который осуждён за нарушение на железнодорожно-автомобильном переезде в Иллинойсе, сталкивается с каким последствием?","options":["Только письменное предупреждение","Приказ о выводе из эксплуатации на 24 часа","Дисквалификация CDL","Штрафные баллы, но без дисквалификации"],"explanation":"Нарушения на железнодорожно-автомобильных переездах являются дисквалифицирующими правонарушениями для держателей CDL в Иллинойсе, с возрастающими сроками дисквалификации (60 дней, 120 дней, затем один год) за повторные нарушения в течение трёх лет. Источник: Учебное руководство по CDL Illinois SOS, подраздел 1.2 («Дисквалификации»); 49 CFR 383.51 в редакции, принятой Иллинойсом."},"74":{"q":"Нарушение закона Скотта (закона Иллинойса «Уступи дорогу») при первом правонарушении влечёт штраф в размере не менее какой суммы?","options":["$100","$250","$500","$1,000"],"explanation":"После принятия Public Act 101-0173 нарушение закона Скотта является деловым правонарушением со штрафом не менее $250 и до $10,000 за первое правонарушение. Источник: 625 ILCS 5/11-907(c)."},"75":{"q":"На чикагском бульваре Лейк-Шор-Драйв (Lake Shore Drive), который юридически классифицируется как бульвар/парковая дорога, что обычно запрещено?","options":["Транспортные средства с грузовыми (коммерческими) номерными знаками, предназначенные для перевозки грузов","Все транспортные средства в часы пик в будние дни","Только легковые автомобили, буксирующие прицепы","Транспортные средства без иллинойсского транспондера I-PASS"],"explanation":"Лейк-Шор-Драйв обозначен как бульвар, и транспортные средства с грузовыми номерными знаками, предназначенные для перевозки грузов или коммерческих товаров, не допускаются на него — это особое чикагское ограничение маршрута, уходящее корнями в его происхождение как «прогулочной дороги». Источник: ограничения для бульваров согласно Муниципальному кодексу Чикаго; руководство CDOT по разрешениям на проезд грузовиков по Лейк-Шор-Драйв."},"76":{"q":"На железнодорожном переезде, где иначе требуется остановка, водитель автобуса в Иллинойсе НЕ обязан полностью останавливаться, но должен снизить скорость и внимательно осмотреться, в какой ситуации?","options":["Когда переезд находится на гравийной дороге","Когда полицейский или регулировщик управляет движением","Когда автобус пуст и без пассажиров","Когда автобус длиннее 40 футов"],"explanation":"Руководство по CDL штата Иллинойс гласит, что автобус не обязан останавливаться, но должен снизить скорость и внимательно осмотреться на трамвайных переездах, там, где полицейский или регулировщик управляет движением, или когда светофор показывает зелёный сигнал. Источник: Учебное руководство по CDL Illinois SOS, подраздел 4.3.5."},"77":{"q":"Поскольку рельеф Иллинойса в основном равнинный, традиционные гравитационные аварийные съезды для грузовиков с отказавшими тормозами здесь редки. Что это означает для водителя с CDL, спускающегося по длинному уклону или подъезду к мосту в Иллинойсе?","options":["Они могут рассчитывать на наличие аварийного съезда внизу любого уклона","Им не следует полагаться на аварийный съезд, и они должны контролировать скорость правильным торможением и подбором передач","Закон Иллинойса запрещает использование моторного тормоза на всех уклонах","Аварийные съезды обязательны на каждом межштатном спуске в Иллинойсе"],"explanation":"В отличие от горных штатов, равнинный рельеф Иллинойса означает, что аварийные съезды редки, поэтому водители должны справляться со спусками с помощью правильно подобранных пониженных передач и техники торможения, а не рассчитывать на аварийный съезд. Источник: Учебное руководство по CDL Illinois SOS, подраздел 2.16 («Вождение в горах / контроль скорости на спусках»)."},"78":{"q":"Водитель в Иллинойсе, приближающийся к остановившемуся школьному автобусу на ДВУХПОЛОСНОЙ неразделённой автомагистрали и движущийся в любом направлении, должен сделать что?","options":["Продолжить движение со сниженной скоростью мимо автобуса","Остановиться, не доезжая до автобуса, и оставаться на месте, пока сигналы не будут выключены","Остановиться, только если приближается с того же направления, что и автобус","Проехать слева, подав сигнал клаксоном"],"explanation":"На двухполосной неразделённой автомагистрали исключение для разделённой автомагистрали не применяется, поэтому водители, приближающиеся с любого направления, должны остановиться, прежде чем встретить или обогнать школьный автобус с включёнными красными сигналами, и оставаться на месте, пока сигналы не прекратятся и автобус не возобновит движение. Источник: 625 ILCS 5/11-1414(a) и (b)."},"79":{"q":"В Иллинойсе какое государственное ведомство выдаёт коммерческие водительские удостоверения (CDL) и проводит экзамены на знание и навыки CDL?","options":["Секретарь штата Иллинойс (Illinois Secretary of State)","Департамент транспорта Иллинойса (IDOT)","Полиция штата Иллинойс","Департамент транспортных средств Иллинойса (DMV)"],"explanation":"В Иллинойсе нет «DMV»; Канцелярия секретаря штата Иллинойс (Illinois SOS) является органом штата по лицензированию водителей, который выдаёт CDL и проводит экзамены в своих CDL-центрах службы Driver Services. Источник: Учебное руководство по CDL Illinois SOS (DSD CDL) и страницы CDL на ilsos.gov."},"80":{"q":"Где заявитель в Иллинойсе сдаёт экзамены на знание CDL и экзамен на навыки (вождение)?","options":["В CDL-центре службы Driver Services секретаря штата (Secretary of State)","В любом местном отделении полиции штата Иллинойс","Только в федеральном центре тестирования FMCSA","На весовой станции Департамента транспорта Иллинойса"],"explanation":"Письменные экзамены и экзамены на навыки CDL проводятся секретарём штата (Secretary of State) в специально назначенных CDL-центрах службы Driver Services. Источник: Учебное руководство по CDL Illinois SOS и страницы CDL по тестированию/записи на ilsos.gov."},"81":{"q":"Из скольких категорий самосертификации должен выбирать заявитель на CDL/CLP в Иллинойсе, заявляя тип коммерческой деятельности, в которой он работает?","options":["Четыре","Две","Три","Пять"],"explanation":"Иллинойс следует федеральному правилу CDL, требующему, чтобы водители самосертифицировались в одну из четырёх категорий: неисключённая межштатная (Non-Excepted Interstate), исключённая межштатная (Excepted Interstate), неисключённая внутриштатная (Non-Excepted Intrastate) и исключённая внутриштатная (Excepted Intrastate). Источник: Учебное руководство по CDL Illinois SOS; 49 CFR 383.71."},"82":{"q":"Водитель в Иллинойсе, который работает с пересечением границ штатов и НЕ освобождён от федеральных правил физической пригодности, должен самосертифицироваться как какая категория?","options":["Неисключённая межштатная (Non-Excepted Interstate, NI)","Исключённая межштатная (Excepted Interstate, EI)","Неисключённая внутриштатная (Non-Excepted Intrastate, NA)","Исключённая внутриштатная (Excepted Intrastate, EA)"],"explanation":"Водитель в межштатной коммерческой деятельности, который должен соответствовать федеральным медицинским стандартам DOT, самосертифицируется как неисключённая межштатная (Non-Excepted Interstate, NI) и должен иметь действующий медицинский сертификат врача. Источник: Учебное руководство по CDL Illinois SOS; 49 CFR 383.71."},"83":{"q":"Какая категория самосертификации применяется к водителю в Иллинойсе, который работает ТОЛЬКО в пределах Иллинойса и не обязан соответствовать требованиям медицинской сертификации?","options":["Исключённая внутриштатная (Excepted Intrastate, EA)","Неисключённая межштатная (Non-Excepted Interstate, NI)","Исключённая межштатная (Excepted Interstate, EI)","Неисключённая внутриштатная (Non-Excepted Intrastate, NA)"],"explanation":"Водитель, работающий исключительно во внутриштатной (в пределах Иллинойса) коммерческой деятельности, который не обязан соответствовать требованиям медицинской сертификации, самосертифицируется как исключённая внутриштатная (Excepted Intrastate, EA). Источник: Учебное руководство по CDL Illinois SOS; 49 CFR 383.71."},"84":{"q":"Какая федеральная форма является медицинским сертификатом врача (Medical Examiner's Certificate), который держатель CDL категории Non-Excepted Interstate в Иллинойсе должен поддерживать действующим?","options":["Форма MCSA-5876","Форма MCSA-5875","Форма SS-CDL-2","Форма DL-180"],"explanation":"Официальным медицинским сертификатом врача является форма FMCSA MCSA-5876, выдаваемая сертифицированным медицинским экспертом. Неисключённые водители должны хранить действующий сертификат на учёте в штате. Источник: FMCSA; страницы CDL Illinois SOS."},"85":{"q":"По состоянию на изменение 2025 года в Иллинойсе, как обычно медицинский сертификат врача держателя CDL поступает секретарю штата (Secretary of State)?","options":["Сертифицированный медицинский эксперт подаёт его в электронном виде через Национальный реестр FMCSA","Водитель отправляет бумажную копию по почте секретарю штата","Водитель отправляет его по факсу в CDL-центр в течение 15 дней","Водитель лично доставляет бумажную карточку в любой CDL-центр"],"explanation":"С вступлением Иллинойса в интеграцию с Национальным реестром FMCSA (середина 2025 года) сертифицированные медицинские эксперты передают результаты обследования в FMCSA в электронном виде, которая предоставляет их SOS; штат больше не принимает бумажные медицинские карточки в CDL-центрах. Источник: страницы CDL Illinois SOS; Национальный реестр FMCSA."},"86":{"q":"Как часто держатель CDL категории Non-Excepted Interstate в Иллинойсе обычно должен обновлять самосертификацию и предоставлять действующий медицинский сертификат?","options":["Не реже чем каждые 2 года (или раньше, если срок действия сертификата короче)","Каждые 5 лет при продлении удостоверения","Каждые 4 года при продлении удостоверения","Только один раз, при первоначальном лицензировании"],"explanation":"Медицинский сертификат врача действителен максимум 2 года (меньше, если эксперт укажет иное), поэтому неисключённые межштатные водители должны поддерживать действующую медицинскую сертификацию по циклу не реже чем раз в 2 года, независимо от 4-летнего цикла удостоверения. Источник: страницы CDL Illinois SOS; 49 CFR 391.45."},"87":{"q":"Прежде чем быть записанным на экзамен на навыки CDL в Иллинойсе, заявитель на первоначальный класс A или класс B должен выполнить какое требование к обучению?","options":["Начальную подготовку водителей (Entry-Level Driver Training, ELDT) у провайдера, зарегистрированного в FMCSA","30-часовой курс защитного вождения в Иллинойсе","Аудиторный семинар по безопасности секретаря штата Иллинойс","Управляемую штатом стажировку продолжительностью 6 месяцев"],"explanation":"Федеральные правила ELDT, принятые в Иллинойсе, требуют, чтобы заявители на первоначальный класс A/класс B (и определённые повышения/одобрения) прошли начальную подготовку водителей (ELDT) у провайдера, указанного в реестре провайдеров обучения FMCSA (Training Provider Registry), до тестирования. Источник: страница ELDT Illinois SOS; 49 CFR часть 380."},"88":{"q":"Согласно требованию ELDT в Иллинойсе, теоретическая часть обучения должна быть завершена до какого этапа?","options":["Сдачи экзамена на знание CDL (письменного) для нового класса или одобрения","Подачи заявления на базовое водительское удостоверение Иллинойса","Продления существующего удостоверения, не относящегося к CDL","Записи на проверку зрения"],"explanation":"Иллинойс требует, чтобы заявители, претендующие на первоначальный CDL класса A или B, на повышение или на первоначальное одобрение S, P или H, прошли теоретическую подготовку ELDT у зарегистрированного провайдера до сдачи соответствующего экзамена на знание. Источник: страница ELDT Illinois SOS; 49 CFR часть 380."},"89":{"q":"Какое из этих одобрений требует прохождения ELDT, прежде чем заявитель в Иллинойсе сможет пройти по нему тестирование?","options":["Пассажирское (P), школьный автобус (S) и опасные материалы (H)","Только сдвоенные/строенные прицепы (T)","Только автоцистерна (N)","Ни одно из одобрений в Иллинойсе не требует ELDT"],"explanation":"ELDT применяется к первоначальной выдаче одобрений школьного автобуса (S), пассажирского (P) и опасных материалов (H), в дополнение к первоначальным удостоверениям класса A/B и повышениям. Источник: страница ELDT Illinois SOS; 49 CFR часть 380."},"90":{"q":"Что водитель в Иллинойсе должен получить в первую очередь как этап, который позволяет практиковаться за рулём до сдачи экзамена на навыки CDL?","options":["Коммерческое ученическое разрешение (Commercial Learner's Permit, CLP)","Временное межштатное освобождение","Карточку предварительного коммерческого одобрения","Освобождение от дорожного экзамена FMCSA"],"explanation":"После сдачи требуемых экзаменов на знание заявителю выдаётся коммерческое ученическое разрешение (Commercial Learner's Permit, CLP), которое разрешает практику под наблюдением на репрезентативном транспортном средстве до экзамена на навыки. Источник: Учебное руководство по CDL Illinois SOS; 49 CFR 383.25."},"91":{"q":"После выдачи CLP в Иллинойсе сколько времени держатель должен ждать, прежде чем ему будет разрешено сдавать экзамен на навыки CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Периода ожидания нет"],"explanation":"Федеральный закон, принятый Иллинойсом, требует минимального ожидания в 14 дней с даты выдачи CLP, прежде чем может быть проведён экзамен на навыки; заявитель может записаться заранее, но не может выбрать дату внутри этих 14 дней. Источник: страницы CDL Illinois SOS; 49 CFR 383.25."},"92":{"q":"Экзамен на навыки CDL в Иллинойсе проводится в трёх частях. Каков правильный порядок их проведения?","options":["Предрейсовый (осмотр транспортного средства), затем базовые навыки управления, затем дорожный экзамен на вождение","Дорожный экзамен на вождение, затем базовые навыки управления, затем предрейсовый осмотр","Базовые навыки управления, затем дорожный экзамен на вождение, затем предрейсовый осмотр","Предрейсовый осмотр, затем дорожный экзамен на вождение, затем базовые навыки управления"],"explanation":"Экзамен на навыки проводится в порядке: (1) предрейсовый (осмотр транспортного средства), (2) базовые навыки управления и (3) дорожный экзамен на вождение. Источник: Учебное руководство по CDL Illinois SOS и страницы CDL на ilsos.gov."},"93":{"q":"Во время части предрейсового осмотра экзамена на навыки в Иллинойсе заявитель должен прежде всего продемонстрировать способность:","options":["Определять компоненты, которые следует проверить, и объяснять, почему каждый из них важен для безопасной эксплуатации","Разбирать и собирать тормозную систему","Прочитать наизусть весь Транспортный кодекс Иллинойса","Заменить шину за установленный лимит времени"],"explanation":"Экзамен по осмотру транспортного средства требует, чтобы заявитель находил элементы, называл, что проверяется, и объяснял, почему эта проверка важна для безопасной эксплуатации. Источник: Учебное руководство по CDL Illinois SOS (раздел 11, «Экзамен по осмотру транспортного средства»)."},"94":{"q":"Что из следующего является частью раздела «Базовые навыки управления» экзамена на навыки CDL в Иллинойсе?","options":["Контролируемые маневры движения задним ходом, такие как движение задним ходом по прямой и со смещением","Выезд на межштатную автомагистраль на полной скорости","Ответ на 50 письменных вопросов с выбором варианта","Присоединение таблички опасных материалов к прицепу"],"explanation":"Базовые навыки управления оценивают точный контроль транспортного средства на малой скорости с помощью таких маневров, как движение задним ходом по прямой, движение задним ходом со смещением и парковка, обычно на площадке. Источник: Учебное руководство по CDL Illinois SOS («Экзамен по базовым навыкам управления транспортным средством»)."},"95":{"q":"Какой минимальный балл должен набрать заявитель, чтобы сдать каждый экзамен на знание CDL (письменный) в Иллинойсе?","options":["80% правильных ответов","70% правильных ответов","75% правильных ответов","90% правильных ответов"],"explanation":"Экзамены на знание CDL в Иллинойсе требуют минимум 80% правильных ответов для сдачи, что соответствует федеральному стандарту. Источник: Учебное руководство по CDL Illinois SOS; 49 CFR 383.135."},"96":{"q":"Каков стандартный цикл продления коммерческого водительского удостоверения Иллинойса для водителя в обычном возрастном диапазоне?","options":["Каждые 4 года","Каждые 2 года","Каждые 5 лет","Каждые 8 лет"],"explanation":"Стандартный CDL Иллинойса выдаётся по 4-летнему циклу, обычно истекая в день рождения держателя; продление также требует действующей самосертификации и, для неисключённых водителей, действующей медицинской сертификации. Источник: страницы CDL Illinois SOS и информация о продлении службы Driver Services."},"97":{"q":"Каков минимальный возраст для подачи заявления на CDL в Иллинойсе для вождения в МЕЖШТАТНОЙ коммерческой деятельности или для перевозки пассажиров, по сравнению с вождением только в пределах штата?","options":["21 для межштатной деятельности или пассажиров; 18 только для внутриштатной","18 для межштатной деятельности или пассажиров; 16 только для внутриштатной","25 для межштатной деятельности или пассажиров; 21 только для внутриштатной","21 как для межштатной, так и для внутриштатной"],"explanation":"Заявителю должно быть не менее 21 года для работы в межштатной коммерческой деятельности или перевозки пассажиров и не менее 18 лет для получения CDL/CLP для работы только в пределах штата. Источник: Учебное руководство по CDL Illinois SOS и страницы CDL на ilsos.gov."}},"tr":{"0":{"q":"Illinois karayollarında, onaylı güvenlik donanımları ve aynalar hariç olmak üzere, bir ticari aracın azami genişliği nedir?","options":["8 fit 6 inç (102 inches)","8 fit 0 inç (96 inches)","9 fit 0 inç (108 inches)","10 fit 0 inç (120 inches)"],"explanation":"Illinois, aynalar ve diğer onaylı güvenlik donanımları hariç olmak üzere araç genişliğini 8 fit 6 inç (102 inches) ile sınırlar. Kaynak: 625 ILCS 5/15-102; Illinois CDL/Rules of the Road."},"1":{"q":"Illinois karayollarında, yükü dahil olmak üzere bir aracın izin verilen azami yüksekliği nedir?","options":["13 fit 6 inç","13 fit 0 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"Illinois, yol yüzeyinden yükün en üst noktasına kadar ölçülen toplam yüksekliği 13 fit 6 inç ile sınırlar. Kaynak: 625 ILCS 5/15-103."},"2":{"q":"Illinois karayollarında izin (permit) olmaksızın çalışan beş veya daha fazla akslı bir araç kombinasyonunun azami brüt ağırlığı nedir?","options":["80,000 pounds","73,280 pounds","84,000 pounds","88,000 pounds"],"explanation":"Illinois, beş veya daha fazla akslı kombinasyonlar için federal azami brüt ağırlık olan 80,000 pounds değerini benimser. Kaynak: 625 ILCS 5/15-111."},"3":{"q":"Illinois karayollarında tek bir aksa izin verilen azami ağırlık nedir?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Illinois, federal standartla uyumlu olarak tek aksı 20,000 pounds ile sınırlar. Kaynak: 625 ILCS 5/15-111."},"4":{"q":"Illinois karayollarında bir tandem aks grubuna izin verilen azami ağırlık nedir?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Illinois, tandem içindeki hiçbir tek aks 20,000 pounds değerini aşmamak koşuluyla, bir tandem aksı 34,000 pounds ile sınırlar. Kaynak: 625 ILCS 5/15-111."},"5":{"q":"Illinois karayollarında tek bir düz (sabit/rijit) kamyonun azami uzunluğu nedir?","options":["42 fit","40 fit","45 fit","53 fit"],"explanation":"Illinois'te düz kamyon gibi tek bir araç toplam uzunlukta 42 fit değerini aşamaz. Kaynak: 625 ILCS 5/15-107."},"6":{"q":"Illinois'te belirlenmiş karayolu (National Network) sistemi üzerinde, çekici-yarı römork kombinasyonunda çalıştırılan tek bir yarı römorkun azami uzunluğu nedir?","options":["53 fit","48 fit","57 fit","60 fit"],"explanation":"Illinois, federal National Network standardıyla tutarlı olarak çekici-yarı römork kombinasyonunda 53 fit uzunluğa kadar yarı römorklara izin verir. Kaynak: 625 ILCS 5/15-107."},"7":{"q":"Illinois, aks aralığına ve aks sayısına göre izin verilen azami brüt ağırlığı belirlemek için hangi formülü kullanır?","options":["Federal Köprü Formülü (ağırlık-mesafe formülü)","Brüt Kombinasyon Derecesi formülü","Lastik-Yük Endeksi formülü","Tescilli Ağırlık Sınıfı formülü"],"explanation":"Illinois, aks aralığına (L) ve aks sayısına (N) göre azami brüt ağırlığı belirlemek için Federal Köprü Formülü olan W = 500[(LN/(N-1)) + 12N + 36] formülünü kullanır. Kaynak: 625 ILCS 5/15-111."},"8":{"q":"Illinois'te, eyalet tarafından bakımı yapılan bir karayolunda yasal boyut veya ağırlık sınırlarını aşan bir yük için eyalet aşırı boyut/aşırı ağırlık iznini (permit) kim verir?","options":["Illinois Ulaştırma Bakanlığı (IDOT)","Illinois Secretary of State","Illinois Eyalet Polisi","Federal Motor Carrier Safety Administration"],"explanation":"IDOT, yasal yetkisi kapsamında eyalet tarafından bakımı yapılan karayollarındaki taşımalar için aşırı boyut/aşırı ağırlık izinlerini verir. Kaynak: 625 ILCS 5/15-301; IDOT Oversize/Overweight Permits."},"9":{"q":"Bir araç veya yük aşağıdakilerden hangisini aştığında, Illinois aşırı boyut/aşırı ağırlık izni (permit) genellikle gereklidir?","options":["8 fit 6 inç genişlik, 13 fit 6 inç yükseklik veya 80,000 pounds brüt ağırlık","8 fit 0 inç genişlik, 13 fit 0 inç yükseklik veya 73,280 pounds brüt ağırlık","9 fit 0 inç genişlik, 14 fit 0 inç yükseklik veya 84,000 pounds brüt ağırlık","10 fit 0 inç genişlik, 15 fit 0 inç yükseklik veya 90,000 pounds brüt ağırlık"],"explanation":"Bir yük yasal sınırları aştığında (8'6\" genişliğin üzerinde, 13'6\" yüksekliğin üzerinde, yasal uzunluğun üzerinde veya 80,000 lb brüt ağırlığın üzerinde), onu eyalet karayollarında taşımak için bir IDOT izni gereklidir. Kaynak: 625 ILCS 5/15-301; IDOT."},"10":{"q":"Illinois'in (yolla temas eden lastik için) lastik genişliğinin her inçi başına izin verdiği azami yük nedir?","options":["Lastik genişliğinin her inçi başına 800 pounds","Lastik genişliğinin her inçi başına 500 pounds","Lastik genişliğinin her inçi başına 1,000 pounds","Lastik genişliğinin her inçi başına 600 pounds"],"explanation":"Illinois, aks ağırlık sınırlarına ek olarak, kaplamayı korumak için yükü lastik genişliğinin inçi başına 800 pounds ile sınırlar. Kaynak: 625 ILCS 5/15-111."},"11":{"q":"IDOT, Illinois aşırı boyut/aşırı ağırlık ve hasat izinleri için başvuruda hangi çevrim içi sistemi kullanır?","options":["ITAP (Illinois Transportation Automated Permits sistemi)","IRP (International Registration Plan portalı)","CDLIS (Commercial Driver License Information System)","SAFER (Safety and Fitness Electronic Records)"],"explanation":"Başvuru sahipleri, aşırı boyut/aşırı ağırlık ve hasat izinlerine 7/24 çevrim içi erişim sağlayan IDOT'un ITAP sistemi aracılığıyla başvurur. Kaynak: IDOT Oversize/Overweight Permits (webapps.dot.illinois.gov/ITAP)."},"12":{"q":"Ücretsiz Illinois Hasat İzni (Harvest Permit), hasat mevsimi boyunca bir aracın brüt, aks ve tescilli ağırlıkları yasal sınırların yaklaşık yüzde kaç üzerine çıkmasına izin verir?","options":["Yüzde 10'a kadar","Yüzde 5'e kadar","Yüzde 15'e kadar","Yüzde 25'e kadar"],"explanation":"Illinois Hasat İzni, hasat sırasında tarımsal ürünlerin taşınması için yasal brüt, aks ve tescilli ağırlıkların yüzde 10'una kadar fazlasına izin verir. Kaynak: IDOT Harvest Permit; Illinois Farm Bureau."},"13":{"q":"IDOT tarafından verilen Illinois Hasat İzni (Harvest Permit), hangi yollarda aşırı ağırlıklı tarımsal seyahate izin verir?","options":["Yalnızca eyalet tarafından bakımı yapılan güzergahlar (ayrıca yetkilendirilmedikçe eyaletlerarası yollar veya yerel yollar değil)","Illinois içindeki tüm eyaletlerarası karayolları","Yerel kasaba yolları dahil Illinois'teki herhangi bir kamu yolu","Yalnızca ilçe ve kasaba yolları, asla eyalet güzergahları değil"],"explanation":"IDOT Hasat İzni yalnızca eyalet güzergahlarını kapsar; eyaletlerarası seyahati yetkilendirmez ve yerel yollar ayrı bir yerel yetkilendirme gerektirir. Kaynak: IDOT Harvest Permit; Illinois Farm Bureau."},"14":{"q":"Standart Illinois Hasat İzni (Harvest Permit), uygun bir çiftçiye veya tarımsal taşıyıcıya ne kadara mal olur?","options":["Ücretsizdir","Araç başına $15","Sezon başına $100","Güzergah yetkilendirmesi başına $50"],"explanation":"Illinois, IDOT'un ITAP sistemi aracılığıyla edinilen Hasat İznini uygun tarımsal taşıyıcılara ücretsiz olarak sunar. Kaynak: IDOT Harvest Permit; Illinois Farm Bureau."},"15":{"q":"Illinois, öncelikle doğal gazla çalışan bir araca (daha ağır yakıt sistemini telafi etmek için) ne kadar ek brüt ağırlık izni tanır ve bu nerede geçerli DEĞİLDİR?","options":["2,000 pounds'a kadar fazladan, ancak Interstate sisteminde değil","Interstate'ler dahil tüm karayollarında 5,000 pounds'a kadar fazladan","Yalnızca yerel yollarda 1,000 pounds'a kadar fazladan","Yalnızca Interstate'lerde 4,000 pounds'a kadar fazladan"],"explanation":"Illinois, Interstate karayolları hariç olmak üzere, doğal gazla çalışan araçlar için 2,000 pounds'a kadar ek brüt ağırlığa izin verir. Kaynak: 625 ILCS 5/15-111."},"16":{"q":"Illinois'te yasal bir tandem aks grubu içinde, tandemin hiçbir tek aksı hangi ağırlığı aşamaz?","options":["20,000 pounds","17,000 pounds","18,000 pounds","22,000 pounds"],"explanation":"Bir tandem toplam 34,000 pounds taşıyabilse de, o tandem içindeki hiçbir tek aks 20,000 pounds değerini aşamaz. Kaynak: 625 ILCS 5/15-111."},"17":{"q":"Illinois'te kullanılan Federal Köprü Formülü W = 500[(LN/(N-1)) + 12N + 36] formülünde 'L' değişkeni neyi temsil eder?","options":["Ölçülen grubun en uçtaki (en dıştaki) aksları arasındaki fit cinsinden mesafe","Römorkun fit cinsinden toplam uzunluğu","Lastik başına yasal yük sınırı","Aracın ruhsatlı brüt ağırlığı"],"explanation":"Köprü formülünde L, grubun en uçtaki aksları arasındaki fit cinsinden aralıktır, N aks sayısıdır ve W izin verilen azami ağırlıktır. Kaynak: 625 ILCS 5/15-111."},"18":{"q":"Illinois'te bir yerel idare, yetki alanındaki bir karayolunda yasal sınırdan daha yüksek brüt ağırlıkları yasal olarak ancak ne yaparsa ilan edebilir ve buna izin verebilir?","options":["Tek aks veya tandem aks azami değerlerini aşmadan, bildirimde bulunan uygun düzenleyici işaretler diker","Federal Highway Administration'dan yazılı onay alır","Tek aks azami değerini 24,000 pounds'a çıkarır","O yol için Federal Köprü Formülünü tamamen yürürlükten kaldırır"],"explanation":"Yerel idareler, belirlenmiş yerel karayollarında artırılmış yüklere yalnızca uygun düzenleyici işaretler dikildiğinde izin verebilir ve yine de tek aks veya tandem aks azami değerlerini aşamazlar. Kaynak: 625 ILCS 5/15-111 ve ilgili yerel-idare hükümleri."},"19":{"q":"9 fit genişliğinde ve 14 fit yüksekliğinde bir yükü bir Illinois eyalet karayolundan geçiren bir sürücünün izni (permit) yok. Bu hareketin doğru nitelendirmesi nedir?","options":["Yasa dışıdır; hem genişlik (8'6\" üzerinde) hem de yükseklik (13'6\" üzerinde) yasal sınırları aşar ve bir IDOT aşırı boyut izni gerektirir","Tarımsal yükler tüm boyut sınırlarından muaf olduğu için yasaldır","Yalnızca ağırlık, boyutlar değil, izin gerektirdiği için yasaldır","Yük 80,000 pounds brüt ağırlığın altında olduğu için yasaldır"],"explanation":"8'6\" genişliği veya 13'6\" yüksekliği aşmak, hareketi bir IDOT aşırı boyut izni olmadan yasa dışı kılar; boyut sınırları brüt ağırlıktan bağımsız olarak uygulanır. Kaynak: 625 ILCS 5/15-102, 15-103 ve 15-301."},"20":{"q":"Illinois'te, çekilen aracın GVWR'si 10,000 lbs'den fazla olmak üzere, brüt kombinasyon ağırlık derecesi (GCWR) 26,001 lbs veya daha fazla olan bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Illinois, çekilen birimin GVWR'si 10,000 lbs'den fazla olmak koşuluyla, GCWR'si 26,001 lbs veya daha fazla olan bir araç kombinasyonunu Class A CDL olarak tanımlar. Kaynak: Illinois SOS CDL Study Guide / ilsos.gov CDL classes sayfası; 92 Ill. Admin. Code 1030."},"21":{"q":"Illinois kurallarına göre, bir Class B CDL aşağıdakilerden hangisinin kullanımına yetki verir?","options":["GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek araç (10,000 lbs'yi aşmayan bir birimi çekerek)","10,000 lbs'yi aşan bir birimi çeken herhangi bir kombinasyon","Yalnızca 16,000 lbs GVWR altındaki araçlar","Yalnızca 16 veya daha fazla yolcu taşımak için tasarlanmış araçlar"],"explanation":"Illinois, GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek aracı veya 10,000 lbs'yi aşmayan başka bir birimi çeken böyle bir aracı (örneğin düz kamyonlar, büyük otobüsler) Class B CDL olarak tanımlar. Kaynak: Illinois SOS CDL Study Guide / ilsos.gov."},"22":{"q":"Bir Illinois sürücüsü, 26,001 lbs'nin altında ağırlığa sahip, (sürücü dahil) 16 veya daha fazla yolcu taşımak için tasarlanmış küçük bir minibüsü kullanmak istiyor. Hangi CDL sınıfı uygulanır?","options":["Class C","Class A","Class B","CDL gerekli değil"],"explanation":"Illinois Class C, Class A veya B'yi karşılamayan ve sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da plakart gerektiren tehlikeli maddeler taşıyan herhangi bir aracı kapsar. Kaynak: Illinois SOS CDL Study Guide / ilsos.gov."},"23":{"q":"Illinois'te plakart gerektiren miktarlarda tehlikeli madde taşıyan bir aracı kullanmak için hangi CDL onayı (endorsement) gereklidir?","options":["H (HazMat)","N (Tanker)","T (Doubles/Triples)","P (Passenger)"],"explanation":"Plakart gerektiren tehlikeli madde taşıyan herhangi bir araç için H onayı gereklidir. Illinois ayrıca H bilgi sınavından önce bir TSA güvenlik tehdidi değerlendirmesi ve ELDT gerektirir. Kaynak: ilsos.gov Hazardous Materials Endorsement sayfası."},"24":{"q":"Illinois'te, dökme halde sıvı veya gaz taşıyan bir tank aracını kullanmak için hangi onay (endorsement) gereklidir?","options":["N (Tanker)","H (HazMat)","T (Doubles/Triples)","S (School Bus)"],"explanation":"N onayı, sıvı veya gaz taşıyan bir tank aracının kullanımına yetki verir. Tank aracı bilgi sınavının geçilmesini gerektirir. Kaynak: Illinois SOS CDL Study Guide / ilsos.gov onaylar."},"25":{"q":"Illinois T onayı (Doubles/Triples) yalnızca hangi CDL sınıfına eklenebilir?","options":["Class A","Class B","Class C","Herhangi bir sınıf"],"explanation":"Illinois'te T (Doubles/Triples) onayı yalnızca Class A CDL için geçerlidir, çünkü birden fazla römork çekmek bir kombinasyon ehliyeti gerektirir. Not: üçlü römorklar Illinois karayollarında yasal değildir. Kaynak: Illinois SOS CDL materyalleri / ilsos.gov onaylar."},"26":{"q":"Illinois'te üçlü römorklarla ilgili hangi ifade doğrudur?","options":["Üçlü römorklara Illinois karayollarında izin verilmez","Üçlü römorklara yalnızca eyaletlerarası yollarda izin verilir","Üçlü römorklara P onayı ile izin verilir","Üçlü römorklar yalnızca bir Class B CDL gerektirir"],"explanation":"Onay Doubles/Triples (T) olarak adlandırılsa da, Illinois yasası karayollarında üçlü römork kombinasyonlarına izin vermez. Kaynak: Illinois SOS CDL onay bilgileri / ilsos.gov."},"27":{"q":"Illinois'te, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı kullanmak için hangi onay (endorsement) gereklidir?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"explanation":"P (Passenger) onayı, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı kullanmak için gereklidir; temsili bir araçta bir bilgi sınavı ve bir beceri sınavı gerektirir. Kaynak: Illinois SOS CDL Study Guide / ilsos.gov."},"28":{"q":"Illinois'te öğrencileri (12. sınıf ve altı) taşıyan sarı bir okul otobüsünü kullanmak için, sürücünün CDL'ye ek olarak hangi onaya (endorsement) ihtiyacı vardır?","options":["S (School Bus)","Yalnızca P","N (Tanker)","H (HazMat)"],"explanation":"S (School Bus) onayı, öğrencileri okula/okuldan veya okul etkinliklerine taşımak için gereklidir; Illinois bilgi, beceri ve bir sürüş sınavı gerektirir (P onayı da bir ön koşuldur). Kaynak: ilsos.gov School Bus onayı."},"29":{"q":"YALNIZCA Illinois içinde (eyalet içi) çalışmak için bir Illinois CDL veya CLP almak için asgari yaş nedir?","options":["18","21","19","16"],"explanation":"Illinois, eyalet içi çalışma için bir CDL/CLP almak isteyen bir başvuru sahibinin en az 18 yaşında olmasını gerektirir. Kaynak: ilsos.gov CDL/CLP sayfası; 625 ILCS 5/6-507."},"30":{"q":"Illinois, eyaletlerarası ticarette bir ticari motorlu aracı kullanmak veya yolcu taşımak için hangi asgari yaşı gerektirir?","options":["21","18","19","25"],"explanation":"Illinois, eyaletlerarası ticarette çalışmak veya yolcu taşımak için bir sürücünün en az 21 yaşında olmasını gerektirir; 18-20 yaş arası kişiler eyalet içi çalışma ile sınırlıdır. Kaynak: ilsos.gov CDL/CLP sayfası; Illinois tarafından benimsenen 49 CFR 391.11."},"31":{"q":"Illinois tarafından benimsenen federal kurallara göre, bir sürücü CDL beceri (yol) sınavına girmeden önce Ticari Öğrenci Belgesini (CLP) ne kadar süre elinde tutmalıdır?","options":["En az 14 days","En az 30 days","En az 7 days","En az 60 days"],"explanation":"Hem federal hem de Illinois kuralları, beceri sınavından önce CLP'nin en az 14 days süreyle elde tutulmasını gerektirir; önceden randevu alabilirsiniz, ancak sınav tarihinin 14 günlük bekleme süresinden sonraya düşmesi gerekir. Kaynak: ilsos.gov CDL/CLP sayfası; 49 CFR 383.25."},"32":{"q":"Bir Illinois Ticari Öğrenci Belgesi (CLP) ne kadar süre geçerlidir?","options":["180 days","90 days","1 yıl","30 days"],"explanation":"Bir Illinois CLP'si, federal CLP standardıyla tutarlı olarak 180 days süreyle geçerlidir. Kaynak: ilsos.gov CDL/CLP sayfası; 49 CFR 383.25."},"33":{"q":"Illinois, aşağıdakilerden hangisi için bilgi veya beceri sınavından önce Giriş Düzeyi Sürücü Eğitimi (ELDT) gerektirir?","options":["İlk H (HazMat), P (Passenger) veya S (School Bus) onayı","Yalnızca N (Tanker) onayı","Mevcut herhangi bir onayın yenilenmesi","Bir motosiklet onayının eklenmesi"],"explanation":"ELDT, ilk Class A veya B CDL'nin alınması, bir yükseltme ve İLK H, P veya S onayı için geçerlidir. HazMat (H) teorik eğitimi, H bilgi sınavından önce gelmelidir. Kaynak: ilsos.gov ELDT sayfası; 49 CFR Part 380."},"34":{"q":"Bir Illinois CLP/CDL başvuru sahibinin bir Secretary of State tesisinde hangi belge setini sunması gerekir?","options":["Kimlik kanıtı, Sosyal Güvenlik numarasının yazılı kanıtı, yasal/hukuki mevcudiyet kanıtı ve iki Illinois ikametgah kanıtı","Yalnızca bir Sosyal Güvenlik kartı","Yalnızca bir ABD pasaportu","Yalnızca iki fatura"],"explanation":"Illinois; kimlik kanıtı, SSN'nin yazılı kanıtı (örneğin asıl kart veya W-2; fotokopi kabul edilmez), hukuki mevcudiyet kanıtı ve iki Illinois ikametgah kanıtı gerektirir. Kaynak: ilsos.gov CDL/CLP ve hukuki mevcudiyet sayfaları."},"35":{"q":"Secretary of State, bir CDL/CLP başvurusu için kaç adet Illinois ikametgah kanıtı gerektirir?","options":["İki","Bir","Üç","Hiçbiri"],"explanation":"Illinois; kimlik, SSN ve hukuki mevcudiyet kanıtına ek olarak, iki kabul edilebilir Illinois ikametgah kanıtı gerektirir. Kaynak: ilsos.gov Driver's License/CDL belge gereksinimleri."},"36":{"q":"Bir Illinois CDL'sine başvururken, hangi öz beyan kategorisi sürücünün geçerli bir federal DOT Tıbbi Muayene Belgesi sunmasını gerektirir?","options":["Muaf olmayan eyaletlerarası (NI)","Muaf eyalet içi (EA)","Muaf eyaletlerarası (EI)","Muaf olmayan eyalet içi (NA)"],"explanation":"Illinois dört öz beyan kategorisini (NI, EI, NA, EA) tanır. Muaf olmayan eyaletlerarası (NI) bir sürücü, federal DOT tıbbi standartlarını karşılamalı ve bir Tıbbi Muayene Belgesi (Form MCSA-5876) sunmalıdır. Kaynak: ilsos.gov CDL sayfası; 92 Ill. Admin. Code 1030.22."},"37":{"q":"Illinois CDL/CLP başvuru sahiplerinin arasından seçim yapması gereken dört tıbbi öz beyan kategorisini hangi liste doğru şekilde adlandırır?","options":["Muaf olmayan eyaletlerarası, Muaf eyaletlerarası, Muaf olmayan eyalet içi, Muaf eyalet içi","Eyaletlerarası, Eyalet içi, Çiftlik, Askeri","Class A, Class B, Class C, Class D","Yerel, Bölgesel, Ulusal, Uluslararası"],"explanation":"Illinois dört federal öz beyan kategorisini kullanır: Muaf olmayan eyaletlerarası (NI), Muaf eyaletlerarası (EI), Muaf olmayan eyalet içi (NA) ve Muaf eyalet içi (EA). Kaynak: ilsos.gov CDL sayfası; 92 Ill. Admin. Code 1030.22."},"38":{"q":"HazMat (H) onaylı bir Illinois CDL sahibi için, onayı korumak amacıyla TSA güvenlik tehdidi değerlendirmesi ne sıklıkta yenilenmelidir?","options":["Her 5 yılda bir","Her 2 yılda bir","Her 10 yılda bir","Yalnızca bir kez, asla yenilenmez"],"explanation":"HazMat onayı için bir TSA güvenlik tehdidi değerlendirmesi 5 yıl geçerlidir; Illinois her yenilemede değerlendirmeyi ve HazMat bilgi sınavını gerektirir ve sürücüler yenilemeye sona ermeden yaklaşık 60 gün önce başlamalıdır. Kaynak: ilsos.gov Hazardous Materials Endorsement; 49 CFR 1572."},"39":{"q":"Illinois yasasına göre, bir CDL sahibi bir ticari motorlu aracı (CMV) kullanırken sahip olabileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.04 percent","0.08 percent","0.02 percent","0.00 percent"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1), bir CDL sahibinin diğer araçlar için geçerli .08 sınırının yarısı olan .04 percent veya daha fazla BAC ile bir CMV kullanamayacağını belirtir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/11-501."},"40":{"q":"Bir sürücü Illinois karayollarında bir araç kullandığında, eyaletin zımni rıza yasası sürücünün önceden ne yapmayı kabul ettiği anlamına gelir?","options":["Kandaki alkol konsantrasyonunu belirlemek için kimyasal testlere tabi olmayı","Aracın yükünün herhangi bir zamanda aranmasına izin vermeyi","Herhangi bir trafik cezasına itiraz etmeden önce bir para cezası ödemeyi","Herhangi bir hareketli ihlalde CDL'yi teslim etmeyi"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1), karayollarında bir CMV veya CMV olmayan araç kullanan sürücülerin, BAC'yi belirlemek için kimyasal testlere tabi olmaya zımnen rıza gösterdiğini belirtir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/11-501.1."},"41":{"q":"Illinois'te, kimyasal teste tabi olmayı reddeden veya yasal sınırın üzerinde test sonucu çıkan bir sürücü, ilk suç için (HazMat olmayan) en az ne kadar süreyle diskalifiye ile karşı karşıya kalır?","options":["12 months","60 days","6 months","3 years"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): kimyasal testi reddeden veya yasal sınırın üzerinde test sonucu çıkan herhangi bir sürücü en az 12 months süreyle diskalifiye edilir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"42":{"q":"Bir sürücü, plakart gerektiren tehlikeli madde taşırken ilk büyük alkol suçunu işlerse, asgari Illinois diskalifiye süresi nedir?","options":["3 years","1 year","5 years","Ömür boyu"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): ihlal plakart gerektiren tehlikeli madde taşırken gerçekleşirse, sürücü en az üç yıl süreyle diskalifiye edilir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"43":{"q":"Bir sürücü, iki veya daha fazla olaydan kaynaklanan iki ayrı büyük suç (örneğin iki DUI) işler. Hangi Illinois diskalifiyesi ortaya çıkar?","options":["Ömür boyu diskalifiye","Üç yıllık diskalifiye","Beş yıllık diskalifiye","120 günlük diskalifiye"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): iki veya daha fazla olaydan kaynaklanan, listelenen büyük ihlallerden ikisini işleyen herhangi bir sürücü ömür boyu diskalifiye edilir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"44":{"q":"Illinois'te, bir CMV kullanan ve sisteminde HERHANGİ bir alkol (0.04'ün altında) bulunan herhangi bir CDL sahibi, en az ne kadar süreyle hizmet dışı bırakılır?","options":["24 hours","1 hour","12 hours","72 hours"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): bir CMV kullanan ve sisteminde herhangi bir alkol bulunan herhangi bir CDL sahibi en az 24 hours süreyle hizmet dışı bırakılır. Kaynak: Illinois CDL Study Guide; 49 CFR 392.5."},"45":{"q":"Illinois'te bir okul otobüsü kullanan bir okul otobüsü sürücüsü için izin verilen azami BAC nedir?","options":["0.00 percent","0.04 percent","0.02 percent","0.08 percent"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): bir okul otobüsü sürücüsü, .00 percent değerinden fazla BAC ile bir okul otobüsü kullanamaz. Kaynak: Illinois CDL Study Guide."},"46":{"q":"Bir CMV kullanırken bir kazanın olay yerini bilerek ve kasten terk etmek, en az ne kadar süreyle Illinois diskalifiyesiyle sonuçlanır?","options":["12 months","60 days","120 days","3 years"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): bir CMV veya CMV olmayan araç kullanırken bir kazanın olay yerini bilerek ve kasten terk etmek, en az 12 months süreyle diskalifiyeyle sonuçlanır. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"47":{"q":"Kontrol altındaki bir maddenin imalatını veya dağıtımını içeren bir suç işlemek için ticari veya ticari olmayan bir motorlu araç kullanmak, hangi Illinois cezasıyla sonuçlanır?","options":["Ömür boyu diskalifiye","Bir yıllık diskalifiye","Üç yıllık diskalifiye","120 günlük diskalifiye"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): kontrol altındaki bir maddenin imalatını, dağıtımını veya temin edilmesini içeren bir suçta bir CMV veya CMV olmayan aracın kullanılması, ömür boyu diskalifiyeyle sonuçlanır. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"48":{"q":"Bir CMV'de demiryolu-karayolu hemzemin geçit düzenlemelerinin İLK ihlali için Illinois diskalifiye süresi nedir?","options":["60 days","30 days","120 days","1 year"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): demiryolu-karayolu hemzemin geçit ihlalinin ilk mahkumiyeti 60 days diskalifiyedir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"49":{"q":"Üç yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali hangi Illinois diskalifiyesiyle sonuçlanır?","options":["120 days","60 days","1 year","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): üç yıl içinde ikinci demiryolu-karayolu hemzemin geçit mahkumiyeti 120 days diskalifiyedir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"50":{"q":"Üç yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali hangi Illinois diskalifiyesiyle sonuçlanır?","options":["1 year","120 days","60 days","Ömür boyu"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): üç yıl içinde üçüncü ve sonraki demiryolu-karayolu hemzemin geçit mahkumiyeti bir yıllık diskalifiyedir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"51":{"q":"Üç yıllık bir süre içinde kaç ciddi trafik ihlali Illinois'te 60 günlük bir diskalifiyeyi tetikler?","options":["İki","Üç","Bir","Dört"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): üç yıllık bir süre içinde iki ciddi trafik ihlali 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"52":{"q":"Üç yıllık bir süre içinde üç ciddi trafik ihlali hangi Illinois diskalifiye süresiyle sonuçlanır?","options":["120 days","60 days","1 year","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): üç yıllık bir süre içinde üç ciddi trafik ihlali 120 günlük bir diskalifiyeyle sonuçlanır. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"53":{"q":"Bir Illinois CDL sahibi için tek bir hız aşımı suçu, belirlenen sınırın üzerinde hangi hızda 'ciddi trafik ihlali' olarak sayılır?","options":["Sınırın 15 mph veya daha fazla üzerinde","Sınırın 10 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 25 mph veya daha fazla üzerinde"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): aşırı hız, belirlenen hız sınırının 15 mph veya daha fazla üzerinde olan herhangi bir tek suçtur. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"54":{"q":"Aşağıdakilerden hangisi bir Illinois CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Uygunsuz veya düzensiz şerit değişiklikleri","Süresi dolmuş bir araç tescil etiketi","Şehir merkezinde bir park ihlali","İzinli bir yükte aşırı ağırlıklı bir aks"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3); uygunsuz/düzensiz şerit değişikliklerini, çok yakın takip etmeyi, dikkatsiz sürüşü, aşırı hızı ve CMV'de mesajlaşmayı ciddi trafik ihlalleri olarak listeler. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"55":{"q":"Illinois CDL Study Guide'a göre, bir hizmet dışı emrinin İLK ihlali için diskalifiye nedir?","options":["En az 90 days","En az 30 days","En az 60 days","En az 1 year"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): bir hizmet dışı emrinin ilk ihlali için CDL'nizi en az 90 days süreyle kaybedersiniz. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"56":{"q":"Bir sürücü 10 yıllık bir süre içinde ÜÇ veya daha fazla hizmet dışı emri ihlali işler. Asgari Illinois diskalifiyesi nedir?","options":["3 years","1 year","90 days","Ömür boyu"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): 10 yıllık bir süre içinde üç veya daha fazla hizmet dışı emri ihlali için en az üç yıl (10 yıl içindeki ikinci ihlal en az bir yıldır). Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"57":{"q":"Illinois, bir CMV kullanırken mesajlaşan veya elde tutulan bir cep telefonu kullanan bir CMV sürücüsünü nasıl sınıflandırır?","options":["Ciddi bir trafik ihlali olarak","Ömür boyu diskalifiyeye neden olan büyük bir suç olarak","CDL etkisi olmayan park türü bir ihlal olarak","Bir hizmet dışı emri ihlali olarak"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): bir CMV kullanırken mesajlaşmak veya elde tutulan bir cep telefonu kullanmak ciddi bir trafik ihlalidir; FMCSA sürücü cezası $2,750'ye ulaşabilir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/12-610.2; 49 CFR 392.80/392.82."},"58":{"q":"Illinois'te bir mahkeme, geçerli bir CDL olmadan bir ticari motorlu araç kullanmak veya birden fazla ehliyete sahip olmak için hangi azami para cezasını uygulayabilir?","options":["$5,000'e kadar veya hapis cezası","Yalnızca $1,000'e kadar","Yalnızca $500'e kadar","$10,000'e kadar veya hapis cezası"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.6): bir mahkeme, CDL olmadan bir CMV kullanmak veya birden fazla ehliyete sahip olmak için $5,000'e kadar para cezası veya hapis cezası uygulayabilir. Kaynak: Illinois CDL Study Guide; 625 ILCS 5/6-507."},"59":{"q":"Illinois'in 'Yol Ver' yasası (Scott Yasası), yanıp sönen uyarı ışıkları yakan duran bir acil durum veya bakım aracına yaklaşan bir sürücüden ne yapmasını ister?","options":["Mümkünse bitişik olmayan bir şeride geçmesini, aksi halde yavaşlayıp dikkatle ilerlemesini","Tamamen durup acil durum aracı ayrılana kadar beklemesini","Hızını korumasını ama geçerken kornaya basmasını","Acil durum aracının arkasında banketin üzerine çekip durmasını"],"explanation":"Scott Yasası, 625 ILCS 5/11-907(c) uyarınca, yanıp sönen ışıklara sahip duran bir acil durum, bakım veya çekici aracına yaklaşan bir sürücü, güvenli olduğunda araca bitişik olmayan bir şeride geçmelidir; şerit değiştirmek mümkün değilse hızını azaltmalı ve dikkatle ilerlemelidir. Kaynak: 625 ILCS 5/11-907; Illinois State Police Move Over Law sayfası."},"60":{"q":"Illinois sürücülerinin duran acil durum araçlarına yol vermesini gerektiren ve Tğm. Scott Gillen'in adını taşıyan yasa genel olarak ne adla bilinir?","options":["Steve Yasası","Scott Yasası","Dan Ryan Yasası","Sarı Işık Yasası"],"explanation":"Illinois'in Yol Ver yasasının resmi takma adı, 2000 yılında Dan Ryan Otoyolu'nda bir araca çarpılarak hayatını kaybeden Chicago İtfaiyesi Tğm. Scott Gillen'in anısına 'Scott Yasası'dır. Kaynak: 625 ILCS 5/11-907; Illinois State Police."},"61":{"q":"Illinois'te bir demiryolu geçidinde durmak zorunda olan bir okul otobüsü ile plakartlı tehlikeli madde taşıyan bir aracın, en yakın raya ne kadar mesafe içinde durması gerekir?","options":["5 ila 25 fit arasında","10 ila 35 fit arasında","15 ila 50 fit arasında","25 ila 75 fit arasında"],"explanation":"Illinois CDL el kitabı, bir otobüs sürücüsünün 'Otobüsünüzü demiryolu geçitlerinden 15 ila 50 fit önce durdurun' demektedir ve plakartlı bir aracın 'en yakın raydan 15 ila 50 fit önce durması gerektiğini' belirtir. Kaynak: Illinois SOS CDL Study Guide, Bölüm 4.3.5 ve 9.6.12."},"62":{"q":"Illinois yasalarına göre, eyaletteki herhangi bir karayolunda izin olmadan bir aracın, yükü dahil, yasal azami yüksekliği nedir?","options":["12 fit 6 inç","13 fit 6 inç","14 fit 0 inç","13 fit 0 inç"],"explanation":"Illinois, lastiğin alt kısmından aracın yükü dahil en üst noktasına kadar ölçülen araç yüksekliğini herhangi bir karayolunda 13 fit 6 inç ile sınırlar. Kaynak: 625 ILCS 5/15-103."},"63":{"q":"Illinois'te bir ticari araç tek yönlü veya bölünmüş bir karayolunda ya da kenarında durmak zorunda kaldığında, sürücü üç uyarı cihazını yaklaşan trafiğe doğru yaklaşık hangi mesafelere yerleştirmelidir?","options":["10, 100 ve 200 fit","10, 50 ve 100 fit","25, 100 ve 250 fit","5, 75 ve 150 fit"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, Illinois CDL el kitabı, uyarı cihazlarının yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit mesafelere yerleştirilmesini gerektirir. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 2.5 (Uyarı Cihazları)."},"64":{"q":"Cook, DuPage, Kane, Lake, McHenry ve Will ilçelerinde, 8.000 pounddan fazla için kayıtlı ikinci sınıf bir kamyon, paralı geçiş eyaletlerarası yolları OLMAYAN yollarda, karayollarında ve caddelerde hangi hızla sınırlıdır?","options":["65 mph","60 mph","55 mph","45 mph"],"explanation":"Bu altı ilçede, 8.000 pounddan ağır kamyonlar Illinois Tollway eyaletlerarası karayollarında 60 mph ve diğer tüm yollar, karayolları veya caddelerde 55 mph ile sınırlıdır. Kaynak: 625 ILCS 5/11-601(e)."},"65":{"q":"Kentsel bir bölge dışında, 70 mph hız limiti olan kırsal bir Illinois eyaletlerarası yolunda (ve Chicago çevresindeki altı çevre ilçesinin dışında), mevcut Illinois yasalarına göre büyük bir kamyon hangi azami hızla seyredebilir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"625 ILCS 5/11-601'deki 2014 değişikliğinden bu yana, altı çevre ilçesinin dışındaki kırsal eyaletlerarası yollardaki kamyonlar, otomobillerle aynı hız limitinde, 70 mph'ye kadar seyredebilir; yalnızca Cook, DuPage, Kane, Lake, McHenry ve Will ilçelerinde daha düşük, kamyona özgü limitlere tabi tutulurlar. Kaynak: 625 ILCS 5/11-601(d-1), (e)."},"66":{"q":"Illinois'te demiryolu raylarını geçerken, bir CDL sürücüsü aşağıdakilerden hangisini yapmalıdır?","options":["Ekstra güç için yarı yolda daha düşük bir vitese geçmeli","Rayları geçerken vites değiştirmemeli","Boşa alıp kayarak geçmeli","Rayları mümkün olduğunca hızlı geçmek için yukarı vites yapmalı"],"explanation":"Illinois CDL el kitabı açıkça şunu belirtir: 'Demiryolu raylarını geçerken vites değiştirmeyin', çünkü kaçırılan veya takılan bir vites aracın raylar üzerinde stop etmesine neden olabilir. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 2.15 ve 9.6.12."},"67":{"q":"En az iki şeridin zıt yönlerde gitmesine izin veren, dört veya daha fazla şeritli bir Illinois karayolunda, KARŞI yönde duran bir okul otobüsüyle karşılaşan bir sürücü ne yapmalıdır?","options":["Durmalı ve otobüsün kırmızı ışıkları yanıp sönmeyi bırakana kadar durmuş halde kalmalı","Yalnızca çocuklar görünürse durmalı","Durması gerekmez, ancak tetikte kalmalı","20 mph'ye yavaşlamalı ve otobüsü geçerek devam etmeli"],"explanation":"Illinois yasaları, en az 2 şeridin zıt yönlerde gitmesine izin veren 4 veya daha fazla şeritli bir karayolundaki bir sürücünün, karşı yönde duran bir okul otobüsüyle KARŞILAŞTIĞINDA durması gerekmediğini öngörür. Kaynak: 625 ILCS 5/11-1414(e)."},"68":{"q":"Bölünmüş karayolu istisnası dışında, bir okul otobüsü öğrenci alıp indirmek için görsel sinyal ışıkları yanıp sönerek bir Illinois yolunda durduğunda, yaklaşan sürücüler ne yapmalıdır?","options":["Otobüsle karşılaşmadan veya onu her iki yönden geçmeden önce durmalı","Yalnızca otobüsün arkasından yaklaşıyorsa durmalı","En fazla 10 mph hızla soldan yavaşça geçmeli","Yalnızca bir geçiş görevlisi işaret ettiğinde durmalı"],"explanation":"Illinois, sürücülerin, öğrenci alıp indirmek için durmuş ve görsel sinyal ışıklarını gösteren herhangi bir okul otobüsüyle karşılaşmadan veya onu her iki yönden geçmeden önce aracı durdurmalarını gerektirir. Kaynak: 625 ILCS 5/11-1414(a)."},"69":{"q":"Plakartlı araçlara ek olarak, Illinois'te demiryolu raylarını geçmeden önce her zaman durmak zorunda olan aşağıdakilerden hangisidir?","options":["10.000 pounddan ağır herhangi bir düz kamyon","Herhangi bir miktarda klor taşıyan herhangi bir araç","Açık platformlu römork çeken herhangi bir araç","Eyalet dışında kayıtlı herhangi bir araç"],"explanation":"Illinois CDL el kitabı, demiryolu geçidinden önce durması gereken üç kategoriyi listeler: plakartlı araçlar, herhangi bir miktarda klor taşıyan araçlar ve tehlikeli maddeler için kullanılan (dolu veya boş) tanker tankları. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 9.6.12."},"70":{"q":"Illinois karayollarında izin olmadan bir araç veya yükü için yasal azami genişlik (aynalar ve belirli güvenlik cihazları hariç) nedir?","options":["8 fit 0 inç","8 fit 6 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"Illinois, bir aracın veya yükün toplam dış genişliğini 8 fit 6 inç ile sınırlar; daha geniş olan her şey IDOT'tan bir gabari aşımı izni gerektirir. Kaynak: 625 ILCS 5/15-102."},"71":{"q":"Bir CDL sürücüsü herhangi bir Illinois karayolunun banketinde veya yolunda durmak zorunda kaldığında, acil durum uyarı cihazları kaç dakika içinde yerleştirilmelidir?","options":["5 dakika","10 dakika","15 dakika","30 dakika"],"explanation":"Illinois CDL el kitabı, bir yolda veya bankette durduktan sonra 10 dakika içinde uyarı cihazlarının yerleştirilmesini gerektirir. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 2.5."},"72":{"q":"Illinois'teki uyarı cihazı gereksinimini karşılamak için bir ticari aracın kaç kırmızı reflektörlü uyarı üçgeni taşıması gerekir?","options":["İki","Üç","Dört","Altı"],"explanation":"Illinois CDL el kitabı, gerekli acil durum ekipmanının bir parçası olarak üç reflektörlü uyarı üçgeni (veya alternatif olarak altı işaret fişeği ya da üç sıvı yakıtlı işaret fişeği) gerektirir. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 2.1."},"73":{"q":"Illinois'te plakartlı tehlikeli madde taşıyan ve demiryolu-karayolu hemzemin geçit ihlalinden mahkûm edilen bir sürücü hangi sonuçla karşılaşır?","options":["Yalnızca yazılı bir uyarı","24 saatlik bir hizmet dışı bırakma emri","CDL diskalifiyesi","Ceza puanı ama diskalifiye yok"],"explanation":"Demiryolu-karayolu hemzemin geçit ihlalleri, Illinois'teki CDL sahipleri için diskalifiye edici suçlardır ve üç yıl içindeki tekrarlanan ihlaller için artan diskalifiye süreleri (60 gün, 120 gün, ardından bir yıl) uygulanır. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 1.2 (Diskalifiyeler); Illinois tarafından kabul edildiği şekliyle 49 CFR 383.51."},"74":{"q":"Scott Yasası'nın (Illinois'in Yol Ver yasası) ilk ihlali en az ne kadar para cezası taşır?","options":["$100","$250","$500","$1,000"],"explanation":"Public Act 101-0173'ten sonra, bir Scott Yasası ihlali, ilk suç için 250 dolardan az olmamak üzere ve 10.000 dolara kadar para cezası olan bir ticari suçtur. Kaynak: 625 ILCS 5/11-907(c)."},"75":{"q":"Yasal olarak bir bulvar/park yolu olarak sınıflandırılan Chicago'nun Lake Shore Drive'ında genellikle ne yasaktır?","options":["Yük taşımak için tasarlanmış kamyon (ticari) plakalı araçlar","Hafta içi yoğun saatlerde tüm araçlar","Yalnızca römork çeken binek otomobiller","Illinois I-PASS transponderı olmayan araçlar"],"explanation":"Lake Shore Drive bir bulvar olarak belirlenmiştir ve yük veya ticari mal taşımak için tasarlanmış kamyon plakalı araçların buraya girmesi yasaktır; bu, 'gezinti yolu' kökenlerine dayanan kendine özgü bir Chicago güzergah kısıtlamasıdır. Kaynak: Chicago Belediye Yasası bulvar kısıtlamaları; CDOT Lake Shore Drive kamyon seyahat izni rehberi."},"76":{"q":"Aksi halde durmanın gerekli olduğu bir demiryolu geçidinde, bir Illinois otobüs sürücüsü hangi durumda tam olarak durmak zorunda DEĞİLDİR, ancak yavaşlayıp dikkatle kontrol etmelidir?","options":["Geçit bir çakıl yolunda olduğunda","Bir polis memuru veya işaretçi trafiği yönlendirdiğinde","Otobüs yolcusuz olduğunda","Otobüs 40 fitten uzun olduğunda"],"explanation":"Illinois CDL el kitabı, bir otobüsün tramvay geçitlerinde, bir polisin veya işaretçinin trafiği yönlendirdiği yerlerde ya da bir trafik sinyali yeşil gösterdiğinde durması gerekmediğini, ancak yavaşlayıp dikkatle kontrol etmesi gerektiğini belirtir. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 4.3.5."},"77":{"q":"Illinois arazisi büyük ölçüde düz olduğundan, geleneksel yerçekimi tipi kaçış kamyonu acil durma rampaları nadirdir. Bu, Illinois'te uzun bir yokuş veya köprü yaklaşımından inen bir CDL sürücüsü için ne anlama gelir?","options":["Herhangi bir yokuşun dibinde bir kaçış rampası bulmaya güvenebilirler","Bir kaçış rampasına güvenmemeli ve hızı doğru fren ve vites kullanımıyla kontrol etmelidirler","Illinois yasaları tüm yokuşlarda motor freni kullanımını yasaklar","Her Illinois eyaletlerarası iniş yokuşunda kaçış rampaları zorunludur"],"explanation":"Dağlık eyaletlerin aksine, Illinois'in düz arazisi kaçış rampalarının nadir olduğu anlamına gelir, bu nedenle sürücüler bir kaçış rampası beklemek yerine yokuş inişlerini doğru düşük vitesler ve fren tekniğiyle yönetmelidir. Kaynak: Illinois SOS CDL Study Guide, Alt bölüm 2.16 (Dağda Sürüş / yokuş inişlerinde hız kontrolü)."},"78":{"q":"İki yönlü, BÖLÜNMEMİŞ bir karayolunda her iki yönden de seyreden ve duran bir okul otobüsüne yaklaşan bir Illinois sürücüsü ne yapmalıdır?","options":["Otobüsü düşük hızda geçerek devam etmeli","Otobüse ulaşmadan önce durmalı ve sinyaller kapatılana kadar durmuş halde kalmalı","Yalnızca otobüsle aynı yönden yaklaşıyorsa durmalı","Kornaya bastıktan sonra soldan geçmeli"],"explanation":"İki yönlü, bölünmemiş bir karayolunda bölünmüş karayolu istisnası geçerli değildir, bu nedenle her iki yönden yaklaşan sürücüler, kırmızı sinyallerini gösteren bir okul otobüsüyle karşılaşmadan veya onu geçmeden önce durmalı ve sinyaller durup otobüs hareketine devam edene kadar durmuş halde kalmalıdır. Kaynak: 625 ILCS 5/11-1414(a) ve (b)."},"79":{"q":"Illinois'te hangi eyalet kurumu Ticari Sürücü Belgelerini düzenler ve CDL bilgi ve beceri sınavlarını yürütür?","options":["Illinois Secretary of State","Illinois Department of Transportation (IDOT)","Illinois State Police","Illinois Department of Motor Vehicles"],"explanation":"Illinois'te bir 'DMV' yoktur; Office of the Illinois Secretary of State (SOS), CDL'leri düzenleyen ve Driver Services CDL tesislerinde sınavları yürüten eyalet sürücü belgelendirme makamıdır. Kaynak: Illinois SOS CDL Study Guide (DSD CDL) ve ilsos.gov CDL sayfaları."},"80":{"q":"Bir Illinois adayı CDL bilgi sınavlarını ve beceri (sürüş) sınavını nerede verir?","options":["Bir Secretary of State Driver Services CDL tesisinde","Herhangi bir yerel Illinois State Police karakolunda","Yalnızca bir FMCSA federal sınav merkezinde","Bir Illinois Department of Transportation tartı istasyonunda"],"explanation":"CDL yazılı ve beceri sınavları, belirlenmiş Driver Services CDL tesislerinde Secretary of State tarafından yürütülür. Kaynak: Illinois SOS CDL Study Guide ve ilsos.gov CDL sınav/randevu sayfaları."},"81":{"q":"Bir Illinois CDL/CLP adayı, faaliyet gösterdiği ticaret türünü beyan ederken kaç öz-sertifikasyon kategorisi arasından seçim yapmalıdır?","options":["Dört","İki","Üç","Beş"],"explanation":"Illinois, sürücülerin dört kategoriden birinde öz-sertifikasyon yapmasını gerektiren federal CDL kuralını izler: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate ve Excepted Intrastate. Kaynak: Illinois SOS CDL Study Guide; 49 CFR 383.71."},"82":{"q":"Eyalet sınırları arasında faaliyet gösteren ve federal fiziksel yeterlilik kurallarından MUAF OLMAYAN bir Illinois sürücüsü hangi kategoride öz-sertifikasyon yapmalıdır?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Federal DOT tıbbi standartlarını karşılamak zorunda olan eyaletlerarası ticarette bir sürücü, Non-Excepted Interstate (NI) olarak öz-sertifikasyon yapar ve geçerli bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: Illinois SOS CDL Study Guide; 49 CFR 383.71."},"83":{"q":"Yalnızca Illinois içinde faaliyet gösteren ve tıbbi sertifikasyon gereksinimlerini karşılaması zorunlu olmayan bir Illinois sürücüsüne hangi öz-sertifikasyon kategorisi uygulanır?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"explanation":"Yalnızca eyalet içi (Illinois içi) ticarette faaliyet gösteren ve tıbbi sertifikasyon gereksinimlerini karşılamak zorunda olmayan bir sürücü, Excepted Intrastate (EA) olarak öz-sertifikasyon yapar. Kaynak: Illinois SOS CDL Study Guide; 49 CFR 383.71."},"84":{"q":"Bir Illinois Non-Excepted Interstate CDL sahibinin güncel tutması gereken Tıbbi Muayene Sertifikası hangi federal formdur?","options":["Form MCSA-5876","Form MCSA-5875","Form SS-CDL-2","Form DL-180"],"explanation":"Resmi Tıbbi Muayene Sertifikası, sertifikalı bir tıbbi muayene uzmanı tarafından düzenlenen FMCSA Form MCSA-5876'dır. Muaf olmayan sürücüler, eyalette dosyada geçerli bir sertifika bulundurmalıdır. Kaynak: FMCSA; Illinois SOS CDL sayfaları."},"85":{"q":"Illinois'teki 2025 değişikliğiyle birlikte, bir CDL sahibinin Tıbbi Muayene Sertifikası normalde Secretary of State'e nasıl ulaşır?","options":["Sertifikalı tıbbi muayene uzmanı bunu FMCSA National Registry aracılığıyla elektronik olarak gönderir","Sürücü Secretary of State'e kağıt bir kopya postalar","Sürücü 15 gün içinde bir CDL tesisine faks gönderir","Sürücü kağıt kartı herhangi bir CDL tesisinde elden teslim eder"],"explanation":"Illinois'in FMCSA National Registry entegrasyonuna katılmasıyla birlikte (2025 ortası) yürürlüğe giren düzenlemeyle, sertifikalı tıbbi muayene uzmanları muayene sonuçlarını elektronik olarak FMCSA'ya iletir ve FMCSA bunları SOS'a sağlar; eyalet artık CDL tesislerinde kağıt tıbbi kartları kabul etmemektedir. Kaynak: Illinois SOS CDL sayfaları; FMCSA National Registry."},"86":{"q":"Bir Illinois Non-Excepted Interstate CDL sahibi genel olarak ne sıklıkla öz-sertifikasyonu güncellemeli ve güncel bir tıbbi sertifika sağlamalıdır?","options":["En az her 2 yılda bir (sertifikanın son kullanma süresi daha kısaysa daha erken)","Lisans yenilemesiyle her 5 yılda bir","Lisans yenilemesiyle her 4 yılda bir","Yalnızca bir kez, ilk belgelendirmede"],"explanation":"Bir Tıbbi Muayene Sertifikası en fazla 2 yıl geçerlidir (muayene uzmanı belirtirse daha kısa), bu nedenle muaf olmayan eyaletlerarası sürücüler, 4 yıllık lisans döngüsünden bağımsız olarak en az 2 yıllık bir döngüde güncel tıbbi sertifikasyonu sürdürmelidir. Kaynak: Illinois SOS CDL sayfaları; 49 CFR 391.45."},"87":{"q":"Illinois'te CDL beceri sınavı için randevu alınmadan önce, ilk Sınıf A veya Sınıf B adayı hangi eğitim gereksinimini tamamlamalıdır?","options":["FMCSA kayıtlı bir sağlayıcıdan Entry-Level Driver Training (ELDT)","30 saatlik bir Illinois savunma sürüş kursu","Bir Illinois Secretary of State sınıf içi güvenlik semineri","6 aylık eyalet tarafından yürütülen bir çıraklık"],"explanation":"Illinois'te kabul edilen federal ELDT kuralları, ilk Sınıf A/Sınıf B adaylarının (ve belirli yükseltmeler/onayların), sınavdan önce FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan Entry-Level Driver Training tamamlamasını gerektirir. Kaynak: Illinois SOS ELDT sayfası; 49 CFR Part 380."},"88":{"q":"Illinois ELDT gereksinimi uyarınca, eğitimin teori bölümü hangi adımdan önce tamamlanmalıdır?","options":["Yeni sınıf veya onay için CDL bilgi (yazılı) sınavına girmeden önce","Temel bir Illinois sürücü belgesine başvurmadan önce","Mevcut bir CDL olmayan lisansı yenilemeden önce","Bir görme taraması randevusu almadan önce"],"explanation":"Illinois, ilk Sınıf A veya B CDL, bir yükseltme ya da ilk S, P veya H onayı isteyen adayların, ilgili bilgi sınavına girmeden önce kayıtlı bir sağlayıcıdan ELDT teori eğitimini tamamlamasını gerektirir. Kaynak: Illinois SOS ELDT sayfası; 49 CFR Part 380."},"89":{"q":"Bir Illinois adayının sınava girebilmesi için bu onaylardan hangisi ELDT tamamlanmasını gerektirir?","options":["Passenger (P), School bus (S) ve Hazardous materials (H)","Yalnızca Double/triple trailers (T)","Yalnızca Tank vehicle (N)","Illinois'te hiçbir onay ELDT gerektirmez"],"explanation":"ELDT, ilk Sınıf A/B lisansları ve yükseltmelere ek olarak, School bus (S), Passenger (P) ve Hazardous materials (H) onaylarının ilk verilişine uygulanır. Kaynak: Illinois SOS ELDT sayfası; 49 CFR Part 380."},"90":{"q":"Bir Illinois sürücüsü, CDL beceri sınavına girmeden önce direksiyon başında pratik yapmasına olanak tanıyan adım olarak ilk önce neyi edinmelidir?","options":["Bir Commercial Learner's Permit (CLP)","Geçici bir eyaletlerarası muafiyet","Geçici bir ticari onay kartı","Bir FMCSA yol sınavı muafiyeti"],"explanation":"Gerekli bilgi sınav(lar)ını geçtikten sonra adaya, beceri sınavından önce temsili bir araçta denetimli pratiğe izin veren bir Commercial Learner's Permit (CLP) verilir. Kaynak: Illinois SOS CDL Study Guide; 49 CFR 383.25."},"91":{"q":"Bir Illinois CLP verildikten sonra, sahibinin CDL beceri sınavına girmesine izin verilmeden önce ne kadar beklemesi gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","Bekleme süresi yoktur"],"explanation":"Illinois tarafından kabul edilen federal yasa, beceri sınavının yapılabilmesi için CLP'nin veriliş tarihinden itibaren en az 14 günlük bir bekleme süresi gerektirir; bir aday önceden randevu alabilir ancak 14 gün içindeki bir tarihi seçemez. Kaynak: Illinois SOS CDL sayfaları; 49 CFR 383.25."},"92":{"q":"Illinois CDL beceri sınavı üç bölüm halinde yapılır. Bunların uygulandığı doğru sıra nedir?","options":["Sefer öncesi (araç) muayenesi, ardından temel kontrol becerileri, ardından yolda sürüş sınavı","Yolda sürüş sınavı, ardından temel kontrol becerileri, ardından sefer öncesi muayene","Temel kontrol becerileri, ardından yolda sürüş sınavı, ardından sefer öncesi muayene","Sefer öncesi muayene, ardından yolda sürüş sınavı, ardından temel kontrol becerileri"],"explanation":"Beceri sınavı şu sırayla yürütülür: (1) Sefer Öncesi (Araç) Muayenesi, (2) Temel Kontrol Becerileri ve (3) Yolda Sürüş Sınavı. Kaynak: Illinois SOS CDL Study Guide ve ilsos.gov CDL sayfaları."},"93":{"q":"Illinois beceri sınavının sefer öncesi muayene bölümünde, aday öncelikle hangi yeteneği göstermelidir:","options":["Kontrol edilmesi gereken bileşenleri belirlemek ve her birinin güvenli kullanım için neden önemli olduğunu açıklamak","Fren sistemini sökmek ve yeniden monte etmek","Tüm Illinois Araç Yasası'nı ezbere okumak","Sabit bir süre içinde bir lastik değiştirmek"],"explanation":"Araç muayene sınavı, adayın öğeleri bulmasını, neyin kontrol edildiğini belirtmesini ve kontrolün güvenli kullanım açısından neden önemli olduğunu açıklamasını gerektirir. Kaynak: Illinois SOS CDL Study Guide (Bölüm 11, Araç Muayene Sınavı)."},"94":{"q":"Aşağıdakilerden hangisi Illinois CDL beceri sınavının Temel Kontrol Becerileri bölümünün bir parçasıdır?","options":["Düz çizgi ve ofset geri gitme gibi kontrollü geri manevralar","Tam hızda bir eyaletlerarası karayoluna katılma","50 yazılı çoktan seçmeli soruyu yanıtlama","Römorka bir tehlikeli madde plakartını bağlama"],"explanation":"Temel Kontrol Becerileri, düz çizgide geri gitme, ofset geri gitme ve park etme gibi manevralar aracılığıyla, genellikle bir alanda hassas düşük hızlı araç kontrolünü değerlendirir. Kaynak: Illinois SOS CDL Study Guide (Temel Araç Kontrol Becerileri Sınavı)."},"95":{"q":"Bir adayın her bir Illinois CDL bilgi (yazılı) sınavını geçmek için elde etmesi gereken asgari puan nedir?","options":["%80 doğru","%70 doğru","%75 doğru","%90 doğru"],"explanation":"Illinois CDL bilgi sınavları, federal standartla uyumlu olarak geçmek için en az %80 doğru gerektirir. Kaynak: Illinois SOS CDL Study Guide; 49 CFR 383.135."},"96":{"q":"Normal yaş aralığındaki bir sürücü için bir Illinois Ticari Sürücü Belgesinin standart yenileme döngüsü nedir?","options":["Her 4 yılda bir","Her 2 yılda bir","Her 5 yılda bir","Her 8 yılda bir"],"explanation":"Standart bir Illinois CDL, genellikle sahibinin doğum gününde sona ererek 4 yıllık bir döngüde düzenlenir; yenileme ayrıca güncel öz-sertifikasyon ve muaf olmayan sürücüler için geçerli tıbbi sertifikasyon gerektirir. Kaynak: Illinois SOS CDL sayfaları ve Driver Services yenileme bilgileri."},"97":{"q":"EYALETLERARASI ticarette araç kullanmak veya yolcu taşımak için bir Illinois CDL'sine başvurmanın asgari yaşı, yalnızca eyalet içinde araç kullanmaya kıyasla nedir?","options":["Eyaletlerarası veya yolcular için 21; yalnızca eyalet içi için 18","Eyaletlerarası veya yolcular için 18; yalnızca eyalet içi için 16","Eyaletlerarası veya yolcular için 25; yalnızca eyalet içi için 21","Hem eyaletlerarası hem de eyalet içi için 21"],"explanation":"Bir aday, eyaletlerarası ticarette faaliyet göstermek veya yolcu taşımak için en az 21 yaşında ve yalnızca eyalet içi faaliyet için bir CDL/CLP almak için en az 18 yaşında olmalıdır. Kaynak: Illinois SOS CDL Study Guide ve ilsos.gov CDL sayfaları."}},"es":{"0":{"q":"En las carreteras de Illinois, ¿cuál es el ancho máximo de un vehículo comercial, sin contar los dispositivos de seguridad aprobados ni los espejos?","options":["8 pies 6 pulgadas (102 inches)","8 pies 0 pulgadas (96 inches)","9 pies 0 pulgadas (108 inches)","10 pies 0 pulgadas (120 inches)"],"explanation":"Illinois limita el ancho del vehículo a 8 pies 6 pulgadas (102 inches), sin contar los espejos ni otros dispositivos de seguridad aprobados. Fuente: 625 ILCS 5/15-102; Illinois CDL/Rules of the Road."},"1":{"q":"¿Cuál es la altura máxima de un vehículo, incluida su carga, permitida en las carreteras de Illinois?","options":["13 pies 6 pulgadas","13 pies 0 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"Illinois limita la altura total, medida desde la superficie de la vía hasta la parte superior de la carga, a 13 pies 6 pulgadas. Fuente: 625 ILCS 5/15-103."},"2":{"q":"¿Cuál es el peso bruto máximo de una combinación de vehículos de cinco o más ejes que circula por las carreteras de Illinois sin permiso?","options":["80,000 libras","73,280 libras","84,000 libras","88,000 libras"],"explanation":"Illinois adopta el máximo federal de 80,000 libras de peso bruto para combinaciones de cinco o más ejes. Fuente: 625 ILCS 5/15-111."},"3":{"q":"¿Cuál es el peso máximo permitido sobre un solo eje en las carreteras de Illinois?","options":["20,000 libras","18,000 libras","22,400 libras","24,000 libras"],"explanation":"Illinois limita un solo eje a 20,000 libras, lo que coincide con el estándar federal. Fuente: 625 ILCS 5/15-111."},"4":{"q":"¿Cuál es el peso máximo permitido sobre un grupo de ejes en tándem en las carreteras de Illinois?","options":["34,000 libras","32,000 libras","36,000 libras","40,000 libras"],"explanation":"Illinois limita un eje en tándem a 34,000 libras, sin que ningún eje individual dentro del tándem supere las 20,000 libras. Fuente: 625 ILCS 5/15-111."},"5":{"q":"¿Cuál es la longitud máxima de un camión rígido (de chasis único) en las carreteras de Illinois?","options":["42 pies","40 pies","45 pies","53 pies"],"explanation":"Un vehículo único, como un camión rígido, no puede superar los 42 pies de longitud total en Illinois. Fuente: 625 ILCS 5/15-107."},"6":{"q":"En el sistema de carreteras designadas (National Network) de Illinois, ¿cuál es la longitud máxima de un solo semirremolque operado en una combinación de tractor con semirremolque?","options":["53 pies","48 pies","57 pies","60 pies"],"explanation":"Illinois permite semirremolques de hasta 53 pies en una combinación de tractor con semirremolque, conforme al estándar federal de la National Network. Fuente: 625 ILCS 5/15-107."},"7":{"q":"¿Qué fórmula utiliza Illinois para determinar el peso bruto máximo permitido en función de la separación entre ejes y la cantidad de ejes?","options":["La Federal Bridge Formula (fórmula de peso-distancia)","La fórmula de Gross Combination Rating","La fórmula del índice de carga del neumático (Tire-Load Index)","La fórmula de Registered Weight Class"],"explanation":"Illinois utiliza la Federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], para establecer el peso bruto máximo según la separación entre ejes (L) y la cantidad de ejes (N). Fuente: 625 ILCS 5/15-111."},"8":{"q":"En Illinois, ¿quién emite un permiso estatal de sobredimensión/sobrepeso para una carga que excede los límites legales de tamaño o peso en una carretera mantenida por el estado?","options":["El Illinois Department of Transportation (IDOT)","El Illinois Secretary of State","La Illinois State Police","La Federal Motor Carrier Safety Administration"],"explanation":"El IDOT emite permisos de sobredimensión/sobrepeso para los traslados en carreteras mantenidas por el estado, en virtud de su autoridad legal. Fuente: 625 ILCS 5/15-301; IDOT Oversize/Overweight Permits."},"9":{"q":"Por lo general, se requiere un permiso de sobredimensión/sobrepeso de Illinois cuando un vehículo o carga excede ¿cuál de las siguientes opciones?","options":["8 pies 6 pulgadas de ancho, 13 pies 6 pulgadas de alto, o 80,000 libras de peso bruto","8 pies 0 pulgadas de ancho, 13 pies 0 pulgadas de alto, o 73,280 libras de peso bruto","9 pies 0 pulgadas de ancho, 14 pies 0 pulgadas de alto, o 84,000 libras de peso bruto","10 pies 0 pulgadas de ancho, 15 pies 0 pulgadas de alto, o 90,000 libras de peso bruto"],"explanation":"Cuando una carga excede los límites legales (más de 8'6\" de ancho, más de 13'6\" de alto, más de la longitud legal, o más de 80,000 lb de peso bruto), se requiere un permiso del IDOT para trasladarla por las carreteras estatales. Fuente: 625 ILCS 5/15-301; IDOT."},"10":{"q":"¿Cuál es la carga máxima que Illinois permite por pulgada de ancho del neumático (para el neumático en contacto con la vía)?","options":["800 libras por pulgada de ancho del neumático","500 libras por pulgada de ancho del neumático","1,000 libras por pulgada de ancho del neumático","600 libras por pulgada de ancho del neumático"],"explanation":"Illinois limita la carga a 800 libras por pulgada de ancho del neumático para proteger el pavimento, además de los límites de peso por eje. Fuente: 625 ILCS 5/15-111."},"11":{"q":"¿Qué sistema en línea utiliza el IDOT para solicitar los permisos de sobredimensión/sobrepeso y de cosecha de Illinois?","options":["ITAP (Illinois Transportation Automated Permits system)","IRP (portal del International Registration Plan)","CDLIS (Commercial Driver License Information System)","SAFER (Safety and Fitness Electronic Records)"],"explanation":"Los solicitantes presentan la solicitud a través del sistema ITAP del IDOT, que ofrece acceso en línea las 24 horas a los permisos de sobredimensión/sobrepeso y de cosecha. Fuente: IDOT Oversize/Overweight Permits (webapps.dot.illinois.gov/ITAP)."},"12":{"q":"¿En qué porcentaje aproximado por encima de los límites legales permite el Illinois Harvest Permit gratuito que un vehículo exceda los pesos brutos, por eje y registrados durante la temporada de cosecha?","options":["Hasta un 10 por ciento","Hasta un 5 por ciento","Hasta un 15 por ciento","Hasta un 25 por ciento"],"explanation":"El Illinois Harvest Permit permite hasta un 10 por ciento por encima de los pesos legales brutos, por eje y registrados para el transporte de productos agrícolas durante la cosecha. Fuente: IDOT Harvest Permit; Illinois Farm Bureau."},"13":{"q":"¿En qué carreteras permite el Illinois Harvest Permit emitido por el IDOT el tránsito agrícola con sobrepeso?","options":["Solo en rutas mantenidas por el estado (no en interestatales ni en caminos locales, salvo autorización aparte)","En todas las autopistas interestatales dentro de Illinois","En cualquier camino público de Illinois, incluidos los caminos municipales (township)","Solo en caminos de condado y municipales (township), nunca en rutas estatales"],"explanation":"El Harvest Permit del IDOT cubre únicamente las rutas estatales; no autoriza el tránsito por interestatales, y los caminos locales requieren autorización local aparte. Fuente: IDOT Harvest Permit; Illinois Farm Bureau."},"14":{"q":"¿Cuánto le cuesta el Illinois Harvest Permit estándar a un agricultor o transportista agrícola que califica?","options":["Es gratuito","$15 por vehículo","$100 por temporada","$50 por autorización de ruta"],"explanation":"Illinois ofrece el Harvest Permit de forma gratuita a los transportistas agrícolas que califican, el cual se obtiene a través del sistema ITAP del IDOT. Fuente: IDOT Harvest Permit; Illinois Farm Bureau."},"15":{"q":"¿Qué tolerancia adicional de peso bruto otorga Illinois a un vehículo impulsado principalmente por gas natural (para compensar el sistema de combustible más pesado), y dónde NO se aplica?","options":["Hasta 2,000 libras adicionales, pero no en el sistema Interstate","Hasta 5,000 libras adicionales en todas las carreteras, incluidas las Interstates","Hasta 1,000 libras adicionales solo en caminos locales","Hasta 4,000 libras adicionales solo en las Interstates"],"explanation":"Illinois permite hasta 2,000 libras de peso bruto adicional para los vehículos impulsados por gas natural, excepto en las autopistas Interstate. Fuente: 625 ILCS 5/15-111."},"16":{"q":"Dentro de un grupo legal de ejes en tándem en Illinois, ¿qué peso no puede superar ningún eje individual del tándem?","options":["20,000 libras","17,000 libras","18,000 libras","22,000 libras"],"explanation":"Aunque un tándem puede transportar 34,000 libras en total, ningún eje individual dentro de ese tándem puede superar las 20,000 libras. Fuente: 625 ILCS 5/15-111."},"17":{"q":"En la Federal Bridge Formula W = 500[(LN/(N-1)) + 12N + 36] utilizada en Illinois, ¿qué representa la variable 'L'?","options":["La distancia en pies entre los ejes extremos (más exteriores) del grupo que se está midiendo","La longitud total del remolque en pies","El límite legal de carga por neumático","El peso bruto autorizado del vehículo"],"explanation":"En la fórmula del puente, L es la separación en pies entre los ejes extremos del grupo, N es la cantidad de ejes y W es el peso máximo permitido. Fuente: 625 ILCS 5/15-111."},"18":{"q":"Una autoridad local en Illinois puede señalizar y permitir legalmente pesos brutos superiores al límite legal en una carretera bajo su jurisdicción solo si hace ¿qué?","options":["Instala las señales reglamentarias apropiadas que dan aviso, sin exceder los máximos por eje individual o en tándem","Obtiene la aprobación por escrito de la Federal Highway Administration","Aumenta el máximo por eje individual a 24,000 libras","Renuncia por completo a la Federal Bridge Formula para esa carretera"],"explanation":"Las autoridades locales pueden permitir cargas mayores en carreteras locales designadas solo cuando se instalan las señales reglamentarias adecuadas, y aun así no pueden exceder los máximos por eje individual o en tándem. Fuente: 625 ILCS 5/15-111 y disposiciones relacionadas sobre la autoridad local."},"19":{"q":"Un conductor que transporta una carga de 9 pies de ancho y 14 pies de alto por una carretera estatal de Illinois no tiene permiso. ¿Cuál es la caracterización correcta de este traslado?","options":["Es ilegal; tanto el ancho (más de 8'6\") como la altura (más de 13'6\") exceden los límites legales y requieren un permiso de sobredimensión del IDOT","Es legal porque las cargas agrícolas están exentas de todos los límites de tamaño","Es legal porque solo el peso, y no las dimensiones, requiere permiso","Es legal porque la carga pesa menos de 80,000 libras de peso bruto"],"explanation":"Exceder los 8'6\" de ancho o los 13'6\" de alto hace que el traslado sea ilegal sin un permiso de sobredimensión del IDOT; los límites dimensionales se aplican de forma independiente del peso bruto. Fuente: 625 ILCS 5/15-102, 15-103 y 15-301."},"20":{"q":"En Illinois, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una calificación de peso bruto combinado (GCWR) de 26,001 lbs o más, donde el vehículo remolcado tiene un GVWR de más de 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"explanation":"Illinois define una CDL Class A como una combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que la unidad remolcada tenga un GVWR superior a 10,000 lbs. Fuente: Illinois SOS CDL Study Guide / página de clases de CDL de ilsos.gov; 92 Ill. Admin. Code 1030."},"21":{"q":"Según las normas de Illinois, una CDL Class B autoriza la operación de ¿cuál de las siguientes opciones?","options":["Cualquier vehículo único con un GVWR de 26,001 lbs o más (que remolque una unidad no mayor de 10,000 lbs)","Cualquier combinación que remolque una unidad de más de 10,000 lbs","Solo vehículos de menos de 16,000 lbs de GVWR","Solo vehículos diseñados para transportar 16 o más pasajeros"],"explanation":"Illinois define una CDL Class B como cualquier vehículo único con un GVWR de 26,001 lbs o más, o dicho vehículo remolcando otro que no exceda las 10,000 lbs (por ejemplo, camiones rígidos y autobuses grandes). Fuente: Illinois SOS CDL Study Guide / ilsos.gov."},"22":{"q":"Un conductor de Illinois quiere operar una camioneta pequeña diseñada para transportar 16 o más pasajeros (incluido el conductor) que pesa menos de 26,001 lbs. ¿Qué clase de CDL corresponde?","options":["Class C","Class A","Class B","No se necesita ninguna CDL"],"explanation":"La Class C de Illinois cubre cualquier vehículo que no cumpla con la Class A o B y que esté diseñado para transportar 16 o más pasajeros incluido el conductor, o que transporte materiales peligrosos que requieran rótulos (placards). Fuente: Illinois SOS CDL Study Guide / ilsos.gov."},"23":{"q":"¿Qué endoso de CDL se requiere en Illinois para conducir un vehículo que transporta materiales peligrosos en cantidades que requieren rótulos (placards)?","options":["H (HazMat)","N (Tanque)","T (Dobles/Triples)","P (Pasajeros)"],"explanation":"El endoso H se requiere para cualquier vehículo que transporte materiales peligrosos que requieran rótulos (placards). Illinois además exige una evaluación de amenazas de seguridad de la TSA y el ELDT antes del examen de conocimientos H. Fuente: página del endoso de Hazardous Materials de ilsos.gov."},"24":{"q":"En Illinois, ¿qué endoso se requiere para operar un vehículo cisterna que transporta líquidos o gases a granel?","options":["N (Tanque)","H (HazMat)","T (Dobles/Triples)","S (Autobús Escolar)"],"explanation":"El endoso N autoriza la operación de un vehículo cisterna que transporta líquidos o gases. Requiere aprobar el examen de conocimientos sobre vehículos cisterna. Fuente: Illinois SOS CDL Study Guide / endosos de ilsos.gov."},"25":{"q":"El endoso T de Illinois (Dobles/Triples) solo puede agregarse a ¿cuál clase de CDL?","options":["Class A","Class B","Class C","Cualquier clase"],"explanation":"En Illinois, el endoso T (Dobles/Triples) se aplica únicamente a una CDL Class A, ya que remolcar más de un remolque requiere una licencia de combinación. Nota: los remolques triples no son legales en las carreteras de Illinois. Fuente: materiales de CDL del Illinois SOS / endosos de ilsos.gov."},"26":{"q":"¿Cuál afirmación sobre los remolques triples en Illinois es correcta?","options":["Los remolques triples no están permitidos en las carreteras de Illinois","Los remolques triples se permiten solo en interestatales","Los remolques triples se permiten con un endoso P","Los remolques triples requieren solo una CDL Class B"],"explanation":"Aunque el endoso se llama Dobles/Triples (T), la ley de Illinois no permite combinaciones de remolques triples en sus carreteras. Fuente: información sobre endosos de CDL del Illinois SOS / ilsos.gov."},"27":{"q":"En Illinois, ¿qué endoso se requiere para conducir un vehículo diseñado para transportar 16 o más pasajeros, incluido el conductor?","options":["P (Pasajeros)","S (Autobús Escolar)","N (Tanque)","T (Dobles/Triples)"],"explanation":"El endoso P (Pasajeros) se requiere para operar un vehículo diseñado para transportar 16 o más personas incluido el conductor; requiere un examen de conocimientos y un examen de habilidades en un vehículo representativo. Fuente: Illinois SOS CDL Study Guide / ilsos.gov."},"28":{"q":"Para conducir un autobús escolar amarillo que transporta estudiantes (de grado 12 o inferior) en Illinois, el conductor necesita ¿qué endoso además de una CDL?","options":["S (Autobús Escolar)","Solo P","N (Tanque)","H (HazMat)"],"explanation":"El endoso S (Autobús Escolar) se requiere para transportar estudiantes hacia/desde la escuela o las actividades escolares; Illinois exige exámenes de conocimientos, de habilidades y de manejo (un endoso P también es un requisito previo). Fuente: endoso de School Bus de ilsos.gov."},"29":{"q":"¿Cuál es la edad mínima para obtener una CDL o CLP de Illinois para operar ÚNICAMENTE dentro de Illinois (intraestatal)?","options":["18","21","19","16"],"explanation":"Illinois exige que el solicitante tenga al menos 18 años para obtener una CDL/CLP para la operación intraestatal. Fuente: página de CDL/CLP de ilsos.gov; 625 ILCS 5/6-507."},"30":{"q":"¿Qué edad mínima exige Illinois para operar un vehículo motorizado comercial en el comercio interestatal o para transportar pasajeros?","options":["21","18","19","25"],"explanation":"Illinois exige que el conductor tenga al menos 21 años para operar en el comercio interestatal o para transportar pasajeros; los jóvenes de 18 a 20 años están limitados a la operación intraestatal. Fuente: página de CDL/CLP de ilsos.gov; 49 CFR 391.11 según lo adoptado por Illinois."},"31":{"q":"Según las normas federales adoptadas por Illinois, ¿durante cuánto tiempo debe un conductor tener un Commercial Learner's Permit (CLP) antes de presentar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 14 days","Al menos 30 days","Al menos 7 days","Al menos 60 days"],"explanation":"Tanto las normas federales como las de Illinois exigen que el CLP se tenga durante un mínimo de 14 days antes del examen de habilidades; puede programarlo con anticipación, pero la fecha del examen debe caer después del período de espera de 14 days. Fuente: página de CDL/CLP de ilsos.gov; 49 CFR 383.25."},"32":{"q":"¿Por cuánto tiempo es válido un Commercial Learner's Permit (CLP) de Illinois?","options":["180 days","90 days","1 año","30 days"],"explanation":"Un CLP de Illinois es válido por 180 days, conforme al estándar federal del CLP. Fuente: página de CDL/CLP de ilsos.gov; 49 CFR 383.25."},"33":{"q":"¿Para cuál de las siguientes situaciones exige Illinois el Entry-Level Driver Training (ELDT) antes del examen de conocimientos o de habilidades?","options":["Un endoso inicial H (HazMat), P (Pasajeros) o S (Autobús Escolar)","Solo el endoso N (Tanque)","Renovar cualquier endoso existente","Agregar un endoso de motocicleta"],"explanation":"El ELDT se aplica a la obtención de una primera CDL Class A o B, una mejora de clase, y un endoso INICIAL H, P o S. La capacitación teórica de HazMat (H) debe preceder al examen de conocimientos H. Fuente: página de ELDT de ilsos.gov; 49 CFR Part 380."},"34":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CLP/CDL de Illinois en una oficina del Secretary of State?","options":["Prueba de identidad, prueba escrita del número de Seguro Social, prueba de presencia legal/lícita, y dos pruebas de residencia en Illinois","Solo una tarjeta de Seguro Social","Solo un pasaporte de EE. UU.","Solo dos facturas de servicios públicos"],"explanation":"Illinois exige prueba de identidad, prueba escrita del SSN (por ejemplo, la tarjeta original o el W-2; no se aceptan fotocopias), prueba de presencia lícita, y dos pruebas de residencia en Illinois. Fuente: páginas de CDL/CLP y de presencia legal de ilsos.gov."},"35":{"q":"¿Cuántas pruebas de residencia en Illinois exige el Secretary of State para una solicitud de CDL/CLP?","options":["Dos","Una","Tres","Ninguna"],"explanation":"Illinois exige dos pruebas aceptables de residencia en Illinois, además de la prueba de identidad, el SSN y la presencia lícita. Fuente: requisitos de documentos para licencia de conducir/CDL de ilsos.gov."},"36":{"q":"Al solicitar una CDL de Illinois, ¿qué categoría de autocertificación exige que el conductor presente un DOT Medical Examiner's Certificate federal válido?","options":["Non-excepted interstate (NI)","Excepted intrastate (EA)","Excepted interstate (EI)","Non-excepted intrastate (NA)"],"explanation":"Illinois reconoce cuatro categorías de autocertificación (NI, EI, NA, EA). Un conductor non-excepted interstate (NI) debe cumplir con los estándares médicos federales del DOT y presentar un Medical Examiner's Certificate (Form MCSA-5876). Fuente: página de CDL de ilsos.gov; 92 Ill. Admin. Code 1030.22."},"37":{"q":"¿Qué lista nombra correctamente las cuatro categorías de autocertificación médica entre las que deben elegir los solicitantes de CDL/CLP de Illinois?","options":["Non-excepted interstate, Excepted interstate, Non-excepted intrastate, Excepted intrastate","Interestatal, Intraestatal, Agrícola, Militar","Class A, Class B, Class C, Class D","Local, Regional, Nacional, Internacional"],"explanation":"Illinois usa las cuatro categorías federales de autocertificación: Non-excepted interstate (NI), Excepted interstate (EI), Non-excepted intrastate (NA) y Excepted intrastate (EA). Fuente: página de CDL de ilsos.gov; 92 Ill. Admin. Code 1030.22."},"38":{"q":"Para un titular de CDL de Illinois con un endoso de HazMat (H), ¿con qué frecuencia debe renovarse la evaluación de amenazas de seguridad de la TSA para mantener el endoso?","options":["Cada 5 años","Cada 2 años","Cada 10 años","Solo una vez, sin renovación"],"explanation":"Una evaluación de amenazas de seguridad de la TSA para el endoso de HazMat es válida por 5 años; Illinois exige la evaluación y el examen de conocimientos de HazMat en cada renovación, y los conductores deben iniciar la renovación unos 60 days antes del vencimiento. Fuente: endoso de Hazardous Materials de ilsos.gov; 49 CFR 1572."},"39":{"q":"Según la ley de Illinois, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) que puede tener un titular de CDL mientras opera un vehículo motorizado comercial (CMV)?","options":["0.04 por ciento","0.08 por ciento","0.02 por ciento","0.00 por ciento"],"explanation":"El Illinois SOS CDL Study Guide (Sec. 1.5.1) establece que un titular de CDL no puede operar un CMV con un BAC de .04 por ciento o más, lo cual es la mitad del límite de .08 para otros vehículos. Fuente: Illinois CDL Study Guide; 625 ILCS 5/11-501."},"40":{"q":"Cuando un conductor opera un vehículo en las carreteras de Illinois, la ley de consentimiento implícito del estado significa que el conductor ha aceptado de antemano hacer ¿qué?","options":["Someterse a pruebas químicas para determinar la concentración de alcohol en la sangre","Permitir una inspección de la carga del vehículo en cualquier momento","Pagar una multa antes de impugnar cualquier citación de tránsito","Entregar la CDL ante cualquier infracción en movimiento"],"explanation":"El Illinois SOS CDL Study Guide (Sec. 1.5.1) establece que los conductores que operan un CMV o un vehículo no CMV en las carreteras han consentido implícitamente someterse a pruebas químicas para determinar el BAC. Fuente: Illinois CDL Study Guide; 625 ILCS 5/11-501.1."},"41":{"q":"En Illinois, un conductor que se niega a someterse a pruebas químicas o que da positivo por encima del límite legal enfrenta una descalificación de al menos cuánto tiempo por una primera infracción (sin HazMat)?","options":["12 months","60 days","6 months","3 años"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): todo conductor que se niegue a las pruebas químicas o que dé positivo por encima del límite legal es descalificado por un mínimo de 12 months. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"42":{"q":"Si un conductor comete una primera infracción mayor relacionada con el alcohol MIENTRAS transporta materiales peligrosos con rótulos (placards), ¿cuál es el período mínimo de descalificación en Illinois?","options":["3 años","1 año","5 años","De por vida"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): si la infracción ocurre mientras se transportan materiales peligrosos con rótulos (placards), el conductor es descalificado por un mínimo de tres años. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"43":{"q":"Un conductor comete dos infracciones mayores distintas (como dos DUI) derivadas de dos o más incidentes. ¿Qué descalificación resulta en Illinois?","options":["Descalificación de por vida","Descalificación de tres años","Descalificación de cinco años","Descalificación de 120 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): todo conductor que cometa dos de las infracciones mayores enumeradas, derivadas de dos o más incidentes, es descalificado de por vida. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"44":{"q":"En Illinois, todo titular de CDL que opere un CMV y a quien se le detecte CUALQUIER cantidad de alcohol en su sistema (por debajo de 0.04) es puesto fuera de servicio por un mínimo de cuánto tiempo?","options":["24 horas","1 hora","12 horas","72 horas"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): todo titular de CDL que opere un CMV y a quien se le detecte cualquier cantidad de alcohol en su sistema es puesto fuera de servicio por un mínimo de 24 horas. Fuente: Illinois CDL Study Guide; 49 CFR 392.5."},"45":{"q":"¿Cuál es el BAC máximo permitido para un conductor de autobús escolar que opera un autobús escolar en Illinois?","options":["0.00 por ciento","0.04 por ciento","0.02 por ciento","0.08 por ciento"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): un conductor de autobús escolar no puede operar un autobús escolar con un BAC de más de .00 por ciento. Fuente: Illinois CDL Study Guide."},"46":{"q":"Abandonar consciente y deliberadamente el lugar de un accidente mientras se opera un CMV resulta en una descalificación en Illinois de al menos cuánto tiempo?","options":["12 months","60 days","120 days","3 años"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): abandonar consciente y deliberadamente el lugar de un accidente mientras se opera un CMV o un vehículo no CMV resulta en una descalificación por un mínimo de 12 months. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"47":{"q":"Usar un vehículo motorizado comercial o no comercial para cometer un delito grave (felony) que implique la fabricación o distribución de una sustancia controlada resulta en ¿qué sanción en Illinois?","options":["Descalificación de por vida","Descalificación de un año","Descalificación de tres años","Descalificación de 120 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): el uso de un CMV o un vehículo no CMV en un delito grave (felony) que implique la fabricación, distribución o dispensación de una sustancia controlada resulta en una descalificación de por vida. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"48":{"q":"Para una PRIMERA condena por violar las regulaciones de cruces a nivel entre ferrocarril y carretera en un CMV, ¿cuál es el período de descalificación en Illinois?","options":["60 days","30 days","120 days","1 año"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): la primera condena por violación de cruce a nivel entre ferrocarril y carretera es una descalificación de 60 days. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"49":{"q":"Una SEGUNDA violación de cruce a nivel entre ferrocarril y carretera dentro de un período de tres años resulta en ¿qué descalificación en Illinois?","options":["120 days","60 days","1 año","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): la segunda condena por cruce a nivel entre ferrocarril y carretera dentro de tres años es una descalificación de 120 days. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"50":{"q":"Una TERCERA violación o posterior de cruce a nivel entre ferrocarril y carretera dentro de un período de tres años resulta en ¿qué descalificación en Illinois?","options":["1 año","120 days","60 days","De por vida"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): la tercera condena y posteriores por cruce a nivel entre ferrocarril y carretera dentro de tres años es una descalificación de un año. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"51":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de tres años activan una descalificación de 60 days en Illinois?","options":["Dos","Tres","Una","Cuatro"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): dos infracciones de tránsito graves dentro de un período de tres años resultan en una descalificación de 60 days. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"52":{"q":"Tres infracciones de tránsito graves dentro de un período de tres años resultan en ¿qué período de descalificación en Illinois?","options":["120 days","60 days","1 año","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): tres infracciones de tránsito graves en un período de tres años resultan en una descalificación de 120 days. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"53":{"q":"¿A qué velocidad por encima del límite señalizado una sola infracción por exceso de velocidad cuenta como una 'infracción de tránsito grave' para un titular de CDL de Illinois?","options":["15 mph o más por encima del límite","10 mph o más por encima del límite","20 mph o más por encima del límite","25 mph o más por encima del límite"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): el exceso de velocidad grave es cualquier infracción única de 15 mph o más por encima del límite de velocidad señalizado. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"54":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para un titular de CDL de Illinois?","options":["Cambios de carril indebidos o erráticos","Una calcomanía de registro del vehículo vencida","Una infracción de estacionamiento en el centro","Un eje con sobrepeso en una carga con permiso"],"explanation":"El Illinois SOS CDL Study Guide (Sec. 1.5.3) enumera como infracciones de tránsito graves los cambios de carril indebidos/erráticos, seguir demasiado cerca, la conducción imprudente, el exceso de velocidad grave y enviar mensajes de texto en un CMV. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"55":{"q":"Según el Illinois CDL Study Guide, ¿cuál es la descalificación por una PRIMERA violación de una orden de fuera de servicio (out-of-service order)?","options":["Al menos 90 days","Al menos 30 days","Al menos 60 days","Al menos 1 año"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): usted pierde su CDL por al menos 90 days por una primera violación de una orden de fuera de servicio. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"56":{"q":"Un conductor comete TRES o más violaciones de órdenes de fuera de servicio dentro de un período de 10 años. ¿Cuál es la descalificación mínima en Illinois?","options":["3 años","1 año","90 days","De por vida"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): al menos tres años por tres o más violaciones de órdenes de fuera de servicio dentro de un período de 10 años (la segunda violación en 10 años es de al menos un año). Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-514."},"57":{"q":"¿Cómo clasifica Illinois a un conductor de CMV que envía mensajes de texto o usa un celular de mano mientras conduce un CMV?","options":["Como una infracción de tránsito grave","Como una infracción mayor que causa descalificación de por vida","Como una infracción tipo estacionamiento sin efecto sobre la CDL","Como una violación de una orden de fuera de servicio"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): enviar mensajes de texto o usar un celular de mano mientras se conduce un CMV es una infracción de tránsito grave; la multa de la FMCSA para el conductor puede llegar a $2,750. Fuente: Illinois CDL Study Guide; 625 ILCS 5/12-610.2; 49 CFR 392.80/392.82."},"58":{"q":"Un tribunal en Illinois puede imponer ¿qué multa máxima por conducir un vehículo motorizado comercial sin una CDL válida, o por tener más de una licencia?","options":["Hasta $5,000 o tiempo en la cárcel","Hasta $1,000 únicamente","Hasta $500 únicamente","Hasta $10,000 o tiempo en la cárcel"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.6): un tribunal puede imponer una multa de hasta $5,000 o tiempo en la cárcel por conducir un CMV sin una CDL o por tener más de una licencia. Fuente: Illinois CDL Study Guide; 625 ILCS 5/6-507."},"59":{"q":"La ley de 'Cambio de Carril' (Ley de Scott) de Illinois exige que un conductor que se aproxima a un vehículo de emergencia o de mantenimiento detenido que tiene encendidas sus luces intermitentes de advertencia haga ¿qué cosa?","options":["Cambiarse a un carril no adyacente si es posible, o de lo contrario reducir la velocidad y avanzar con precaución","Detenerse por completo y esperar hasta que el vehículo de emergencia se retire","Mantener la velocidad pero tocar la bocina al pasar","Orillarse hacia la berma detrás del vehículo de emergencia y detenerse"],"explanation":"Conforme a la Ley de Scott, 625 ILCS 5/11-907(c), un conductor que se aproxima a un vehículo de emergencia, mantenimiento o grúa detenido con luces intermitentes debe cambiarse a un carril no adyacente a él cuando sea seguro, y si no es posible cambiar de carril, debe reducir la velocidad y avanzar con precaución. Fuente: 625 ILCS 5/11-907; página de la Ley de Cambio de Carril de la Policía Estatal de Illinois."},"60":{"q":"La ley que lleva el nombre del Tte. Scott Gillen, que exige que los conductores de Illinois cedan el paso a los vehículos de emergencia detenidos, se conoce comúnmente como ¿qué?","options":["La Ley de Steve","La Ley de Scott","La Ley Dan Ryan","La Ley de la Luz Amarilla"],"explanation":"La ley de Cambio de Carril de Illinois se apoda oficialmente 'Ley de Scott', en honor al Tte. Scott Gillen del Departamento de Bomberos de Chicago, quien fue atropellado y murió en la autopista Dan Ryan en 2000. Fuente: 625 ILCS 5/11-907; Policía Estatal de Illinois."},"61":{"q":"Un autobús escolar y un vehículo de materiales peligrosos con placards que deben detenerse en un cruce ferroviario de Illinois están obligados a detenerse dentro de qué distancia del riel más cercano?","options":["Entre 5 y 25 pies","Entre 10 y 35 pies","Entre 15 y 50 pies","Entre 25 y 75 pies"],"explanation":"El manual de CDL de Illinois indica que un conductor de autobús debe 'Detener su autobús entre 15 y 50 pies antes de los cruces ferroviarios', y que un vehículo con placards 'debe detenerse de 15 a 50 pies antes del riel más cercano'. Fuente: Guía de Estudio del CDL del Illinois SOS, Secciones 4.3.5 y 9.6.12."},"62":{"q":"Según la ley de Illinois, ¿cuál es la altura máxima legal de un vehículo, incluida su carga, en cualquier carretera del estado sin un permiso?","options":["12 pies 6 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas","13 pies 0 pulgadas"],"explanation":"Illinois limita la altura del vehículo, medida desde la parte inferior del neumático hasta la parte superior del vehículo incluida la carga, a 13 pies 6 pulgadas en cualquier carretera. Fuente: 625 ILCS 5/15-103."},"63":{"q":"Cuando un vehículo comercial debe detenerse en una carretera de un solo sentido o dividida de Illinois, o junto a ella, el conductor debe colocar los tres dispositivos de advertencia aproximadamente a qué distancias en dirección al tráfico que se aproxima?","options":["10, 100 y 200 pies","10, 50 y 100 pies","25, 100 y 250 pies","5, 75 y 150 pies"],"explanation":"En una carretera de un solo sentido o dividida, el manual de CDL de Illinois exige que los dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies en dirección al tráfico que se aproxima. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 2.5 (Dispositivos de Advertencia)."},"64":{"q":"En los condados de Cook, DuPage, Kane, Lake, McHenry y Will, un camión de segunda división registrado para más de 8,000 libras está limitado a qué velocidad en caminos, carreteras y calles que NO son interestatales de peaje?","options":["65 mph","60 mph","55 mph","45 mph"],"explanation":"En esos seis condados, los camiones de más de 8,000 libras están limitados a 60 mph en las carreteras interestatales de peaje de Illinois y a 55 mph en todos los demás caminos, carreteras o calles. Fuente: 625 ILCS 5/11-601(e)."},"65":{"q":"Fuera de un distrito urbano, en una interestatal rural de Illinois con límite señalizado de 70 mph (y fuera de los seis condados periféricos del área de Chicago), un camión grande conforme a la ley actual de Illinois puede circular a qué velocidad máxima?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Desde el cambio de 2014 a la 625 ILCS 5/11-601, los camiones en interestatales rurales fuera de los seis condados periféricos pueden circular al mismo límite señalizado que los automóviles, hasta 70 mph; solo en los condados de Cook, DuPage, Kane, Lake, McHenry y Will están sujetos a límites más bajos específicos para camiones. Fuente: 625 ILCS 5/11-601(d-1), (e)."},"66":{"q":"Al cruzar vías ferroviarias en Illinois, un conductor con CDL debe hacer ¿cuál de las siguientes acciones?","options":["Cambiar a una marcha más baja a mitad del cruce para tener potencia extra","No cambiar de marcha mientras cruza las vías","Poner en neutral y cruzar en punto muerto","Subir de marcha para despejar las vías lo más rápido posible"],"explanation":"El manual de CDL de Illinois lo dice claramente: 'No cambie de marcha mientras cruza las vías ferroviarias', porque un cambio fallido o que rechina podría hacer que el vehículo se cale sobre las vías. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsecciones 2.15 y 9.6.12."},"67":{"q":"En una carretera de Illinois con cuatro o más carriles que permite al menos dos carriles de tráfico en sentidos opuestos, un conductor que se cruza con un autobús escolar detenido en la calzada CONTRARIA debe hacer ¿qué?","options":["Detenerse y permanecer detenido hasta que las luces rojas del autobús dejen de parpadear","Detenerse solo si hay niños visibles","No necesita detenerse, pero debe permanecer alerta","Reducir a 20 mph y continuar pasando el autobús"],"explanation":"La ley de Illinois establece que un conductor en una carretera con 4 o más carriles que permite al menos 2 carriles de tráfico en sentidos opuestos no necesita detenerse al CRUZARSE con un autobús escolar detenido en la calzada contraria. Fuente: 625 ILCS 5/11-1414(e)."},"68":{"q":"Salvo por la excepción de la carretera dividida, cuando un autobús escolar está detenido en una calzada de Illinois con sus luces de señal visual parpadeando para recoger o dejar alumnos, ¿qué deben hacer los conductores que se aproximan?","options":["Detenerse antes de cruzarse con el autobús o rebasarlo, desde cualquier dirección","Detenerse solo si se aproximan por detrás del autobús","Pasar lentamente por la izquierda a no más de 10 mph","Detenerse solo cuando un guardia de cruce les indique que lo hagan"],"explanation":"Illinois exige que los conductores detengan el vehículo antes de cruzarse o rebasar, desde cualquier dirección, cualquier autobús escolar que se haya detenido y esté mostrando sus luces de señal visual para recoger o dejar alumnos. Fuente: 625 ILCS 5/11-1414(a)."},"69":{"q":"Además de los vehículos con placards, ¿cuál de los siguientes debe detenerse siempre antes de cruzar vías ferroviarias en Illinois?","options":["Cualquier camión rígido que pese más de 10,000 libras","Cualquier vehículo que transporte cualquier cantidad de cloro","Cualquier vehículo que remolque un tráiler de plataforma","Cualquier vehículo registrado fuera del estado"],"explanation":"El manual de CDL de Illinois enumera tres categorías que deben detenerse antes de un cruce ferroviario: los vehículos con placards, los vehículos que transportan cualquier cantidad de cloro y los tanques de carga (cargados o vacíos) usados para materiales peligrosos. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 9.6.12."},"70":{"q":"¿Cuál es el ancho máximo legal (excluyendo espejos y ciertos dispositivos de seguridad) de un vehículo o su carga en las carreteras de Illinois sin un permiso?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"Illinois limita el ancho exterior total de un vehículo o carga a 8 pies 6 pulgadas; cualquier cosa más ancha requiere un permiso de sobredimensión del IDOT. Fuente: 625 ILCS 5/15-102."},"71":{"q":"Cuando un conductor con CDL debe detenerse en la berma o calzada de cualquier carretera de Illinois, ¿dentro de cuántos minutos deben colocarse los dispositivos de advertencia de emergencia?","options":["5 minutos","10 minutos","15 minutos","30 minutos"],"explanation":"El manual de CDL de Illinois exige que los dispositivos de advertencia se coloquen dentro de los 10 minutos de haberse detenido en un camino o berma. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 2.5."},"72":{"q":"¿Cuántos triángulos de advertencia reflectantes rojos debe llevar un vehículo comercial para cumplir con el requisito de dispositivos de advertencia en Illinois?","options":["Dos","Tres","Cuatro","Seis"],"explanation":"El manual de CDL de Illinois exige tres triángulos de advertencia reflectantes (o, alternativamente, seis bengalas o tres antorchas de combustible líquido) como parte del equipo de emergencia requerido. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 2.1."},"73":{"q":"Un conductor que transporta materiales peligrosos con placards y que es condenado por una infracción en un cruce a nivel de ferrocarril y carretera en Illinois enfrenta ¿qué consecuencia?","options":["Solo una advertencia por escrito","Una orden de fuera de servicio de 24 horas","Descalificación del CDL","Puntos pero sin descalificación"],"explanation":"Las infracciones en cruces a nivel de ferrocarril y carretera son delitos que descalifican a los titulares de CDL en Illinois, con periodos de descalificación crecientes (60 días, 120 días y luego un año) por infracciones reincidentes dentro de tres años. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 1.2 (Descalificaciones); 49 CFR 383.51 según lo adoptado por Illinois."},"74":{"q":"Una infracción por primera vez de la Ley de Scott (la ley de Cambio de Carril de Illinois) conlleva una multa de al menos ¿cuánto?","options":["$100","$250","$500","$1,000"],"explanation":"Tras la Ley Pública 101-0173, una infracción de la Ley de Scott es un delito comercial con una multa no menor de $250 y hasta $10,000 por una primera infracción. Fuente: 625 ILCS 5/11-907(c)."},"75":{"q":"En Lake Shore Drive de Chicago, que está legalmente clasificada como bulevar/parkway, ¿qué está generalmente prohibido?","options":["Los vehículos con placas de camión (comerciales) diseñados para transportar carga","Todos los vehículos durante las horas pico de los días laborables","Solo los automóviles de pasajeros que remolcan tráileres","Los vehículos sin un transpondedor I-PASS de Illinois"],"explanation":"Lake Shore Drive está designada como bulevar, y los vehículos que portan placas de camión diseñados para transportar carga o mercancías comerciales tienen prohibido el acceso, una restricción de circulación distintiva de Chicago arraigada en sus orígenes como 'vía de paseo'. Fuente: restricciones de bulevares del Código Municipal de Chicago; guía del CDOT sobre el permiso de tránsito de camiones en Lake Shore Drive."},"76":{"q":"En un cruce ferroviario donde de otro modo se requiere detenerse, un conductor de autobús de Illinois NO tiene que detenerse por completo, pero debe reducir la velocidad y revisar con cuidado, ¿en cuál situación?","options":["Cuando el cruce está en un camino de grava","Cuando un oficial de policía o un señalero está dirigiendo el tráfico","Cuando el autobús está vacío de pasajeros","Cuando el autobús mide más de 40 pies de largo"],"explanation":"El manual de CDL de Illinois indica que un autobús no necesita detenerse, pero debe reducir la velocidad y revisar con cuidado, en los cruces de tranvías, donde un policía o señalero está dirigiendo el tráfico, o cuando un semáforo muestra luz verde. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 4.3.5."},"77":{"q":"Como el terreno de Illinois es mayormente plano, las rampas de escape para camiones desbocados de tipo gravitatorio tradicionales son poco comunes. ¿Qué significa esto para un conductor con CDL que desciende por una pendiente larga o por la aproximación a un puente en Illinois?","options":["Puede confiar en encontrar una rampa de escape al final de cualquier pendiente","No debe depender de una rampa de escape y debe controlar la velocidad con un frenado y un uso de marchas adecuados","La ley de Illinois prohíbe usar frenos de motor en todas las pendientes","Las rampas de escape son obligatorias en cada bajada interestatal de Illinois"],"explanation":"A diferencia de los estados montañosos, el terreno plano de Illinois hace que las rampas de escape sean raras, por lo que los conductores deben manejar las bajadas con marchas bajas y técnica de frenado adecuadas, en lugar de esperar una rampa para desbocados. Fuente: Guía de Estudio del CDL del Illinois SOS, Subsección 2.16 (Conducción en Montaña / control de velocidad en bajadas)."},"78":{"q":"Un conductor de Illinois que se aproxima a un autobús escolar detenido en una carretera de DOS CARRILES sin dividir, circulando en cualquier dirección, debe hacer ¿qué?","options":["Continuar a velocidad reducida pasando el autobús","Detenerse antes de llegar al autobús y permanecer detenido hasta que se apaguen las señales","Detenerse solo si se aproxima en la misma dirección que el autobús","Pasar por la izquierda después de tocar la bocina"],"explanation":"En una carretera de dos carriles sin dividir, la excepción de la carretera dividida no aplica, por lo que los conductores que se aproximan desde cualquier dirección deben detenerse antes de cruzarse o rebasar un autobús escolar que muestra sus señales rojas y permanecer detenidos hasta que las señales se apaguen y el autobús reanude la marcha. Fuente: 625 ILCS 5/11-1414(a) y (b)."},"79":{"q":"En Illinois, ¿qué agencia estatal emite las Licencias de Conducir Comerciales y administra los exámenes de conocimientos y habilidades del CDL?","options":["El Secretario de Estado de Illinois","El Departamento de Transporte de Illinois (IDOT)","La Policía Estatal de Illinois","El Departamento de Vehículos Motorizados de Illinois"],"explanation":"Illinois no tiene un 'DMV'; la Oficina del Secretario de Estado de Illinois (SOS) es la autoridad estatal de licencias de conducir que emite los CDL y administra los exámenes en sus centros de CDL de Driver Services. Fuente: Guía de Estudio del CDL del Illinois SOS (DSD CDL) y páginas de CDL de ilsos.gov."},"80":{"q":"¿Dónde toma un solicitante de Illinois los exámenes de conocimientos del CDL y el examen de habilidades (de manejo)?","options":["En un centro de CDL de Driver Services del Secretario de Estado","En cualquier puesto local de la Policía Estatal de Illinois","Solo en un centro federal de exámenes de la FMCSA","En una estación de pesaje del Departamento de Transporte de Illinois"],"explanation":"Los exámenes escritos y de habilidades del CDL los realiza el Secretario de Estado en los centros de CDL de Driver Services designados. Fuente: Guía de Estudio del CDL del Illinois SOS y páginas de exámenes/programación de CDL de ilsos.gov."},"81":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL/CLP de Illinois al declarar el tipo de comercio en el que opera?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Illinois sigue la regla federal del CDL que exige que los conductores se autocertifiquen en una de cuatro categorías: Interestatal No Exceptuado, Interestatal Exceptuado, Intraestatal No Exceptuado e Intraestatal Exceptuado. Fuente: Guía de Estudio del CDL del Illinois SOS; 49 CFR 383.71."},"82":{"q":"Un conductor de Illinois que opera cruzando líneas estatales y que NO está exento de las reglas federales de calificación física debe autocertificarse en ¿cuál categoría?","options":["Interestatal No Exceptuado (NI)","Interestatal Exceptuado (EI)","Intraestatal No Exceptuado (NA)","Intraestatal Exceptuado (EA)"],"explanation":"Un conductor en comercio interestatal que debe cumplir con los estándares médicos federales del DOT se autocertifica como Interestatal No Exceptuado (NI) y debe mantener un certificado válido de examinador médico. Fuente: Guía de Estudio del CDL del Illinois SOS; 49 CFR 383.71."},"83":{"q":"¿Qué categoría de autocertificación aplica a un conductor de Illinois que opera ÚNICAMENTE dentro de Illinois y no está obligado a cumplir con los requisitos de certificación médica?","options":["Intraestatal Exceptuado (EA)","Interestatal No Exceptuado (NI)","Interestatal Exceptuado (EI)","Intraestatal No Exceptuado (NA)"],"explanation":"Un conductor que opera exclusivamente en comercio intraestatal (dentro de Illinois) y que no tiene que cumplir con los requisitos de certificación médica se autocertifica como Intraestatal Exceptuado (EA). Fuente: Guía de Estudio del CDL del Illinois SOS; 49 CFR 383.71."},"84":{"q":"¿Cuál formulario federal es el Certificado de Examinador Médico que un titular de CDL Interestatal No Exceptuado de Illinois debe mantener vigente?","options":["Formulario MCSA-5876","Formulario MCSA-5875","Formulario SS-CDL-2","Formulario DL-180"],"explanation":"El Certificado oficial de Examinador Médico es el Formulario MCSA-5876 de la FMCSA, emitido por un examinador médico certificado. Los conductores no exceptuados deben mantener un certificado válido en archivo con el estado. Fuente: FMCSA; páginas de CDL del Illinois SOS."},"85":{"q":"A partir del cambio de 2025 en Illinois, ¿cómo llega normalmente el Certificado de Examinador Médico de un titular de CDL al Secretario de Estado?","options":["El examinador médico certificado lo presenta electrónicamente a través del Registro Nacional de la FMCSA","El conductor envía por correo una copia en papel al Secretario de Estado","El conductor lo envía por fax a un centro de CDL dentro de 15 días","El conductor entrega en mano la tarjeta de papel en cualquier centro de CDL"],"explanation":"A partir de la integración de Illinois con el Registro Nacional de la FMCSA (mediados de 2025), los examinadores médicos certificados transmiten electrónicamente los resultados del examen a la FMCSA, que los proporciona al SOS; el estado ya no acepta tarjetas médicas de papel en los centros de CDL. Fuente: páginas de CDL del Illinois SOS; Registro Nacional de la FMCSA."},"86":{"q":"¿Con qué frecuencia debe un titular de CDL Interestatal No Exceptuado de Illinois actualizar generalmente su autocertificación y proporcionar un certificado médico vigente?","options":["Al menos cada 2 años (o antes si el vencimiento del certificado es más corto)","Cada 5 años con la renovación de la licencia","Cada 4 años con la renovación de la licencia","Solo una vez, en la licencia inicial"],"explanation":"Un Certificado de Examinador Médico es válido por un máximo de 2 años (menos si el examinador lo especifica), por lo que los conductores interestatales no exceptuados deben mantener vigente la certificación médica en un ciclo de al menos 2 años, independientemente del ciclo de licencia de 4 años. Fuente: páginas de CDL del Illinois SOS; 49 CFR 391.45."},"87":{"q":"Antes de que se le programe el examen de habilidades del CDL en Illinois, un solicitante de una Clase A o Clase B inicial debe completar ¿cuál requisito de capacitación?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor registrado ante la FMCSA","Un curso de manejo defensivo de 30 horas de Illinois","Un seminario presencial de seguridad del Secretario de Estado de Illinois","Un aprendizaje administrado por el estado de 6 meses"],"explanation":"Las reglas federales de ELDT, adoptadas en Illinois, exigen que los solicitantes iniciales de Clase A/Clase B (y ciertas mejoras/endosos) completen la Capacitación para Conductores Principiantes de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de presentar el examen. Fuente: página de ELDT del Illinois SOS; 49 CFR Parte 380."},"88":{"q":"Conforme al requisito de ELDT de Illinois, la porción teórica de la capacitación debe completarse antes de ¿cuál paso?","options":["Tomar el examen de conocimientos (escrito) del CDL para la nueva clase o endoso","Solicitar una licencia de conducir básica de Illinois","Renovar una licencia existente que no sea CDL","Programar un examen de la vista"],"explanation":"Illinois exige que los solicitantes que buscan un CDL inicial de Clase A o B, una mejora, o un endoso inicial S, P o H completen la capacitación teórica de ELDT de un proveedor registrado antes de tomar el examen de conocimientos relacionado. Fuente: página de ELDT del Illinois SOS; 49 CFR Parte 380."},"89":{"q":"¿Cuál de estos endosos requiere completar el ELDT antes de que un solicitante de Illinois pueda presentar su examen?","options":["Pasajeros (P), Autobús escolar (S) y Materiales peligrosos (H)","Solo tráileres dobles/triples (T)","Solo vehículo cisterna (N)","Ningún endoso requiere ELDT en Illinois"],"explanation":"El ELDT aplica a la emisión inicial de los endosos de Autobús escolar (S), Pasajeros (P) y Materiales peligrosos (H), además de las licencias iniciales de Clase A/B y las mejoras. Fuente: página de ELDT del Illinois SOS; 49 CFR Parte 380."},"90":{"q":"¿Qué debe obtener primero un conductor de Illinois como el paso que permite practicar al volante antes de tomar el examen de habilidades del CDL?","options":["Un Permiso de Aprendiz Comercial (CLP)","Una exención interestatal temporal","Una tarjeta de endoso comercial provisional","Una exención del examen de manejo de la FMCSA"],"explanation":"Después de aprobar el o los exámenes de conocimientos requeridos, se le emite al solicitante un Permiso de Aprendiz Comercial (CLP), que autoriza la práctica supervisada en un vehículo representativo antes del examen de habilidades. Fuente: Guía de Estudio del CDL del Illinois SOS; 49 CFR 383.25."},"91":{"q":"Después de que se emite un CLP de Illinois, ¿cuánto tiempo debe esperar el titular antes de que se le permita tomar el examen de habilidades del CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","No hay periodo de espera"],"explanation":"La ley federal adoptada por Illinois exige un periodo de espera mínimo de 14 días desde la fecha de emisión del CLP antes de que se pueda administrar el examen de habilidades; un solicitante puede programarlo con anticipación pero no puede elegir una fecha dentro de los 14 días. Fuente: páginas de CDL del Illinois SOS; 49 CFR 383.25."},"92":{"q":"El examen de habilidades del CDL de Illinois se da en tres partes. ¿Cuál es el orden correcto en que se administran?","options":["Inspección (del vehículo) previa al viaje, luego habilidades básicas de control, luego examen de manejo en carretera","Examen de manejo en carretera, luego habilidades básicas de control, luego inspección previa al viaje","Habilidades básicas de control, luego examen de manejo en carretera, luego inspección previa al viaje","Inspección previa al viaje, luego examen de manejo en carretera, luego habilidades básicas de control"],"explanation":"El examen de habilidades se realiza en el orden: (1) Inspección (del Vehículo) Previa al Viaje, (2) Habilidades Básicas de Control y (3) Examen de Manejo en Carretera. Fuente: Guía de Estudio del CDL del Illinois SOS y páginas de CDL de ilsos.gov."},"93":{"q":"Durante la porción de inspección previa al viaje del examen de habilidades de Illinois, el solicitante debe demostrar principalmente la capacidad de:","options":["Identificar los componentes que deben revisarse y explicar por qué cada uno es importante para la operación segura","Desarmar y rearmar el sistema de frenos","Recitar de memoria todo el Código de Vehículos de Illinois","Reemplazar un neumático dentro de un límite de tiempo fijo"],"explanation":"El examen de inspección del vehículo requiere que el solicitante localice los elementos, indique qué se está revisando y explique por qué la revisión importa para la operación segura. Fuente: Guía de Estudio del CDL del Illinois SOS (Sección 11, Examen de Inspección del Vehículo)."},"94":{"q":"¿Cuál de los siguientes forma parte de la porción de Habilidades Básicas de Control del examen de habilidades del CDL de Illinois?","options":["Maniobras de retroceso controlado, como el retroceso en línea recta y el retroceso desplazado","Incorporarse a una carretera interestatal a toda velocidad","Responder 50 preguntas escritas de opción múltiple","Acoplar un placard de materiales peligrosos al tráiler"],"explanation":"Las Habilidades Básicas de Control evalúan el control preciso del vehículo a baja velocidad mediante maniobras como el retroceso en línea recta, el retroceso desplazado y el estacionamiento, típicamente en una pista. Fuente: Guía de Estudio del CDL del Illinois SOS (Examen de Habilidades Básicas de Control del Vehículo)."},"95":{"q":"¿Qué puntaje mínimo debe alcanzar un solicitante para aprobar cada examen de conocimientos (escrito) del CDL de Illinois?","options":["80% correcto","70% correcto","75% correcto","90% correcto"],"explanation":"Los exámenes de conocimientos del CDL de Illinois requieren un mínimo del 80% correcto para aprobar, en consonancia con el estándar federal. Fuente: Guía de Estudio del CDL del Illinois SOS; 49 CFR 383.135."},"96":{"q":"¿Cuál es el ciclo de renovación estándar de una Licencia de Conducir Comercial de Illinois para un conductor en el rango de edad normal?","options":["Cada 4 años","Cada 2 años","Cada 5 años","Cada 8 años"],"explanation":"Un CDL estándar de Illinois se emite en un ciclo de 4 años, que generalmente vence en el cumpleaños del titular; la renovación también requiere una autocertificación vigente y, para los conductores no exceptuados, una certificación médica válida. Fuente: páginas de CDL del Illinois SOS e información de renovación de Driver Services."},"97":{"q":"¿Cuál es la edad mínima para solicitar un CDL de Illinois para conducir en comercio INTERESTATAL o para transportar pasajeros, en comparación con conducir solo intraestatal?","options":["21 para interestatal o pasajeros; 18 para solo intraestatal","18 para interestatal o pasajeros; 16 para solo intraestatal","25 para interestatal o pasajeros; 21 para solo intraestatal","21 tanto para interestatal como intraestatal"],"explanation":"Un solicitante debe tener al menos 21 años para operar en comercio interestatal o transportar pasajeros, y al menos 18 años para obtener un CDL/CLP para operación solo intraestatal. Fuente: Guía de Estudio del CDL del Illinois SOS y páginas de CDL de ilsos.gov."}},"hi":{"0":{"q":"इलिनॉय के राजमार्गों पर, स्वीकृत सुरक्षा उपकरणों और दर्पणों को छोड़कर, एक वाणिज्यिक वाहन की अधिकतम चौड़ाई कितनी है?","options":["8 फुट 6 इंच (102 inches)","8 फुट 0 इंच (96 inches)","9 फुट 0 इंच (108 inches)","10 फुट 0 इंच (120 inches)"],"explanation":"इलिनॉय वाहन की चौड़ाई को 8 फुट 6 इंच (102 inches) तक सीमित करता है, जिसमें दर्पण और अन्य स्वीकृत सुरक्षा उपकरण शामिल नहीं हैं। स्रोत: 625 ILCS 5/15-102; Illinois CDL/Rules of the Road।"},"1":{"q":"इलिनॉय के राजमार्गों पर अनुमत वाहन की, उसके लदान सहित, अधिकतम ऊँचाई कितनी है?","options":["13 फुट 6 इंच","13 फुट 0 इंच","14 फुट 0 इंच","12 फुट 6 इंच"],"explanation":"इलिनॉय कुल ऊँचाई को, जो सड़क की सतह से लदान के शीर्ष तक मापी जाती है, 13 फुट 6 इंच तक सीमित करता है। स्रोत: 625 ILCS 5/15-103।"},"2":{"q":"इलिनॉय के राजमार्गों पर बिना परमिट के संचालित पाँच या अधिक एक्सल वाले वाहन संयोजन का अधिकतम सकल वजन कितना है?","options":["80,000 pounds","73,280 pounds","84,000 pounds","88,000 pounds"],"explanation":"इलिनॉय पाँच या अधिक एक्सल वाले संयोजनों के लिए 80,000 pounds सकल वजन की संघीय अधिकतम सीमा को अपनाता है। स्रोत: 625 ILCS 5/15-111।"},"3":{"q":"इलिनॉय के राजमार्गों पर एक एकल एक्सल पर अनुमत अधिकतम वजन कितना है?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"इलिनॉय एक एकल एक्सल को 20,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: 625 ILCS 5/15-111।"},"4":{"q":"इलिनॉय के राजमार्गों पर एक टैंडम एक्सल समूह पर अनुमत अधिकतम वजन कितना है?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"इलिनॉय एक टैंडम एक्सल को 34,000 pounds तक सीमित करता है, जिसमें टैंडम के भीतर कोई भी एकल एक्सल 20,000 pounds से अधिक नहीं हो सकता। स्रोत: 625 ILCS 5/15-111।"},"5":{"q":"इलिनॉय के राजमार्गों पर एक एकल सीधे (कठोर) ट्रक की अधिकतम लंबाई कितनी है?","options":["42 feet","40 feet","45 feet","53 feet"],"explanation":"इलिनॉय में सीधे ट्रक जैसे एकल वाहन की कुल लंबाई 42 feet से अधिक नहीं हो सकती। स्रोत: 625 ILCS 5/15-107।"},"6":{"q":"इलिनॉय में निर्दिष्ट राजमार्ग (National Network) प्रणाली पर, ट्रैक्टर-सेमीट्रेलर संयोजन में संचालित एकल सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["53 feet","48 feet","57 feet","60 feet"],"explanation":"इलिनॉय ट्रैक्टर-सेमीट्रेलर संयोजन में 53 feet तक के सेमीट्रेलर की अनुमति देता है, जो संघीय National Network मानक के अनुरूप है। स्रोत: 625 ILCS 5/15-107।"},"7":{"q":"एक्सल के बीच की दूरी और एक्सल की संख्या के आधार पर अधिकतम अनुमत सकल वजन निर्धारित करने के लिए इलिनॉय किस सूत्र का उपयोग करता है?","options":["The Federal Bridge Formula (वजन-दूरी सूत्र)","The Gross Combination Rating सूत्र","The Tire-Load Index सूत्र","The Registered Weight Class सूत्र"],"explanation":"इलिनॉय एक्सल के बीच की दूरी (L) और एक्सल की संख्या (N) के आधार पर अधिकतम सकल वजन निर्धारित करने के लिए Federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], का उपयोग करता है। स्रोत: 625 ILCS 5/15-111।"},"8":{"q":"इलिनॉय में, राज्य-अनुरक्षित राजमार्ग पर कानूनी आकार या वजन सीमा से अधिक लदान के लिए राज्य का ओवरसाइज़/ओवरवेट परमिट कौन जारी करता है?","options":["The Illinois Department of Transportation (IDOT)","The Illinois Secretary of State","The Illinois State Police","The Federal Motor Carrier Safety Administration"],"explanation":"IDOT अपने वैधानिक अधिकार के तहत राज्य-अनुरक्षित राजमार्गों पर आवाजाही के लिए ओवरसाइज़/ओवरवेट परमिट जारी करता है। स्रोत: 625 ILCS 5/15-301; IDOT Oversize/Overweight Permits।"},"9":{"q":"इलिनॉय का ओवरसाइज़/ओवरवेट परमिट सामान्यतः तब आवश्यक होता है जब कोई वाहन या लदान निम्नलिखित में से किससे अधिक हो जाता है?","options":["8 फुट 6 इंच चौड़ा, 13 फुट 6 इंच ऊँचा, या 80,000 pounds सकल वजन","8 फुट 0 इंच चौड़ा, 13 फुट 0 इंच ऊँचा, या 73,280 pounds सकल वजन","9 फुट 0 इंच चौड़ा, 14 फुट 0 इंच ऊँचा, या 84,000 pounds सकल वजन","10 फुट 0 इंच चौड़ा, 15 फुट 0 इंच ऊँचा, या 90,000 pounds सकल वजन"],"explanation":"जब कोई लदान कानूनी सीमाओं से अधिक हो जाता है (8'6\" से अधिक चौड़ा, 13'6\" से अधिक ऊँचा, कानूनी लंबाई से अधिक, या 80,000 lb सकल से अधिक), तो उसे राज्य राजमार्गों पर ले जाने के लिए IDOT परमिट आवश्यक होता है। स्रोत: 625 ILCS 5/15-301; IDOT।"},"10":{"q":"इलिनॉय टायर की चौड़ाई के प्रति इंच (सड़क के संपर्क में आने वाले टायर के लिए) अधिकतम कितना लदान अनुमत करता है?","options":["800 pounds प्रति इंच टायर चौड़ाई","500 pounds प्रति इंच टायर चौड़ाई","1,000 pounds प्रति इंच टायर चौड़ाई","600 pounds प्रति इंच टायर चौड़ाई"],"explanation":"इलिनॉय एक्सल वजन सीमाओं के अतिरिक्त, फुटपाथ की सुरक्षा के लिए लदान को टायर की चौड़ाई के प्रति इंच 800 pounds तक सीमित करता है। स्रोत: 625 ILCS 5/15-111।"},"11":{"q":"इलिनॉय ओवरसाइज़/ओवरवेट और हार्वेस्ट परमिट के लिए आवेदन करने हेतु IDOT किस ऑनलाइन प्रणाली का उपयोग करता है?","options":["ITAP (Illinois Transportation Automated Permits system)","IRP (International Registration Plan portal)","CDLIS (Commercial Driver License Information System)","SAFER (Safety and Fitness Electronic Records)"],"explanation":"आवेदक IDOT की ITAP प्रणाली के माध्यम से आवेदन करते हैं, जो ओवरसाइज़/ओवरवेट और हार्वेस्ट परमिट तक 24/7 ऑनलाइन पहुँच प्रदान करती है। स्रोत: IDOT Oversize/Overweight Permits (webapps.dot.illinois.gov/ITAP)।"},"12":{"q":"कटाई के मौसम के दौरान मुफ्त इलिनॉय हार्वेस्ट परमिट किसी वाहन को सकल, एक्सल और पंजीकृत वजन से लगभग कितने प्रतिशत तक कानूनी सीमाओं से अधिक होने की अनुमति देता है?","options":["10 प्रतिशत तक","5 प्रतिशत तक","15 प्रतिशत तक","25 प्रतिशत तक"],"explanation":"इलिनॉय हार्वेस्ट परमिट कटाई के दौरान कृषि वस्तुओं को ढोने के लिए कानूनी सकल, एक्सल और पंजीकृत वजन से 10 प्रतिशत तक अधिक की अनुमति देता है। स्रोत: IDOT Harvest Permit; Illinois Farm Bureau।"},"13":{"q":"IDOT द्वारा जारी इलिनॉय हार्वेस्ट परमिट किन सड़कों पर ओवरवेट कृषि यात्रा की अनुमति देता है?","options":["केवल राज्य-अनुरक्षित मार्ग (इंटरस्टेट या स्थानीय सड़कें नहीं, जब तक कि अलग से प्राधिकृत न हों)","इलिनॉय के भीतर सभी इंटरस्टेट राजमार्ग","इलिनॉय में कोई भी सार्वजनिक सड़क, जिसमें स्थानीय टाउनशिप सड़कें शामिल हैं","केवल काउंटी और टाउनशिप सड़कें, राज्य मार्ग कभी नहीं"],"explanation":"IDOT हार्वेस्ट परमिट केवल राज्य मार्गों को कवर करता है; यह इंटरस्टेट यात्रा को प्राधिकृत नहीं करता, और स्थानीय सड़कों के लिए अलग से स्थानीय प्राधिकरण आवश्यक होता है। स्रोत: IDOT Harvest Permit; Illinois Farm Bureau।"},"14":{"q":"मानक इलिनॉय हार्वेस्ट परमिट की कीमत एक पात्र किसान या कृषि ढुलाईकर्ता को कितनी पड़ती है?","options":["यह मुफ्त है","$15 प्रति वाहन","$100 प्रति सीज़न","$50 प्रति मार्ग प्राधिकरण"],"explanation":"इलिनॉय पात्र कृषि ढुलाईकर्ताओं को हार्वेस्ट परमिट मुफ्त में प्रदान करता है, जो IDOT की ITAP प्रणाली के माध्यम से प्राप्त किया जाता है। स्रोत: IDOT Harvest Permit; Illinois Farm Bureau।"},"15":{"q":"इलिनॉय मुख्य रूप से प्राकृतिक गैस द्वारा संचालित वाहन को (भारी ईंधन प्रणाली की भरपाई के लिए) कितनी अतिरिक्त सकल वजन छूट देता है, और यह कहाँ लागू नहीं होती?","options":["2,000 pounds तक अतिरिक्त, लेकिन Interstate प्रणाली पर नहीं","Interstates सहित सभी राजमार्गों पर 5,000 pounds तक अतिरिक्त","केवल स्थानीय सड़कों पर 1,000 pounds तक अतिरिक्त","केवल Interstates पर 4,000 pounds तक अतिरिक्त"],"explanation":"इलिनॉय प्राकृतिक-गैस-संचालित वाहनों के लिए 2,000 pounds तक अतिरिक्त सकल वजन की अनुमति देता है, सिवाय Interstate राजमार्गों के। स्रोत: 625 ILCS 5/15-111।"},"16":{"q":"इलिनॉय में एक कानूनी टैंडम एक्सल समूह के भीतर, टैंडम का कोई भी एकल एक्सल किस वजन से अधिक नहीं हो सकता?","options":["20,000 pounds","17,000 pounds","18,000 pounds","22,000 pounds"],"explanation":"भले ही एक टैंडम कुल 34,000 pounds ले जा सकता है, उस टैंडम के भीतर कोई भी एकल एक्सल 20,000 pounds से अधिक नहीं हो सकता। स्रोत: 625 ILCS 5/15-111।"},"17":{"q":"इलिनॉय में प्रयुक्त Federal Bridge Formula W = 500[(LN/(N-1)) + 12N + 36] में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["मापे जा रहे समूह के चरम (सबसे बाहरी) एक्सल के बीच की दूरी फुट में","ट्रेलर की कुल लंबाई फुट में","प्रति टायर कानूनी लदान सीमा","वाहन का लाइसेंसीकृत सकल वजन"],"explanation":"ब्रिज सूत्र में, L समूह के चरम एक्सल के बीच की दूरी फुट में है, N एक्सल की संख्या है, और W अधिकतम अनुमत वजन है। स्रोत: 625 ILCS 5/15-111।"},"18":{"q":"इलिनॉय में एक स्थानीय प्राधिकरण अपने अधिकार क्षेत्र के अधीन किसी राजमार्ग पर वैधानिक सीमा से अधिक सकल वजन को कानूनी रूप से तभी पोस्ट और अनुमत कर सकता है जब वह क्या करे?","options":["उचित नियामक संकेत लगाकर सूचना दे, बिना एकल- या टैंडम-एक्सल अधिकतम सीमाओं से अधिक हुए","Federal Highway Administration से लिखित अनुमोदन प्राप्त करे","एकल-एक्सल अधिकतम को 24,000 pounds तक बढ़ाए","उस सड़क के लिए Federal Bridge Formula को पूरी तरह से माफ कर दे"],"explanation":"स्थानीय प्राधिकरण निर्दिष्ट स्थानीय राजमार्गों पर बढ़े हुए लदान की अनुमति केवल तभी दे सकते हैं जब उचित नियामक संकेत लगाए गए हों, और वे फिर भी एकल- या टैंडम-एक्सल अधिकतम सीमाओं से अधिक नहीं हो सकते। स्रोत: 625 ILCS 5/15-111 और संबंधित स्थानीय-प्राधिकरण प्रावधान।"},"19":{"q":"एक चालक इलिनॉय राज्य राजमार्ग पर 9 फुट चौड़ा और 14 फुट ऊँचा लदान बिना परमिट के ले जा रहा है। इस आवाजाही का सही वर्णन क्या है?","options":["यह अवैध है; चौड़ाई (8'6\" से अधिक) और ऊँचाई (13'6\" से अधिक) दोनों कानूनी सीमाओं से अधिक हैं और इसके लिए IDOT ओवरसाइज़ परमिट आवश्यक है","यह कानूनी है क्योंकि कृषि लदान सभी आकार सीमाओं से छूट प्राप्त हैं","यह कानूनी है क्योंकि केवल वजन के लिए, आयामों के लिए नहीं, परमिट आवश्यक है","यह कानूनी है क्योंकि लदान 80,000 pounds सकल वजन से कम है"],"explanation":"8'6\" चौड़ाई या 13'6\" ऊँचाई से अधिक होने पर आवाजाही IDOT ओवरसाइज़ परमिट के बिना अवैध हो जाती है; आयामी सीमाएँ सकल वजन से स्वतंत्र रूप से लागू होती हैं। स्रोत: 625 ILCS 5/15-102, 15-103, और 15-301।"},"20":{"q":"इलिनॉय में, 26,001 lbs या अधिक के सकल संयोजन वजन रेटिंग (GCWR) वाले वाहन संयोजन को, जहाँ खींचे जा रहे वाहन का GVWR 10,000 lbs से अधिक हो, संचालित करने के लिए कौन सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"इलिनॉय Class A CDL को 26,001 lbs या अधिक के GCWR वाले वाहनों के संयोजन के रूप में परिभाषित करता है, बशर्ते खींची जाने वाली इकाई का GVWR 10,000 lbs से अधिक हो। स्रोत: Illinois SOS CDL Study Guide / ilsos.gov CDL classes page; 92 Ill. Admin. Code 1030।"},"21":{"q":"इलिनॉय नियमों के तहत, एक Class B CDL निम्नलिखित में से किसके संचालन को प्राधिकृत करता है?","options":["26,001 lbs या अधिक के GVWR वाला कोई भी एकल वाहन (10,000 lbs से अधिक न होने वाली इकाई खींचते हुए)","10,000 lbs से अधिक की इकाई खींचने वाला कोई भी संयोजन","केवल 16,000 lbs GVWR से कम के वाहन","केवल 16+ यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन"],"explanation":"इलिनॉय Class B CDL को 26,001 lbs या अधिक के GVWR वाले किसी भी एकल वाहन के रूप में, या ऐसे वाहन के रूप में परिभाषित करता है जो 10,000 lbs से अधिक न होने वाली किसी अन्य इकाई को खींच रहा हो (जैसे, सीधे ट्रक, बड़ी बसें)। स्रोत: Illinois SOS CDL Study Guide / ilsos.gov।"},"22":{"q":"एक इलिनॉय चालक 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन की गई एक छोटी वैन, जिसका वजन 26,001 lbs से कम है, संचालित करना चाहता है। कौन सा CDL वर्ग लागू होता है?","options":["Class C","Class A","Class B","किसी CDL की आवश्यकता नहीं है"],"explanation":"इलिनॉय Class C ऐसे किसी भी वाहन को कवर करता है जो Class A या B को पूरा नहीं करता और जो चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है, या जो प्लेकार्ड किए गए खतरनाक पदार्थ ले जाता है। स्रोत: Illinois SOS CDL Study Guide / ilsos.gov।"},"23":{"q":"इलिनॉय में ऐसे वाहन को चलाने के लिए कौन सा CDL एंडोर्समेंट आवश्यक है जो प्लेकार्डिंग की आवश्यकता वाली मात्रा में खतरनाक पदार्थ ले जा रहा हो?","options":["H (HazMat)","N (Tanker)","T (Doubles/Triples)","P (Passenger)"],"explanation":"प्लेकार्डिंग की आवश्यकता वाले खतरनाक पदार्थ ले जाने वाले किसी भी वाहन के लिए H एंडोर्समेंट आवश्यक है। इलिनॉय अतिरिक्त रूप से H ज्ञान परीक्षा से पहले एक TSA सुरक्षा खतरा मूल्यांकन और ELDT की आवश्यकता रखता है। स्रोत: ilsos.gov Hazardous Materials Endorsement page।"},"24":{"q":"इलिनॉय में, थोक में तरल या गैस ढोने वाले टैंक वाहन को संचालित करने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["N (Tanker)","H (HazMat)","T (Doubles/Triples)","S (School Bus)"],"explanation":"N एंडोर्समेंट उस टैंक वाहन के संचालन को प्राधिकृत करता है जो तरल या गैस का परिवहन करता है। इसके लिए टैंक वाहन ज्ञान परीक्षा उत्तीर्ण करना आवश्यक है। स्रोत: Illinois SOS CDL Study Guide / ilsos.gov endorsements।"},"25":{"q":"इलिनॉय T एंडोर्समेंट (Doubles/Triples) केवल किस वर्ग के CDL में जोड़ा जा सकता है?","options":["Class A","Class B","Class C","कोई भी वर्ग"],"explanation":"इलिनॉय में T (Doubles/Triples) एंडोर्समेंट केवल Class A CDL पर लागू होता है, क्योंकि एक से अधिक ट्रेलर खींचने के लिए संयोजन लाइसेंस आवश्यक है। ध्यान दें: ट्रिपल ट्रेलर इलिनॉय के राजमार्गों पर कानूनी नहीं हैं। स्रोत: Illinois SOS CDL materials / ilsos.gov endorsements।"},"26":{"q":"इलिनॉय में ट्रिपल ट्रेलरों के बारे में कौन सा कथन सही है?","options":["ट्रिपल ट्रेलर इलिनॉय के राजमार्गों पर अनुमत नहीं हैं","ट्रिपल ट्रेलर केवल इंटरस्टेट पर अनुमत हैं","ट्रिपल ट्रेलर P एंडोर्समेंट के साथ अनुमत हैं","ट्रिपल ट्रेलर के लिए केवल Class B CDL आवश्यक है"],"explanation":"हालाँकि एंडोर्समेंट को Doubles/Triples (T) कहा जाता है, इलिनॉय कानून अपने राजमार्गों पर ट्रिपल-ट्रेलर संयोजनों की अनुमति नहीं देता। स्रोत: Illinois SOS CDL endorsement information / ilsos.gov।"},"27":{"q":"इलिनॉय में, चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["P (Passenger)","S (School Bus)","N (Tanker)","T (Doubles/Triples)"],"explanation":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को संचालित करने के लिए P (Passenger) एंडोर्समेंट आवश्यक है; इसके लिए ज्ञान परीक्षा और एक प्रतिनिधि वाहन में कौशल परीक्षा आवश्यक है। स्रोत: Illinois SOS CDL Study Guide / ilsos.gov।"},"28":{"q":"इलिनॉय में छात्रों (12वीं कक्षा और उससे नीचे) को ले जाने वाली पीली स्कूल बस चलाने के लिए, चालक को CDL के अतिरिक्त कौन सा एंडोर्समेंट चाहिए?","options":["S (School Bus)","केवल P","N (Tanker)","H (HazMat)"],"explanation":"छात्रों को स्कूल से/स्कूल तक या स्कूल गतिविधियों के लिए परिवहन हेतु S (School Bus) एंडोर्समेंट आवश्यक है; इलिनॉय में ज्ञान, कौशल और एक ड्राइव परीक्षा आवश्यक है (P एंडोर्समेंट भी एक पूर्व-शर्त है)। स्रोत: ilsos.gov School Bus endorsement।"},"29":{"q":"केवल इलिनॉय के भीतर (इंट्रास्टेट) संचालन के लिए इलिनॉय CDL या CLP प्राप्त करने की न्यूनतम आयु क्या है?","options":["18","21","19","16"],"explanation":"इलिनॉय में इंट्रास्टेट संचालन के लिए CDL/CLP प्राप्त करने हेतु आवेदक का कम से कम 18 वर्ष का होना आवश्यक है। स्रोत: ilsos.gov CDL/CLP page; 625 ILCS 5/6-507।"},"30":{"q":"इंटरस्टेट वाणिज्य में एक वाणिज्यिक मोटर वाहन संचालित करने या यात्रियों के परिवहन के लिए इलिनॉय न्यूनतम कितनी आयु की आवश्यकता रखता है?","options":["21","18","19","25"],"explanation":"इलिनॉय में इंटरस्टेट वाणिज्य में संचालन या यात्रियों के परिवहन के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है; 18-20 वर्ष के लोग केवल इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: ilsos.gov CDL/CLP page; 49 CFR 391.11 जैसा इलिनॉय द्वारा अपनाया गया।"},"31":{"q":"इलिनॉय द्वारा अपनाए गए संघीय नियमों के तहत, CDL कौशल (सड़क) परीक्षा देने से पहले एक चालक को Commercial Learner's Permit (CLP) कितने समय तक धारण करना आवश्यक है?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 7 days","कम से कम 60 days"],"explanation":"संघीय और इलिनॉय दोनों नियम कौशल परीक्षा से पहले CLP को कम से कम 14 days तक धारण करना आवश्यक करते हैं; आप पहले से शेड्यूल कर सकते हैं, लेकिन परीक्षा की तारीख 14-दिन की होल्ड अवधि के बाद होनी चाहिए। स्रोत: ilsos.gov CDL/CLP page; 49 CFR 383.25।"},"32":{"q":"इलिनॉय Commercial Learner's Permit (CLP) कितने समय के लिए वैध होता है?","options":["180 days","90 days","1 year","30 days"],"explanation":"एक इलिनॉय CLP 180 days के लिए वैध होता है, जो संघीय CLP मानक के अनुरूप है। स्रोत: ilsos.gov CDL/CLP page; 49 CFR 383.25।"},"33":{"q":"इलिनॉय निम्नलिखित में से किसके लिए ज्ञान या कौशल परीक्षा से पहले Entry-Level Driver Training (ELDT) की आवश्यकता रखता है?","options":["एक आरंभिक H (HazMat), P (Passenger), या S (School Bus) एंडोर्समेंट","केवल N (Tanker) एंडोर्समेंट","किसी भी मौजूदा एंडोर्समेंट का नवीनीकरण","एक मोटरसाइकिल एंडोर्समेंट जोड़ना"],"explanation":"ELDT पहला Class A या B CDL प्राप्त करने, अपग्रेड करने, और एक आरंभिक H, P, या S एंडोर्समेंट प्राप्त करने पर लागू होता है। HazMat (H) सैद्धांतिक प्रशिक्षण H ज्ञान परीक्षा से पहले होना चाहिए। स्रोत: ilsos.gov ELDT page; 49 CFR Part 380।"},"34":{"q":"एक इलिनॉय CLP/CDL आवेदक को Secretary of State सुविधा पर कौन से दस्तावेज़ों का सेट प्रस्तुत करना होगा?","options":["पहचान का प्रमाण, Social Security number का लिखित प्रमाण, कानूनी/वैध उपस्थिति का प्रमाण, और इलिनॉय निवास के दो प्रमाण","केवल एक Social Security card","केवल एक U.S. passport","केवल दो उपयोगिता बिल"],"explanation":"इलिनॉय पहचान का प्रमाण, SSN का लिखित प्रमाण (जैसे, वास्तविक कार्ड या W-2; कोई फोटोकॉपी नहीं), वैध उपस्थिति का प्रमाण, और इलिनॉय निवास के दो प्रमाण आवश्यक करता है। स्रोत: ilsos.gov CDL/CLP and legal presence pages।"},"35":{"q":"Secretary of State CDL/CLP आवेदन के लिए इलिनॉय निवास के कितने प्रमाण आवश्यक करता है?","options":["दो","एक","तीन","कोई नहीं"],"explanation":"इलिनॉय पहचान, SSN और वैध उपस्थिति के प्रमाण के अतिरिक्त, इलिनॉय निवास के दो स्वीकार्य प्रमाण आवश्यक करता है। स्रोत: ilsos.gov Driver's License/CDL document requirements।"},"36":{"q":"इलिनॉय CDL के लिए आवेदन करते समय, कौन सी स्व-प्रमाणन श्रेणी में चालक को एक वैध संघीय DOT Medical Examiner's Certificate प्रदान करना आवश्यक है?","options":["Non-excepted interstate (NI)","Excepted intrastate (EA)","Excepted interstate (EI)","Non-excepted intrastate (NA)"],"explanation":"इलिनॉय चार स्व-प्रमाणन श्रेणियों (NI, EI, NA, EA) को मान्यता देता है। एक non-excepted interstate (NI) चालक को संघीय DOT चिकित्सा मानकों को पूरा करना होगा और एक Medical Examiner's Certificate (Form MCSA-5876) प्रस्तुत करना होगा। स्रोत: ilsos.gov CDL page; 92 Ill. Admin. Code 1030.22।"},"37":{"q":"कौन सी सूची सही रूप से उन चार चिकित्सा स्व-प्रमाणन श्रेणियों के नाम बताती है जिनमें से इलिनॉय CDL/CLP आवेदकों को चुनना होता है?","options":["Non-excepted interstate, Excepted interstate, Non-excepted intrastate, Excepted intrastate","Interstate, Intrastate, Farm, Military","Class A, Class B, Class C, Class D","Local, Regional, National, International"],"explanation":"इलिनॉय चार संघीय स्व-प्रमाणन श्रेणियों का उपयोग करता है: Non-excepted interstate (NI), Excepted interstate (EI), Non-excepted intrastate (NA), और Excepted intrastate (EA)। स्रोत: ilsos.gov CDL page; 92 Ill. Admin. Code 1030.22।"},"38":{"q":"HazMat (H) एंडोर्समेंट वाले एक इलिनॉय CDL धारक के लिए, एंडोर्समेंट बनाए रखने के लिए TSA सुरक्षा खतरा मूल्यांकन को कितनी बार नवीनीकृत करना आवश्यक है?","options":["हर 5 years","हर 2 years","हर 10 years","केवल एक बार, कभी नवीनीकृत नहीं"],"explanation":"HazMat एंडोर्समेंट के लिए एक TSA सुरक्षा खतरा मूल्यांकन 5 years के लिए वैध होता है; इलिनॉय प्रत्येक नवीनीकरण पर मूल्यांकन और HazMat ज्ञान परीक्षा आवश्यक करता है, और चालकों को समाप्ति से लगभग 60 days पहले नवीनीकरण शुरू कर देना चाहिए। स्रोत: ilsos.gov Hazardous Materials Endorsement; 49 CFR 1572।"},"39":{"q":"इलिनॉय कानून के तहत, एक CDL धारक एक वाणिज्यिक मोटर वाहन (CMV) संचालित करते समय अधिकतम कितना रक्त-अल्कोहल सांद्रता (BAC) रख सकता है?","options":["0.04 percent","0.08 percent","0.02 percent","0.00 percent"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1) में कहा गया है कि एक CDL धारक .04 percent या उससे अधिक BAC के साथ CMV संचालित नहीं कर सकता, जो अन्य वाहनों के लिए .08 सीमा का आधा है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/11-501।"},"40":{"q":"जब कोई चालक इलिनॉय के राजमार्गों पर वाहन संचालित करता है, तो राज्य के निहित-सहमति (implied-consent) कानून का अर्थ है कि चालक ने पहले से क्या करने के लिए सहमति दे दी है?","options":["रक्त-अल्कोहल सांद्रता निर्धारित करने के लिए रासायनिक परीक्षणों से गुजरना","किसी भी समय वाहन के माल की तलाशी की अनुमति देना","किसी भी ट्रैफिक चालान का विरोध करने से पहले जुर्माना भरना","किसी भी चलती-वाहन उल्लंघन पर CDL समर्पित करना"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1) में कहा गया है कि राजमार्गों पर CMV या गैर-CMV संचालित करने वाले चालक BAC निर्धारित करने के लिए रासायनिक परीक्षणों से गुजरने हेतु निहित रूप से सहमत हो गए हैं। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/11-501.1।"},"41":{"q":"इलिनॉय में, एक चालक जो रासायनिक परीक्षण से गुजरने से इनकार करता है या कानूनी सीमा से अधिक परीक्षण करता है, उसे पहले अपराध (गैर-HazMat) के लिए कम से कम कितने समय की अयोग्यता का सामना करना पड़ता है?","options":["12 months","60 days","6 months","3 years"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): कोई भी चालक जो रासायनिक परीक्षण से इनकार करता है या कानूनी सीमा से अधिक परीक्षण करता है, उसे न्यूनतम 12 months के लिए अयोग्य घोषित किया जाता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"42":{"q":"यदि कोई चालक प्लेकार्ड किए गए खतरनाक पदार्थों के परिवहन के दौरान पहला बड़ा अल्कोहल अपराध करता है, तो इलिनॉय अयोग्यता की न्यूनतम अवधि क्या है?","options":["3 years","1 year","5 years","आजीवन"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): यदि उल्लंघन प्लेकार्ड किए गए खतरनाक पदार्थों के परिवहन के दौरान होता है, तो चालक को न्यूनतम तीन वर्ष के लिए अयोग्य घोषित किया जाता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"43":{"q":"एक चालक दो या अधिक घटनाओं से उत्पन्न दो अलग-अलग बड़े अपराध (जैसे दो DUI) करता है। इलिनॉय में क्या अयोग्यता होती है?","options":["आजीवन अयोग्यता","तीन-वर्षीय अयोग्यता","पाँच-वर्षीय अयोग्यता","120-दिन की अयोग्यता"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): कोई भी चालक जो सूचीबद्ध बड़े उल्लंघनों में से दो करता है, जो दो या अधिक घटनाओं से उत्पन्न होते हैं, उसे आजीवन के लिए अयोग्य घोषित किया जाता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"44":{"q":"इलिनॉय में, CMV संचालित करने वाला कोई भी CDL धारक जिसके सिस्टम में कोई भी अल्कोहल (0.04 से कम) पाया जाता है, उसे न्यूनतम कितने समय के लिए सेवा से बाहर (out of service) कर दिया जाता है?","options":["24 hours","1 hour","12 hours","72 hours"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): CMV संचालित करने वाले किसी भी CDL धारक के सिस्टम में कोई भी अल्कोहल पाए जाने पर उसे न्यूनतम 24 hours के लिए सेवा से बाहर कर दिया जाता है। स्रोत: Illinois CDL Study Guide; 49 CFR 392.5।"},"45":{"q":"इलिनॉय में स्कूल बस संचालित करने वाले स्कूल बस चालक के लिए अधिकतम अनुमत BAC क्या है?","options":["0.00 percent","0.04 percent","0.02 percent","0.08 percent"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.1): एक स्कूल बस चालक .00 percent से अधिक BAC के साथ स्कूल बस संचालित नहीं कर सकता। स्रोत: Illinois CDL Study Guide।"},"46":{"q":"CMV संचालित करते समय जानबूझकर और जान-बूझकर दुर्घटना स्थल से चले जाने पर इलिनॉय में कम से कम कितने समय की अयोग्यता होती है?","options":["12 months","60 days","120 days","3 years"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): CMV या गैर-CMV संचालित करते समय जानबूझकर और जान-बूझकर दुर्घटना स्थल से चले जाने पर न्यूनतम 12 months की अयोग्यता होती है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"47":{"q":"किसी नियंत्रित पदार्थ के निर्माण या वितरण से जुड़े अपराध (felony) को करने के लिए वाणिज्यिक या गैर-वाणिज्यिक मोटर वाहन का उपयोग करने पर इलिनॉय में क्या दंड होता है?","options":["आजीवन अयोग्यता","एक-वर्षीय अयोग्यता","तीन-वर्षीय अयोग्यता","120-दिन की अयोग्यता"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): किसी नियंत्रित पदार्थ के निर्माण, वितरण या वितरण से जुड़े अपराध (felony) में CMV या गैर-CMV का उपयोग आजीवन अयोग्यता का परिणाम होता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"48":{"q":"CMV में रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग नियमों के उल्लंघन की पहली दोषसिद्धि के लिए, इलिनॉय अयोग्यता अवधि क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि 60-दिन की अयोग्यता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"49":{"q":"तीन-वर्षीय अवधि के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन इलिनॉय में क्या अयोग्यता का परिणाम होता है?","options":["120 days","60 days","1 year","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): तीन वर्षों के भीतर दूसरी रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग दोषसिद्धि 120-दिन की अयोग्यता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"50":{"q":"तीन-वर्षीय अवधि के भीतर तीसरा या उसके बाद का रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन इलिनॉय में क्या अयोग्यता का परिणाम होता है?","options":["1 year","120 days","60 days","आजीवन"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.2): तीन वर्षों के भीतर तीसरी और उसके बाद की रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग दोषसिद्धि एक-वर्षीय अयोग्यता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"51":{"q":"तीन-वर्षीय अवधि के भीतर कितने गंभीर ट्रैफिक उल्लंघन इलिनॉय में 60-दिन की अयोग्यता को ट्रिगर करते हैं?","options":["दो","तीन","एक","चार"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): तीन-वर्षीय अवधि के भीतर दो गंभीर ट्रैफिक उल्लंघन 60-दिन की अयोग्यता का परिणाम होते हैं। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"52":{"q":"तीन-वर्षीय अवधि के भीतर तीन गंभीर ट्रैफिक उल्लंघन इलिनॉय में क्या अयोग्यता अवधि का परिणाम होते हैं?","options":["120 days","60 days","1 year","90 days"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): तीन-वर्षीय अवधि में तीन गंभीर ट्रैफिक उल्लंघन 120-दिन की अयोग्यता का परिणाम होते हैं। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"53":{"q":"इलिनॉय CDL धारक के लिए पोस्ट की गई सीमा से कितनी गति अधिक होने पर एक एकल गति अपराध 'गंभीर ट्रैफिक उल्लंघन' के रूप में गिना जाता है?","options":["सीमा से 15 mph या अधिक","सीमा से 10 mph या अधिक","सीमा से 20 mph या अधिक","सीमा से 25 mph या अधिक"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): अत्यधिक गति पोस्ट की गई गति सीमा से 15 mph या अधिक का कोई एकल अपराध है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"54":{"q":"इलिनॉय CDL धारक के लिए निम्नलिखित में से किसे 'गंभीर ट्रैफिक उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["अनुचित या अनियमित ट्रैफिक लेन परिवर्तन","एक समाप्त वाहन पंजीकरण स्टिकर","शहर के केंद्र में एक पार्किंग उल्लंघन","एक परमिट लदान पर एक ओवरवेट एक्सल"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3) अनुचित/अनियमित लेन परिवर्तन, बहुत करीब से चलना, लापरवाह ड्राइविंग, अत्यधिक गति और CMV में टेक्स्टिंग को गंभीर ट्रैफिक उल्लंघन के रूप में सूचीबद्ध करता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"55":{"q":"Illinois CDL Study Guide के अनुसार, out-of-service order के पहले उल्लंघन के लिए अयोग्यता क्या है?","options":["कम से कम 90 days","कम से कम 30 days","कम से कम 60 days","कम से कम 1 year"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): out-of-service order के पहले उल्लंघन के लिए आप अपना CDL कम से कम 90 days के लिए खो देते हैं। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"56":{"q":"एक चालक 10-वर्षीय अवधि के भीतर तीन या अधिक out-of-service order उल्लंघन करता है। न्यूनतम इलिनॉय अयोग्यता क्या है?","options":["3 years","1 year","90 days","आजीवन"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.4): 10-वर्षीय अवधि के भीतर तीन या अधिक out-of-service order उल्लंघनों के लिए कम से कम तीन वर्ष (10 वर्षों में दूसरा उल्लंघन कम से कम एक वर्ष है)। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-514।"},"57":{"q":"इलिनॉय CMV चलाते समय टेक्स्टिंग या हैंड-हेल्ड सेलफोन का उपयोग करने वाले CMV चालक को कैसे वर्गीकृत करता है?","options":["एक गंभीर ट्रैफिक उल्लंघन के रूप में","आजीवन अयोग्यता का कारण बनने वाले एक बड़े अपराध के रूप में","बिना CDL प्रभाव वाले एक पार्किंग-प्रकार के उल्लंघन के रूप में","एक out-of-service order उल्लंघन के रूप में"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.5.3): CMV चलाते समय टेक्स्टिंग या हैंड-हेल्ड सेलफोन का उपयोग एक गंभीर ट्रैफिक उल्लंघन है; FMCSA चालक जुर्माना $2,750 तक पहुँच सकता है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/12-610.2; 49 CFR 392.80/392.82।"},"58":{"q":"इलिनॉय में एक अदालत बिना वैध CDL के वाणिज्यिक मोटर वाहन चलाने के लिए, या एक से अधिक लाइसेंस रखने के लिए, अधिकतम कितना जुर्माना लगा सकती है?","options":["$5,000 तक या जेल की सज़ा","केवल $1,000 तक","केवल $500 तक","$10,000 तक या जेल की सज़ा"],"explanation":"Illinois SOS CDL Study Guide (Sec. 1.6): एक अदालत बिना CDL के CMV चलाने या एक से अधिक लाइसेंस रखने के लिए $5,000 तक का जुर्माना या जेल की सज़ा लगा सकती है। स्रोत: Illinois CDL Study Guide; 625 ILCS 5/6-507।"},"59":{"q":"इलिनॉय का 'मूव ओवर' कानून (स्कॉट्स लॉ) किसी चालक को, जो चमकती चेतावनी लाइटें दिखा रहे रुके हुए आपातकालीन या रखरखाव वाहन के पास पहुँच रहा हो, क्या करने के लिए कहता है?","options":["यदि संभव हो तो किसी गैर-निकटवर्ती लेन में बदल जाएँ, अन्यथा गति कम करें और सावधानी से आगे बढ़ें","पूरी तरह रुक जाएँ और आपातकालीन वाहन के जाने तक प्रतीक्षा करें","गति बनाए रखें लेकिन गुज़रते समय हॉर्न बजाएँ","आपातकालीन वाहन के पीछे शोल्डर पर वाहन ले जाएँ और रुक जाएँ"],"explanation":"स्कॉट्स लॉ, 625 ILCS 5/11-907(c) के तहत, चमकती लाइटों वाले रुके हुए आपातकालीन, रखरखाव या टो वाहन के पास पहुँचने वाले चालक को, जब सुरक्षित हो, उससे निकटवर्ती न होने वाली लेन में बदलना चाहिए, और यदि लेन बदलना संभव न हो, तो गति कम करनी चाहिए और सावधानी से आगे बढ़ना चाहिए। स्रोत: 625 ILCS 5/11-907; Illinois State Police Move Over Law पेज।"},"60":{"q":"लेफ्टिनेंट स्कॉट गिलेन के नाम पर बना कानून, जो इलिनॉय के चालकों को रुके हुए आपातकालीन वाहनों को रास्ता देने के लिए कहता है, आम तौर पर किस नाम से जाना जाता है?","options":["द स्टीव्स लॉ","स्कॉट्स लॉ","द डैन रायन एक्ट","द येलो लाइट लॉ"],"explanation":"इलिनॉय के मूव ओवर कानून का आधिकारिक उपनाम 'स्कॉट्स लॉ' है, जो शिकागो फायर डिपार्टमेंट के लेफ्टिनेंट स्कॉट गिलेन के नाम पर है, जिन्हें 2000 में डैन रायन एक्सप्रेसवे पर टक्कर लगने से मार दिया गया था। स्रोत: 625 ILCS 5/11-907; Illinois State Police।"},"61":{"q":"इलिनॉय के रेलमार्ग क्रॉसिंग पर रुकने वाले स्कूल बस और प्लेकार्ड लगे खतरनाक-सामग्री वाहन को निकटतम रेल से कितनी दूरी के भीतर रुकना आवश्यक है?","options":["5 और 25 फीट के बीच","10 और 35 फीट के बीच","15 और 50 फीट के बीच","25 और 75 फीट के बीच"],"explanation":"इलिनॉय CDL हैंडबुक निर्देश देती है कि बस चालक 'अपनी बस को रेलमार्ग क्रॉसिंग से पहले 15 और 50 फीट के बीच रोकें,' और प्लेकार्ड लगे वाहन को 'निकटतम रेल से 15 से 50 फीट पहले रुकना चाहिए।' स्रोत: Illinois SOS CDL Study Guide, धारा 4.3.5 और 9.6.12।"},"62":{"q":"इलिनॉय कानून के अनुसार, बिना परमिट के राज्य के किसी भी राजमार्ग पर वाहन की, उसके भार सहित, अधिकतम वैध ऊँचाई क्या है?","options":["12 फीट 6 इंच","13 फीट 6 इंच","14 फीट 0 इंच","13 फीट 0 इंच"],"explanation":"इलिनॉय वाहन की ऊँचाई को, जो टायर के निचले हिस्से से लेकर भार सहित वाहन के शीर्ष तक मापी जाती है, किसी भी राजमार्ग पर 13 फीट 6 इंच तक सीमित करता है। स्रोत: 625 ILCS 5/15-103।"},"63":{"q":"जब किसी वाणिज्यिक वाहन को इलिनॉय में एकतरफ़ा या विभाजित राजमार्ग पर या उसके किनारे रुकना पड़े, तो चालक को तीनों चेतावनी उपकरणों को आ रहे यातायात की ओर लगभग किन दूरियों पर रखना चाहिए?","options":["10, 100, और 200 फीट","10, 50, और 100 फीट","25, 100, और 250 फीट","5, 75, और 150 फीट"],"explanation":"एकतरफ़ा या विभाजित राजमार्ग पर, इलिनॉय CDL हैंडबुक के अनुसार चेतावनी उपकरणों को आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर रखना आवश्यक है। स्रोत: Illinois SOS CDL Study Guide, उपधारा 2.5 (Warning Devices)।"},"64":{"q":"कुक, ड्यूपेज, केन, लेक, मैकहेनरी, और विल काउंटियों में, 8,000 पाउंड से अधिक के लिए पंजीकृत द्वितीय-श्रेणी के ट्रक की उन सड़कों, राजमार्गों, और गलियों पर अधिकतम गति कितनी है जो टॉलवे इंटरस्टेट नहीं हैं?","options":["65 mph","60 mph","55 mph","45 mph"],"explanation":"उन छह काउंटियों में, 8,000 पाउंड से अधिक के ट्रकों की गति Illinois Tollway इंटरस्टेट राजमार्गों पर 60 mph और अन्य सभी सड़कों, राजमार्गों, या गलियों पर 55 mph तक सीमित है। स्रोत: 625 ILCS 5/11-601(e)।"},"65":{"q":"शहरी जिले के बाहर 70 mph पर पोस्ट किए गए ग्रामीण इलिनॉय इंटरस्टेट पर (और छह शिकागो-क्षेत्र कॉलर काउंटियों के बाहर), वर्तमान इलिनॉय कानून के तहत एक बड़ा ट्रक किस अधिकतम गति पर चल सकता है?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"625 ILCS 5/11-601 में 2014 के बदलाव के बाद से, छह कॉलर काउंटियों के बाहर ग्रामीण इंटरस्टेट पर ट्रक कारों के समान ही पोस्ट की गई सीमा पर, 70 mph तक चल सकते हैं; केवल कुक, ड्यूपेज, केन, लेक, मैकहेनरी, और विल काउंटियों में ही उन्हें कम ट्रक-विशिष्ट सीमाओं पर रखा जाता है। स्रोत: 625 ILCS 5/11-601(d-1), (e)।"},"66":{"q":"इलिनॉय में रेलमार्ग पटरियों को पार करते समय, एक CDL चालक को निम्नलिखित में से क्या करना चाहिए?","options":["अतिरिक्त शक्ति के लिए आधे रास्ते पर निचले गियर में बदल जाएँ","पटरियों को पार करते समय गियर न बदलें","न्यूट्रल में डालें और पार करते हुए कोस्ट करें","पटरियों को जितनी जल्दी हो सके पार करने के लिए ऊपरी गियर में बदलें"],"explanation":"इलिनॉय CDL हैंडबुक स्पष्ट रूप से कहती है: 'रेलमार्ग पटरियों को पार करते समय गियर न बदलें,' क्योंकि गियर छूट जाने या घिसने से वाहन पटरियों पर रुक सकता है। स्रोत: Illinois SOS CDL Study Guide, उपधारा 2.15 और 9.6.12।"},"67":{"q":"चार या अधिक लेन वाले इलिनॉय राजमार्ग पर, जो कम से कम दो लेन यातायात को विपरीत दिशाओं में चलने की अनुमति देता है, एक चालक जो विपरीत सड़क मार्ग में रुकी हुई स्कूल बस से मिल रहा हो, उसे क्या करना चाहिए?","options":["रुकें और तब तक रुके रहें जब तक बस की लाल लाइटें चमकना बंद न कर दें","केवल तभी रुकें जब बच्चे दिखाई दें","रुकने की आवश्यकता नहीं है, लेकिन सतर्क रहना चाहिए","20 mph तक धीमा करें और बस के पास से गुज़रते रहें"],"explanation":"इलिनॉय कानून प्रावधान करता है कि 4 या अधिक लेन वाले राजमार्ग पर, जो कम से कम 2 लेन यातायात को विपरीत दिशाओं में अनुमति देता है, एक चालक को विपरीत सड़क मार्ग में रुकी हुई स्कूल बस से मिलने पर रुकने की आवश्यकता नहीं है। स्रोत: 625 ILCS 5/11-1414(e)।"},"68":{"q":"विभाजित-राजमार्ग अपवाद को छोड़कर, जब कोई स्कूल बस इलिनॉय की किसी सड़क पर अपनी दृश्य संकेत लाइटें चमकाते हुए विद्यार्थियों को चढ़ाने या उतारने के लिए रुकी हो, तो पास आ रहे चालकों को क्या करना चाहिए?","options":["किसी भी दिशा से बस से मिलने या उसे ओवरटेक करने से पहले रुकें","केवल तभी रुकें जब बस के पीछे से पास आ रहे हों","बाईं ओर से 10 mph से अधिक नहीं की गति पर धीरे-धीरे गुज़रें","केवल तभी रुकें जब क्रॉसिंग गार्ड उन्हें संकेत दे"],"explanation":"इलिनॉय चालकों से अपेक्षा करता है कि वे किसी भी दिशा से, किसी ऐसी स्कूल बस से मिलने या उसे ओवरटेक करने से पहले वाहन रोक दें जो रुकी हुई है और विद्यार्थियों को चढ़ाने या उतारने के लिए अपनी दृश्य संकेत लाइटें दिखा रही है। स्रोत: 625 ILCS 5/11-1414(a)।"},"69":{"q":"प्लेकार्ड लगे वाहनों के अलावा, निम्नलिखित में से किसे इलिनॉय में रेलमार्ग पटरियों को पार करने से पहले हमेशा रुकना चाहिए?","options":["10,000 पाउंड से अधिक वज़न वाला कोई भी सीधा ट्रक","किसी भी मात्रा में क्लोरीन ले जा रहा कोई भी वाहन","फ्लैटबेड ट्रेलर खींचने वाला कोई भी वाहन","राज्य से बाहर पंजीकृत कोई भी वाहन"],"explanation":"इलिनॉय CDL हैंडबुक तीन श्रेणियों को सूचीबद्ध करती है जिन्हें रेलमार्ग क्रॉसिंग से पहले रुकना चाहिए: प्लेकार्ड लगे वाहन, किसी भी मात्रा में क्लोरीन ले जा रहे वाहन, और खतरनाक सामग्री के लिए प्रयुक्त कार्गो टैंक (भरे हुए या खाली)। स्रोत: Illinois SOS CDL Study Guide, उपधारा 9.6.12।"},"70":{"q":"बिना परमिट के इलिनॉय के राजमार्गों पर वाहन या उसके भार के लिए अधिकतम वैध चौड़ाई (दर्पणों और कुछ सुरक्षा उपकरणों को छोड़कर) क्या है?","options":["8 फीट 0 इंच","8 फीट 6 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"इलिनॉय किसी वाहन या भार की कुल बाहरी चौड़ाई को 8 फीट 6 इंच तक सीमित करता है; इससे अधिक चौड़ी किसी भी चीज़ के लिए IDOT से ओवरसाइज़ परमिट आवश्यक है। स्रोत: 625 ILCS 5/15-102।"},"71":{"q":"जब किसी CDL चालक को किसी भी इलिनॉय राजमार्ग के शोल्डर या सड़क मार्ग पर रुकना पड़े, तो आपातकालीन चेतावनी उपकरणों को कितने मिनट के भीतर रखना आवश्यक है?","options":["5 मिनट","10 मिनट","15 मिनट","30 मिनट"],"explanation":"इलिनॉय CDL हैंडबुक के अनुसार सड़क या शोल्डर पर रुकने के 10 मिनट के भीतर चेतावनी उपकरण निकालकर रखना आवश्यक है। स्रोत: Illinois SOS CDL Study Guide, उपधारा 2.5।"},"72":{"q":"इलिनॉय में चेतावनी-उपकरण आवश्यकता को पूरा करने के लिए एक वाणिज्यिक वाहन को कितने लाल परावर्तक चेतावनी त्रिकोण ले जाने चाहिए?","options":["दो","तीन","चार","छह"],"explanation":"इलिनॉय CDL हैंडबुक के अनुसार आवश्यक आपातकालीन उपकरण के भाग के रूप में तीन परावर्तक चेतावनी त्रिकोण (या वैकल्पिक रूप से, छह फ्यूज़ या तीन तरल-दहन फ्लेयर) आवश्यक हैं। स्रोत: Illinois SOS CDL Study Guide, उपधारा 2.1।"},"73":{"q":"प्लेकार्ड लगी खतरनाक सामग्री ले जा रहे एक चालक को, जो इलिनॉय में रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन का दोषी पाया जाता है, किस परिणाम का सामना करना पड़ता है?","options":["केवल एक लिखित चेतावनी","24-घंटे का आउट-ऑफ-सर्विस आदेश","CDL अयोग्यता","अंक लेकिन कोई अयोग्यता नहीं"],"explanation":"रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन इलिनॉय में CDL धारकों के लिए अयोग्यता वाले अपराध हैं, जिनमें तीन वर्षों के भीतर बार-बार उल्लंघन के लिए बढ़ती अयोग्यता अवधि (60 दिन, 120 दिन, फिर एक वर्ष) होती है। स्रोत: Illinois SOS CDL Study Guide, उपधारा 1.2 (Disqualifications); इलिनॉय द्वारा अपनाया गया 49 CFR 383.51।"},"74":{"q":"स्कॉट्स लॉ (इलिनॉय के मूव ओवर कानून) के पहले अपराध के उल्लंघन पर कम से कम कितना जुर्माना लगता है?","options":["$100","$250","$500","$1,000"],"explanation":"Public Act 101-0173 के बाद, स्कॉट्स लॉ का उल्लंघन एक व्यावसायिक अपराध है जिसमें पहले अपराध के लिए $250 से कम नहीं और $10,000 तक का जुर्माना है। स्रोत: 625 ILCS 5/11-907(c)।"},"75":{"q":"शिकागो के लेक शोर ड्राइव पर, जिसे कानूनी रूप से बुलेवार्ड/पार्कवे के रूप में वर्गीकृत किया गया है, आम तौर पर क्या प्रतिबंधित है?","options":["माल ढोने के लिए डिज़ाइन की गई ट्रक (वाणिज्यिक) लाइसेंस प्लेट वाले वाहन","सप्ताह के दिनों के व्यस्त समय के दौरान सभी वाहन","केवल ट्रेलर खींचने वाली यात्री कारें","इलिनॉय I-PASS ट्रांसपोंडर के बिना वाहन"],"explanation":"लेक शोर ड्राइव को बुलेवार्ड के रूप में नामित किया गया है, और माल या वाणिज्यिक वस्तुओं को ढोने के लिए डिज़ाइन की गई ट्रक प्लेट वाले वाहनों को इस पर प्रतिबंधित किया गया है, जो इसकी 'प्लेज़र ड्राइव' उत्पत्ति में निहित एक विशिष्ट शिकागो रूटिंग प्रतिबंध है। स्रोत: Chicago Municipal Code बुलेवार्ड प्रतिबंध; CDOT Lake Shore Drive truck travel permit मार्गदर्शन।"},"76":{"q":"किसी रेलमार्ग क्रॉसिंग पर जहाँ अन्यथा रुकना आवश्यक है, एक इलिनॉय बस चालक को पूरी तरह रुकने की आवश्यकता नहीं है, लेकिन उसे किस स्थिति में गति कम करनी चाहिए और सावधानी से जाँच करनी चाहिए?","options":["जब क्रॉसिंग किसी बजरी वाली सड़क पर हो","जब कोई पुलिस अधिकारी या फ्लैगमैन यातायात निर्देशित कर रहा हो","जब बस में कोई यात्री न हो","जब बस 40 फीट से अधिक लंबी हो"],"explanation":"इलिनॉय CDL हैंडबुक के अनुसार बस को स्ट्रीटकार क्रॉसिंग पर, जहाँ कोई पुलिसकर्मी या फ्लैगमैन यातायात निर्देशित कर रहा हो, या जब ट्रैफ़िक सिग्नल हरा दिखा रहा हो, तो रुकने की आवश्यकता नहीं है, लेकिन गति कम करनी चाहिए और सावधानी से जाँच करनी चाहिए। स्रोत: Illinois SOS CDL Study Guide, उपधारा 4.3.5।"},"77":{"q":"चूँकि इलिनॉय का भू-भाग काफ़ी हद तक समतल है, पारंपरिक गुरुत्वाकर्षण-शैली के रनअवे ट्रक एस्केप रैंप असामान्य हैं। इलिनॉय में किसी लंबी ढलान या पुल पहुँच मार्ग से उतर रहे CDL चालक के लिए इसका क्या अर्थ है?","options":["वे किसी भी ढलान के निचले हिस्से पर एस्केप रैंप मिलने पर भरोसा कर सकते हैं","उन्हें एस्केप रैंप पर निर्भर नहीं रहना चाहिए और उचित ब्रेकिंग व गियरिंग से गति को नियंत्रित करना चाहिए","इलिनॉय कानून सभी ढलानों पर इंजन ब्रेक के उपयोग को मना करता है","हर इलिनॉय इंटरस्टेट डाउनग्रेड पर एस्केप रैंप अनिवार्य हैं"],"explanation":"पहाड़ी राज्यों के विपरीत, इलिनॉय का समतल भू-भाग होने का अर्थ है कि एस्केप रैंप दुर्लभ हैं, इसलिए चालकों को रनअवे रैंप की अपेक्षा करने के बजाय उचित निचले गियर और ब्रेकिंग तकनीक से ढलानों को संभालना चाहिए। स्रोत: Illinois SOS CDL Study Guide, उपधारा 2.16 (Mountain Driving / ढलानों पर गति नियंत्रण)।"},"78":{"q":"किसी दो-लेन वाले अविभाजित राजमार्ग पर, किसी भी दिशा में चल रहे, रुकी हुई स्कूल बस के पास पहुँच रहे इलिनॉय चालक को क्या करना चाहिए?","options":["बस के पास से कम गति पर आगे बढ़ते रहें","बस तक पहुँचने से पहले रुकें और तब तक रुके रहें जब तक संकेत बंद न हो जाएँ","केवल तभी रुकें जब बस के समान दिशा से पास आ रहे हों","हॉर्न बजाने के बाद बाईं ओर से गुज़रें"],"explanation":"दो-लेन वाले अविभाजित राजमार्ग पर विभाजित-राजमार्ग अपवाद लागू नहीं होता, इसलिए किसी भी दिशा से पास आ रहे चालकों को अपने लाल संकेत दिखा रही स्कूल बस से मिलने या उसे ओवरटेक करने से पहले रुकना चाहिए और तब तक रुके रहना चाहिए जब तक संकेत बंद न हो जाएँ और बस फिर से चलना शुरू न कर दे। स्रोत: 625 ILCS 5/11-1414(a) और (b)।"},"79":{"q":"इलिनॉय में, कौन सी राज्य एजेंसी कमर्शियल ड्राइवर लाइसेंस जारी करती है और CDL ज्ञान व कौशल परीक्षण प्रशासित करती है?","options":["Illinois Secretary of State","Illinois Department of Transportation (IDOT)","Illinois State Police","Illinois Department of Motor Vehicles"],"explanation":"इलिनॉय में कोई 'DMV' नहीं है; Office of the Illinois Secretary of State (SOS) राज्य का ड्राइवर-लाइसेंसिंग प्राधिकरण है जो CDL जारी करता है और अपनी Driver Services CDL सुविधाओं पर परीक्षण प्रशासित करता है। स्रोत: Illinois SOS CDL Study Guide (DSD CDL) और ilsos.gov CDL पेज।"},"80":{"q":"एक इलिनॉय आवेदक CDL ज्ञान परीक्षण और कौशल (ड्राइव) परीक्षण कहाँ देता है?","options":["किसी Secretary of State Driver Services CDL सुविधा पर","किसी भी स्थानीय Illinois State Police पोस्ट पर","केवल किसी FMCSA संघीय परीक्षण केंद्र पर","किसी Illinois Department of Transportation वज़न स्टेशन पर"],"explanation":"CDL लिखित और कौशल परीक्षण Secretary of State द्वारा नामित Driver Services CDL सुविधाओं पर आयोजित किया जाता है। स्रोत: Illinois SOS CDL Study Guide और ilsos.gov CDL परीक्षण/शेड्यूलिंग पेज।"},"81":{"q":"एक इलिनॉय CDL/CLP आवेदक को अपने द्वारा संचालित वाणिज्य के प्रकार की घोषणा करते समय कितनी स्व-प्रमाणन श्रेणियों में से चुनना होता है?","options":["चार","दो","तीन","पाँच"],"explanation":"इलिनॉय संघीय CDL नियम का पालन करता है जिसके लिए चालकों को चार श्रेणियों में से एक में स्व-प्रमाणित होना आवश्यक है: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। स्रोत: Illinois SOS CDL Study Guide; 49 CFR 383.71।"},"82":{"q":"एक इलिनॉय चालक जो राज्य की सीमाओं के पार संचालन करता है और संघीय शारीरिक-योग्यता नियमों से छूट प्राप्त नहीं है, उसे किस श्रेणी के रूप में स्व-प्रमाणित होना चाहिए?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"अंतरराज्यीय वाणिज्य में एक चालक जिसे संघीय DOT चिकित्सा मानकों को पूरा करना आवश्यक है, वह Non-Excepted Interstate (NI) के रूप में स्व-प्रमाणित होता है और उसे एक वैध medical examiner's certificate बनाए रखना चाहिए। स्रोत: Illinois SOS CDL Study Guide; 49 CFR 383.71।"},"83":{"q":"कौन सी स्व-प्रमाणन श्रेणी ऐसे इलिनॉय चालक पर लागू होती है जो केवल इलिनॉय के भीतर संचालन करता है और जिसे चिकित्सा प्रमाणन आवश्यकताओं को पूरा करना आवश्यक नहीं है?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"explanation":"केवल अंतःराज्यीय (इलिनॉय के भीतर) वाणिज्य में संचालन करने वाला एक चालक जिसे चिकित्सा प्रमाणन आवश्यकताओं को पूरा नहीं करना पड़ता, वह Excepted Intrastate (EA) के रूप में स्व-प्रमाणित होता है। स्रोत: Illinois SOS CDL Study Guide; 49 CFR 383.71।"},"84":{"q":"कौन सा संघीय फ़ॉर्म Medical Examiner's Certificate है जिसे एक इलिनॉय Non-Excepted Interstate CDL धारक को वर्तमान बनाए रखना चाहिए?","options":["Form MCSA-5876","Form MCSA-5875","Form SS-CDL-2","Form DL-180"],"explanation":"आधिकारिक Medical Examiner's Certificate FMCSA Form MCSA-5876 है, जो एक प्रमाणित चिकित्सा परीक्षक द्वारा जारी किया जाता है। Non-excepted चालकों को राज्य के पास एक वैध प्रमाणपत्र फ़ाइल में रखना चाहिए। स्रोत: FMCSA; Illinois SOS CDL पेज।"},"85":{"q":"इलिनॉय में 2025 के बदलाव के अनुसार, एक CDL धारक का Medical Examiner's Certificate सामान्यतः Secretary of State तक कैसे पहुँचता है?","options":["प्रमाणित चिकित्सा परीक्षक इसे FMCSA National Registry के माध्यम से इलेक्ट्रॉनिक रूप से जमा करता है","चालक एक कागज़ी प्रति Secretary of State को डाक से भेजता है","चालक इसे 15 दिनों के भीतर किसी CDL सुविधा पर फ़ैक्स करता है","चालक कागज़ी कार्ड किसी भी CDL सुविधा पर हाथ से सौंपता है"],"explanation":"इलिनॉय के FMCSA National Registry एकीकरण में शामिल होने (मध्य-2025) के साथ प्रभावी, प्रमाणित चिकित्सा परीक्षक परीक्षा परिणामों को इलेक्ट्रॉनिक रूप से FMCSA को भेजते हैं, जो उन्हें SOS को प्रदान करता है; राज्य अब CDL सुविधाओं पर कागज़ी चिकित्सा कार्ड स्वीकार नहीं करता। स्रोत: Illinois SOS CDL पेज; FMCSA National Registry।"},"86":{"q":"एक इलिनॉय Non-Excepted Interstate CDL धारक को आम तौर पर कितनी बार स्व-प्रमाणन अपडेट करना और एक वर्तमान चिकित्सा प्रमाणपत्र प्रदान करना चाहिए?","options":["कम से कम हर 2 वर्ष में (या उससे पहले यदि प्रमाणपत्र की समाप्ति अवधि कम हो)","लाइसेंस नवीनीकरण के साथ हर 5 वर्ष में","लाइसेंस नवीनीकरण के साथ हर 4 वर्ष में","केवल एक बार, आरंभिक लाइसेंसिंग पर"],"explanation":"एक Medical Examiner's Certificate अधिकतम 2 वर्षों के लिए वैध होता है (यदि परीक्षक निर्दिष्ट करे तो कम), इसलिए non-excepted अंतरराज्यीय चालकों को 4-वर्षीय लाइसेंस चक्र से स्वतंत्र रूप से, कम से कम 2-वर्षीय चक्र पर वर्तमान चिकित्सा प्रमाणन बनाए रखना चाहिए। स्रोत: Illinois SOS CDL पेज; 49 CFR 391.45।"},"87":{"q":"इलिनॉय में CDL कौशल परीक्षण के लिए शेड्यूल किए जाने से पहले, आरंभिक Class A या Class B के आवेदक को कौन सी प्रशिक्षण आवश्यकता पूरी करनी चाहिए?","options":["किसी FMCSA-पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक 30-घंटे का इलिनॉय रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक Illinois Secretary of State कक्षा सुरक्षा सेमिनार","6 महीने की राज्य-प्रशासित प्रशिक्षुता"],"explanation":"इलिनॉय में अपनाए गए संघीय ELDT नियमों के अनुसार आरंभिक Class A/Class B आवेदकों (और कुछ अपग्रेड/एंडोर्समेंट) को परीक्षण से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training पूरी करनी होती है। स्रोत: Illinois SOS ELDT पेज; 49 CFR Part 380।"},"88":{"q":"इलिनॉय ELDT आवश्यकता के तहत, प्रशिक्षण का सैद्धांतिक भाग किस चरण से पहले पूरा किया जाना चाहिए?","options":["नई श्रेणी या एंडोर्समेंट के लिए CDL ज्ञान (लिखित) परीक्षण देने से पहले","एक आधार इलिनॉय ड्राइवर लाइसेंस के लिए आवेदन करने से पहले","एक मौजूदा गैर-CDL लाइसेंस का नवीनीकरण करने से पहले","एक दृष्टि जाँच शेड्यूल करने से पहले"],"explanation":"इलिनॉय के अनुसार आरंभिक Class A या B CDL, एक अपग्रेड, या एक आरंभिक S, P, या H एंडोर्समेंट चाहने वाले आवेदकों को संबंधित ज्ञान परीक्षण देने से पहले एक पंजीकृत प्रदाता से ELDT सैद्धांतिक प्रशिक्षण पूरा करना आवश्यक है। स्रोत: Illinois SOS ELDT पेज; 49 CFR Part 380।"},"89":{"q":"इनमें से किस एंडोर्समेंट के लिए इलिनॉय आवेदक के परीक्षण से पहले ELDT पूरा करना आवश्यक है?","options":["Passenger (P), School bus (S), और Hazardous materials (H)","केवल Double/triple trailers (T)","केवल Tank vehicle (N)","इलिनॉय में किसी भी एंडोर्समेंट के लिए ELDT आवश्यक नहीं है"],"explanation":"ELDT आरंभिक Class A/B लाइसेंस और अपग्रेड के अलावा, School bus (S), Passenger (P), और Hazardous materials (H) एंडोर्समेंट के आरंभिक जारी होने पर लागू होता है। स्रोत: Illinois SOS ELDT पेज; 49 CFR Part 380।"},"90":{"q":"CDL कौशल परीक्षण देने से पहले व्हील-के-पीछे अभ्यास की अनुमति देने वाले चरण के रूप में एक इलिनॉय चालक को सबसे पहले क्या प्राप्त करना चाहिए?","options":["एक Commercial Learner's Permit (CLP)","एक अस्थायी अंतरराज्यीय छूट","एक अनंतिम वाणिज्यिक एंडोर्समेंट कार्ड","एक FMCSA रोड-टेस्ट छूट"],"explanation":"आवश्यक ज्ञान परीक्षण(ओं) को पास करने के बाद, आवेदक को एक Commercial Learner's Permit (CLP) जारी किया जाता है, जो कौशल परीक्षण से पहले एक प्रतिनिधि वाहन में पर्यवेक्षित अभ्यास को अधिकृत करता है। स्रोत: Illinois SOS CDL Study Guide; 49 CFR 383.25।"},"91":{"q":"एक इलिनॉय CLP जारी होने के बाद, धारक को CDL कौशल परीक्षण देने की अनुमति मिलने से पहले कितने समय तक प्रतीक्षा करनी चाहिए?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कोई प्रतीक्षा अवधि नहीं है"],"explanation":"इलिनॉय द्वारा अपनाया गया संघीय कानून कौशल परीक्षण प्रशासित किए जाने से पहले CLP जारी होने की तारीख से न्यूनतम 14-दिन की होल्ड आवश्यक करता है; एक आवेदक पहले से शेड्यूल कर सकता है लेकिन 14 दिनों के भीतर की तारीख नहीं चुन सकता। स्रोत: Illinois SOS CDL पेज; 49 CFR 383.25।"},"92":{"q":"इलिनॉय CDL कौशल परीक्षण तीन भागों में दिया जाता है। उन्हें प्रशासित किए जाने का सही क्रम क्या है?","options":["प्री-ट्रिप (वाहन) निरीक्षण, फिर बेसिक कंट्रोल स्किल्स, फिर ऑन-रोड ड्राइव परीक्षण","ऑन-रोड ड्राइव परीक्षण, फिर बेसिक कंट्रोल स्किल्स, फिर प्री-ट्रिप निरीक्षण","बेसिक कंट्रोल स्किल्स, फिर ऑन-रोड ड्राइव परीक्षण, फिर प्री-ट्रिप निरीक्षण","प्री-ट्रिप निरीक्षण, फिर ऑन-रोड ड्राइव परीक्षण, फिर बेसिक कंट्रोल स्किल्स"],"explanation":"कौशल परीक्षण इस क्रम में आयोजित किया जाता है: (1) प्री-ट्रिप (वाहन) निरीक्षण, (2) बेसिक कंट्रोल स्किल्स, और (3) ऑन-रोड ड्राइव परीक्षण। स्रोत: Illinois SOS CDL Study Guide और ilsos.gov CDL पेज।"},"93":{"q":"इलिनॉय कौशल परीक्षण के प्री-ट्रिप निरीक्षण भाग के दौरान, आवेदक को मुख्य रूप से किस क्षमता का प्रदर्शन करना चाहिए:","options":["उन घटकों की पहचान करना जिन्हें जाँचा जाना चाहिए और यह समझाना कि प्रत्येक सुरक्षित संचालन के लिए क्यों महत्वपूर्ण है","ब्रेक प्रणाली को अलग करना और फिर से जोड़ना","पूरे Illinois Vehicle Code को याद से सुनाना","एक निश्चित समय सीमा के भीतर टायर बदलना"],"explanation":"वाहन निरीक्षण परीक्षण के लिए आवेदक को वस्तुओं का पता लगाना, यह बताना कि क्या जाँचा जा रहा है, और यह समझाना आवश्यक है कि वह जाँच सुरक्षित संचालन के लिए क्यों मायने रखती है। स्रोत: Illinois SOS CDL Study Guide (धारा 11, Vehicle Inspection Test)।"},"94":{"q":"निम्नलिखित में से कौन सा इलिनॉय CDL कौशल परीक्षण के बेसिक कंट्रोल स्किल्स भाग का हिस्सा है?","options":["नियंत्रित बैकिंग पैंतरेबाज़ी जैसे सीधी-रेखा और ऑफ़सेट बैकिंग","पूरी गति से किसी इंटरस्टेट राजमार्ग पर विलय करना","50 लिखित बहुविकल्पीय प्रश्नों का उत्तर देना","ट्रेलर पर एक खतरनाक सामग्री प्लेकार्ड जोड़ना"],"explanation":"बेसिक कंट्रोल स्किल्स सीधी-रेखा बैकिंग, ऑफ़सेट बैकिंग, और पार्किंग जैसी पैंतरेबाज़ियों के माध्यम से, आम तौर पर एक रेंज पर, सटीक कम-गति वाहन नियंत्रण का मूल्यांकन करता है। स्रोत: Illinois SOS CDL Study Guide (Basic Vehicle Control Skills Test)।"},"95":{"q":"प्रत्येक इलिनॉय CDL ज्ञान (लिखित) परीक्षण को पास करने के लिए एक आवेदक को न्यूनतम कितना स्कोर प्राप्त करना चाहिए?","options":["80% सही","70% सही","75% सही","90% सही"],"explanation":"इलिनॉय CDL ज्ञान परीक्षणों के लिए पास होने हेतु न्यूनतम 80% सही आवश्यक है, जो संघीय मानक के अनुरूप है। स्रोत: Illinois SOS CDL Study Guide; 49 CFR 383.135।"},"96":{"q":"सामान्य आयु सीमा वाले चालक के लिए इलिनॉय कमर्शियल ड्राइवर लाइसेंस का मानक नवीनीकरण चक्र क्या है?","options":["हर 4 वर्ष में","हर 2 वर्ष में","हर 5 वर्ष में","हर 8 वर्ष में"],"explanation":"एक मानक इलिनॉय CDL 4-वर्षीय चक्र पर जारी किया जाता है, जो आम तौर पर धारक के जन्मदिन पर समाप्त होता है; नवीनीकरण के लिए वर्तमान स्व-प्रमाणन और, non-excepted चालकों के लिए, वैध चिकित्सा प्रमाणन भी आवश्यक है। स्रोत: Illinois SOS CDL पेज और Driver Services नवीनीकरण जानकारी।"},"97":{"q":"केवल अंतःराज्यीय ड्राइविंग की तुलना में, अंतरराज्यीय वाणिज्य में ड्राइव करने या यात्रियों को ले जाने के लिए इलिनॉय CDL के लिए आवेदन करने की न्यूनतम आयु क्या है?","options":["अंतरराज्यीय या यात्रियों के लिए 21; केवल अंतःराज्यीय के लिए 18","अंतरराज्यीय या यात्रियों के लिए 18; केवल अंतःराज्यीय के लिए 16","अंतरराज्यीय या यात्रियों के लिए 25; केवल अंतःराज्यीय के लिए 21","अंतरराज्यीय और अंतःराज्यीय दोनों के लिए 21"],"explanation":"एक आवेदक को अंतरराज्यीय वाणिज्य में संचालन करने या यात्रियों को ले जाने के लिए कम से कम 21 वर्ष का होना चाहिए, और केवल-अंतःराज्यीय संचालन के लिए CDL/CLP प्राप्त करने हेतु कम से कम 18 वर्ष का होना चाहिए। स्रोत: Illinois SOS CDL Study Guide और ilsos.gov CDL पेज।"}},"ar":{"0":{"q":"على الطرق السريعة في إلينوي، ما هو الحد الأقصى لعرض المركبة التجارية، باستثناء أجهزة السلامة والمرايا المعتمدة؟","options":["8 أقدام و6 بوصات (102 inches)","8 أقدام و0 بوصة (96 inches)","9 أقدام و0 بوصة (108 inches)","10 أقدام و0 بوصة (120 inches)"],"explanation":"تحدّ إلينوي عرض المركبة بـ 8 أقدام و6 بوصات (102 inches)، دون احتساب المرايا وأجهزة السلامة المعتمدة الأخرى. المصدر: 625 ILCS 5/15-102؛ دليل CDL/قواعد الطريق في إلينوي."},"1":{"q":"ما هو الحد الأقصى لارتفاع المركبة، بما في ذلك حمولتها، المسموح به على الطرق السريعة في إلينوي؟","options":["13 قدمًا و6 بوصات","13 قدمًا و0 بوصة","14 قدمًا و0 بوصة","12 قدمًا و6 بوصات"],"explanation":"تحدّ إلينوي الارتفاع الإجمالي، مقاسًا من سطح الطريق إلى أعلى الحمولة، بـ 13 قدمًا و6 بوصات. المصدر: 625 ILCS 5/15-103."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي لتركيبة مركبات من خمسة محاور أو أكثر تعمل على الطرق السريعة في إلينوي دون تصريح؟","options":["80,000 pounds","73,280 pounds","84,000 pounds","88,000 pounds"],"explanation":"تعتمد إلينوي الحد الأقصى الفيدرالي البالغ 80,000 pounds للوزن الإجمالي لتركيبات من خمسة محاور أو أكثر. المصدر: 625 ILCS 5/15-111."},"3":{"q":"ما هو الحد الأقصى للوزن المسموح به على محور واحد على الطرق السريعة في إلينوي؟","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"تحدّ إلينوي المحور الواحد بـ 20,000 pounds، بما يطابق المعيار الفيدرالي. المصدر: 625 ILCS 5/15-111."},"4":{"q":"ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور مزدوجة (تاندم) على الطرق السريعة في إلينوي؟","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"تحدّ إلينوي المحور المزدوج (التاندم) بـ 34,000 pounds، على ألا يتجاوز أي محور واحد ضمن التاندم 20,000 pounds. المصدر: 625 ILCS 5/15-111."},"5":{"q":"ما هو الحد الأقصى لطول الشاحنة المستقيمة (الصلبة) المفردة على الطرق السريعة في إلينوي؟","options":["42 feet","40 feet","45 feet","53 feet"],"explanation":"لا يجوز أن تتجاوز المركبة المفردة، مثل الشاحنة المستقيمة، 42 feet في الطول الإجمالي في إلينوي. المصدر: 625 ILCS 5/15-107."},"6":{"q":"على نظام الطرق السريعة المخصص (الشبكة الوطنية) في إلينوي، ما هو الحد الأقصى لطول المقطورة النصفية المفردة المشغّلة ضمن تركيبة جرّار-مقطورة نصفية؟","options":["53 feet","48 feet","57 feet","60 feet"],"explanation":"تسمح إلينوي بالمقطورات النصفية حتى 53 feet ضمن تركيبة جرّار-مقطورة نصفية، بما يتوافق مع معيار الشبكة الوطنية الفيدرالية. المصدر: 625 ILCS 5/15-107."},"7":{"q":"ما هي الصيغة التي تستخدمها إلينوي لتحديد الحد الأقصى المسموح به للوزن الإجمالي بناءً على تباعد المحاور وعددها؟","options":["صيغة الجسر الفيدرالية (صيغة الوزن-المسافة)","صيغة تصنيف الوزن الإجمالي المركّب","صيغة مؤشر حمل الإطار","صيغة فئة الوزن المسجّل"],"explanation":"تستخدم إلينوي صيغة الجسر الفيدرالية، W = 500[(LN/(N-1)) + 12N + 36]، لتحديد الحد الأقصى للوزن الإجمالي حسب تباعد المحاور (L) وعدد المحاور (N). المصدر: 625 ILCS 5/15-111."},"8":{"q":"في إلينوي، من الذي يصدر تصريح الولاية للحمولات الزائدة الحجم/الوزن لحمولة تتجاوز حدود الحجم أو الوزن القانونية على طريق سريع تتولى الولاية صيانته؟","options":["وزارة النقل في إلينوي (IDOT)","وزير خارجية إلينوي","شرطة ولاية إلينوي","الإدارة الفيدرالية لسلامة الناقلات بالمركبات الآلية"],"explanation":"تصدر IDOT تصاريح الحمولات الزائدة الحجم/الوزن للتنقلات على الطرق السريعة التي تتولى الولاية صيانتها بموجب سلطتها التشريعية. المصدر: 625 ILCS 5/15-301؛ تصاريح الحمولات الزائدة الحجم/الوزن لدى IDOT."},"9":{"q":"يُطلب عمومًا تصريح إلينوي للحمولات الزائدة الحجم/الوزن عندما تتجاوز المركبة أو الحمولة أيًّا مما يلي؟","options":["عرض 8 أقدام و6 بوصات، أو ارتفاع 13 قدمًا و6 بوصات، أو وزن إجمالي 80,000 pounds","عرض 8 أقدام و0 بوصة، أو ارتفاع 13 قدمًا و0 بوصة، أو وزن إجمالي 73,280 pounds","عرض 9 أقدام و0 بوصة، أو ارتفاع 14 قدمًا و0 بوصة، أو وزن إجمالي 84,000 pounds","عرض 10 أقدام و0 بوصة، أو ارتفاع 15 قدمًا و0 بوصة، أو وزن إجمالي 90,000 pounds"],"explanation":"عندما تتجاوز الحمولة الحدود القانونية (أكثر من 8'6\" عرضًا، أو أكثر من 13'6\" ارتفاعًا، أو أكثر من الطول القانوني، أو أكثر من 80,000 lb وزنًا إجماليًا)، يلزم تصريح من IDOT لنقلها على الطرق السريعة للولاية. المصدر: 625 ILCS 5/15-301؛ IDOT."},"10":{"q":"ما هو الحد الأقصى للحمولة الذي تسمح به إلينوي لكل بوصة من عرض الإطار (للإطار الملامس للطريق)؟","options":["800 pounds لكل بوصة من عرض الإطار","500 pounds لكل بوصة من عرض الإطار","1,000 pounds لكل بوصة من عرض الإطار","600 pounds لكل بوصة من عرض الإطار"],"explanation":"تحدّ إلينوي الحمولة بـ 800 pounds لكل بوصة من عرض الإطار لحماية الرصيف، إضافةً إلى حدود وزن المحاور. المصدر: 625 ILCS 5/15-111."},"11":{"q":"ما هو النظام الإلكتروني الذي تستخدمه IDOT للتقدّم بطلبات تصاريح الحمولات الزائدة الحجم/الوزن وتصاريح الحصاد في إلينوي؟","options":["ITAP (نظام تصاريح النقل الآلية في إلينوي)","IRP (بوابة خطة التسجيل الدولية)","CDLIS (نظام معلومات رخصة القيادة التجارية)","SAFER (السجلات الإلكترونية للسلامة واللياقة)"],"explanation":"يتقدّم مقدّمو الطلبات عبر نظام ITAP التابع لـ IDOT، الذي يوفّر وصولًا إلكترونيًا على مدار الساعة طوال أيام الأسبوع لتصاريح الحمولات الزائدة الحجم/الوزن وتصاريح الحصاد. المصدر: تصاريح الحمولات الزائدة الحجم/الوزن لدى IDOT (webapps.dot.illinois.gov/ITAP)."},"12":{"q":"بأي نسبة مئوية تقريبًا فوق الحدود القانونية يسمح تصريح الحصاد المجاني في إلينوي للمركبة بتجاوز الأوزان الإجمالية وأوزان المحاور والأوزان المسجّلة خلال موسم الحصاد؟","options":["حتى 10 percent","حتى 5 percent","حتى 15 percent","حتى 25 percent"],"explanation":"يسمح تصريح الحصاد في إلينوي بما يصل إلى 10 percent فوق الأوزان الإجمالية وأوزان المحاور والأوزان المسجّلة القانونية لنقل المنتجات الزراعية خلال الحصاد. المصدر: تصريح الحصاد لدى IDOT؛ مكتب مزارعي إلينوي."},"13":{"q":"على أي طرق يسمح تصريح الحصاد في إلينوي الصادر عن IDOT بالتنقّل الزراعي ذي الوزن الزائد؟","options":["الطرق التي تتولى الولاية صيانتها فقط (وليس الطرق السريعة بين الولايات أو الطرق المحلية ما لم يُصرَّح بذلك بشكل منفصل)","جميع الطرق السريعة بين الولايات داخل إلينوي","أي طريق عام في إلينوي، بما في ذلك طرق البلدات المحلية","فقط طرق المقاطعات والبلدات، وليس طرق الولاية أبدًا"],"explanation":"يشمل تصريح الحصاد الصادر عن IDOT طرق الولاية فقط؛ فهو لا يصرّح بالتنقّل بين الولايات، والطرق المحلية تتطلب تصريحًا محليًا منفصلًا. المصدر: تصريح الحصاد لدى IDOT؛ مكتب مزارعي إلينوي."},"14":{"q":"كم تبلغ تكلفة تصريح الحصاد القياسي في إلينوي على المزارع المؤهّل أو الناقل الزراعي؟","options":["إنه مجاني","$15 لكل مركبة","$100 لكل موسم","$50 لكل تصريح طريق"],"explanation":"تقدّم إلينوي تصريح الحصاد مجانًا للناقلين الزراعيين المؤهّلين، ويُحصَل عليه عبر نظام ITAP التابع لـ IDOT. المصدر: تصريح الحصاد لدى IDOT؛ مكتب مزارعي إلينوي."},"15":{"q":"ما هو السماح الإضافي للوزن الإجمالي الذي تمنحه إلينوي لمركبة تعمل أساسًا بالغاز الطبيعي (لتعويض نظام الوقود الأثقل)، وأين لا ينطبق؟","options":["حتى 2,000 pounds إضافية، ولكن ليس على نظام الطرق السريعة بين الولايات","حتى 5,000 pounds إضافية على جميع الطرق السريعة بما في ذلك الطرق بين الولايات","حتى 1,000 pounds إضافية على الطرق المحلية فقط","حتى 4,000 pounds إضافية على الطرق بين الولايات فقط"],"explanation":"تسمح إلينوي بما يصل إلى 2,000 pounds من الوزن الإجمالي الإضافي للمركبات التي تعمل بالغاز الطبيعي، باستثناء الطرق السريعة بين الولايات. المصدر: 625 ILCS 5/15-111."},"16":{"q":"ضمن مجموعة محاور مزدوجة (تاندم) قانونية في إلينوي، لا يجوز أن يتجاوز أي محور واحد من التاندم أي وزن؟","options":["20,000 pounds","17,000 pounds","18,000 pounds","22,000 pounds"],"explanation":"رغم أن التاندم قد يحمل 34,000 pounds إجمالًا، لا يجوز أن يتجاوز أي محور واحد ضمن ذلك التاندم 20,000 pounds. المصدر: 625 ILCS 5/15-111."},"17":{"q":"في صيغة الجسر الفيدرالية W = 500[(LN/(N-1)) + 12N + 36] المستخدمة في إلينوي، ماذا يمثّل المتغيّر 'L'؟","options":["المسافة بالأقدام بين المحاور الطرفية (الخارجية) للمجموعة التي يجري قياسها","الطول الإجمالي للمقطورة بالأقدام","الحد القانوني للحمولة لكل إطار","الوزن الإجمالي المرخّص للمركبة"],"explanation":"في صيغة الجسر، L هي المسافة بالأقدام بين المحاور الطرفية للمجموعة، وN هي عدد المحاور، وW هي الحد الأقصى المسموح به للوزن. المصدر: 625 ILCS 5/15-111."},"18":{"q":"لا يجوز لسلطة محلية في إلينوي أن تنشر وتسمح بأوزان إجمالية أعلى من الحد القانوني على طريق سريع يقع ضمن اختصاصها إلا إذا قامت بماذا؟","options":["وضع لافتات تنظيمية مناسبة تُشعِر بذلك، دون تجاوز الحدود القصوى للمحور الواحد أو المزدوج","الحصول على موافقة خطية من الإدارة الفيدرالية للطرق السريعة","رفع الحد الأقصى للمحور الواحد إلى 24,000 pounds","إلغاء صيغة الجسر الفيدرالية بالكامل لذلك الطريق"],"explanation":"يجوز للسلطات المحلية السماح بأحمال متزايدة على الطرق السريعة المحلية المخصصة فقط عند وضع لافتات تنظيمية مناسبة، ومع ذلك لا يمكنها تجاوز الحدود القصوى للمحور الواحد أو المزدوج. المصدر: 625 ILCS 5/15-111 والأحكام ذات الصلة بسلطة الجهات المحلية."},"19":{"q":"سائق ينقل حمولة بعرض 9 أقدام وارتفاع 14 قدمًا عبر طريق سريع تابع لولاية إلينوي دون تصريح. ما هو التوصيف الصحيح لهذا التنقّل؟","options":["إنه غير قانوني؛ فكل من العرض (أكثر من 8'6\") والارتفاع (أكثر من 13'6\") يتجاوز الحدود القانونية ويتطلب تصريح حمولة زائدة الحجم من IDOT","إنه قانوني لأن الحمولات الزراعية معفاة من جميع حدود الحجم","إنه قانوني لأن الوزن فقط، وليس الأبعاد، هو ما يتطلب تصريحًا","إنه قانوني لأن وزن الحمولة أقل من 80,000 pounds إجماليًا"],"explanation":"تجاوز عرض 8'6\" أو ارتفاع 13'6\" يجعل التنقّل غير قانوني دون تصريح حمولة زائدة الحجم من IDOT؛ وتنطبق حدود الأبعاد بشكل مستقل عن الوزن الإجمالي. المصدر: 625 ILCS 5/15-102 و15-103 و15-301."},"20":{"q":"في إلينوي، أي فئة من CDL مطلوبة لتشغيل تركيبة من المركبات بتصنيف وزن مركّب إجمالي (GCWR) يبلغ 26,001 lbs أو أكثر، حيث يكون للمركبة المقطورة تصنيف وزن إجمالي (GVWR) يزيد على 10,000 lbs؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف إلينوي CDL من الفئة A بأنها تركيبة من المركبات بتصنيف GCWR يبلغ 26,001 lbs أو أكثر، شريطة أن يكون للوحدة المقطورة تصنيف GVWR يزيد على 10,000 lbs. المصدر: دليل دراسة CDL لدى Illinois SOS / صفحة فئات CDL على ilsos.gov؛ 92 Ill. Admin. Code 1030."},"21":{"q":"بموجب قواعد إلينوي، يخوّل CDL من الفئة B تشغيل أيٍّ مما يلي؟","options":["أي مركبة مفردة بتصنيف GVWR يبلغ 26,001 lbs أو أكثر (تقطر وحدة لا تتجاوز 10,000 lbs)","أي تركيبة تقطر وحدة تزيد على 10,000 lbs","فقط المركبات الأقل من 16,000 lbs GVWR","فقط المركبات المصمّمة لنقل 16 راكبًا أو أكثر"],"explanation":"تعرّف إلينوي CDL من الفئة B بأنها أي مركبة مفردة بتصنيف GVWR يبلغ 26,001 lbs أو أكثر، أو هذه المركبة وهي تقطر مركبة أخرى لا تتجاوز 10,000 lbs (مثل الشاحنات المستقيمة والحافلات الكبيرة). المصدر: دليل دراسة CDL لدى Illinois SOS / ilsos.gov."},"22":{"q":"يرغب سائق في إلينوي بتشغيل شاحنة صغيرة (فان) مصمّمة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) ويبلغ وزنها أقل من 26,001 lbs. أي فئة CDL تنطبق؟","options":["الفئة C","الفئة A","الفئة B","لا حاجة إلى CDL"],"explanation":"تشمل الفئة C في إلينوي أي مركبة لا تستوفي شروط الفئة A أو B وتكون مصمّمة لنقل 16 راكبًا أو أكثر بما في ذلك السائق، أو تنقل مواد خطرة تستلزم وضع لافتات. المصدر: دليل دراسة CDL لدى Illinois SOS / ilsos.gov."},"23":{"q":"ما هي مصادقة CDL المطلوبة في إلينوي لقيادة مركبة تنقل مواد خطرة بكميات تستلزم وضع لافتات؟","options":["H (HazMat)","N (صهريج)","T (مقطورات مزدوجة/ثلاثية)","P (ركّاب)"],"explanation":"تُطلب مصادقة H لأي مركبة تنقل مواد خطرة تستلزم وضع لافتات. تتطلب إلينوي إضافةً إلى ذلك تقييمًا أمنيًا للتهديدات من TSA وتدريب ELDT قبل اختبار المعرفة الخاص بـ H. المصدر: صفحة مصادقة المواد الخطرة على ilsos.gov."},"24":{"q":"في إلينوي، ما هي المصادقة المطلوبة لتشغيل مركبة صهريج تنقل سوائل أو غازات بالجملة؟","options":["N (صهريج)","H (HazMat)","T (مقطورات مزدوجة/ثلاثية)","S (حافلة مدرسية)"],"explanation":"تخوّل مصادقة N تشغيل مركبة صهريج تنقل السوائل أو الغازات. وتتطلب اجتياز اختبار المعرفة الخاص بمركبات الصهاريج. المصدر: دليل دراسة CDL لدى Illinois SOS / مصادقات ilsos.gov."},"25":{"q":"لا يجوز إضافة مصادقة T في إلينوي (المقطورات المزدوجة/الثلاثية) إلا إلى أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","أي فئة"],"explanation":"في إلينوي تنطبق مصادقة T (المقطورات المزدوجة/الثلاثية) على CDL من الفئة A فقط، لأن قطر أكثر من مقطورة واحدة يتطلب رخصة تركيبة. ملاحظة: المقطورات الثلاثية ليست قانونية على الطرق السريعة في إلينوي. المصدر: مواد CDL لدى Illinois SOS / مصادقات ilsos.gov."},"26":{"q":"أي عبارة عن المقطورات الثلاثية في إلينوي صحيحة؟","options":["المقطورات الثلاثية غير مسموح بها على الطرق السريعة في إلينوي","المقطورات الثلاثية مسموح بها فقط على الطرق بين الولايات","المقطورات الثلاثية مسموح بها مع مصادقة P","المقطورات الثلاثية تتطلب فقط CDL من الفئة B"],"explanation":"رغم أن المصادقة تُسمّى المقطورات المزدوجة/الثلاثية (T)، فإن قانون إلينوي لا يسمح بتركيبات المقطورات الثلاثية على طرقه السريعة. المصدر: معلومات مصادقة CDL لدى Illinois SOS / ilsos.gov."},"27":{"q":"في إلينوي، ما هي المصادقة المطلوبة لقيادة مركبة مصمّمة لنقل 16 راكبًا أو أكثر، بما في ذلك السائق؟","options":["P (ركّاب)","S (حافلة مدرسية)","N (صهريج)","T (مقطورات مزدوجة/ثلاثية)"],"explanation":"تُطلب مصادقة P (الركّاب) لتشغيل مركبة مصمّمة لنقل 16 شخصًا أو أكثر بما في ذلك السائق؛ وهي تتطلب اختبار معرفة واختبار مهارات في مركبة تمثيلية. المصدر: دليل دراسة CDL لدى Illinois SOS / ilsos.gov."},"28":{"q":"لقيادة حافلة مدرسية صفراء تنقل الطلاب (حتى الصف الثاني عشر وما دونه) في إلينوي، يحتاج السائق إلى أي مصادقة إضافةً إلى CDL؟","options":["S (حافلة مدرسية)","P فقط","N (صهريج)","H (HazMat)"],"explanation":"تُطلب مصادقة S (الحافلة المدرسية) لنقل الطلاب من وإلى المدرسة أو الأنشطة المدرسية؛ وتتطلب إلينوي اختبار معرفة ومهارات واختبار قيادة (وتُعدّ مصادقة P أيضًا شرطًا مسبقًا). المصدر: مصادقة الحافلة المدرسية على ilsos.gov."},"29":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL أو CLP في إلينوي للعمل داخل إلينوي فقط (ضمن الولاية)؟","options":["18","21","19","16"],"explanation":"تتطلب إلينوي أن يكون عمر مقدّم الطلب 18 على الأقل للحصول على CDL/CLP للعمل ضمن الولاية. المصدر: صفحة CDL/CLP على ilsos.gov؛ 625 ILCS 5/6-507."},"30":{"q":"ما هو الحد الأدنى للعمر الذي تتطلبه إلينوي لتشغيل مركبة تجارية آلية في التجارة بين الولايات أو لنقل الركّاب؟","options":["21","18","19","25"],"explanation":"تتطلب إلينوي أن يكون عمر السائق 21 على الأقل للعمل في التجارة بين الولايات أو لنقل الركّاب؛ ويقتصر من تتراوح أعمارهم بين 18 و20 على العمل ضمن الولاية. المصدر: صفحة CDL/CLP على ilsos.gov؛ 49 CFR 391.11 كما اعتمدتها إلينوي."},"31":{"q":"بموجب القواعد الفيدرالية التي اعتمدتها إلينوي، كم من الوقت يجب أن يحمل السائق تصريح المتعلّم التجاري (CLP) قبل خوض اختبار مهارات CDL (اختبار الطريق)؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"تتطلب كل من القواعد الفيدرالية وقواعد إلينوي حمل CLP لمدة لا تقل عن 14 يومًا قبل اختبار المهارات؛ ويمكنك الحجز مسبقًا، لكن يجب أن يقع موعد الاختبار بعد فترة الحجز البالغة 14 يومًا. المصدر: صفحة CDL/CLP على ilsos.gov؛ 49 CFR 383.25."},"32":{"q":"ما مدة صلاحية تصريح المتعلّم التجاري (CLP) في إلينوي؟","options":["180 يومًا","90 يومًا","سنة واحدة","30 يومًا"],"explanation":"يكون CLP في إلينوي صالحًا لمدة 180 يومًا، بما يتوافق مع المعيار الفيدرالي لـ CLP. المصدر: صفحة CDL/CLP على ilsos.gov؛ 49 CFR 383.25."},"33":{"q":"لأيٍّ مما يلي تتطلب إلينوي تدريب السائق المبتدئ (ELDT) قبل اختبار المعرفة أو المهارات؟","options":["مصادقة أولية H (HazMat) أو P (ركّاب) أو S (حافلة مدرسية)","فقط مصادقة N (صهريج)","تجديد أي مصادقة قائمة","إضافة مصادقة دراجة نارية"],"explanation":"ينطبق ELDT على الحصول على أول CDL من الفئة A أو B، وعلى الترقية، وعلى مصادقة أولية H أو P أو S. ويجب أن يسبق التدريب النظري للمواد الخطرة (H) اختبار المعرفة الخاص بـ H. المصدر: صفحة ELDT على ilsos.gov؛ 49 CFR Part 380."},"34":{"q":"أي مجموعة من المستندات يجب على مقدّم طلب CLP/CDL في إلينوي تقديمها في منشأة وزير الخارجية؟","options":["إثبات الهوية، وإثبات خطي لرقم الضمان الاجتماعي، وإثبات الوجود القانوني/المشروع، وإثباتان للإقامة في إلينوي","فقط بطاقة الضمان الاجتماعي","فقط جواز سفر أمريكي","فقط فاتورتا خدمات"],"explanation":"تتطلب إلينوي إثبات الهوية، وإثباتًا خطيًا لرقم الضمان الاجتماعي (مثل البطاقة الفعلية أو نموذج W-2؛ لا تُقبل النسخ المصوّرة)، وإثبات الوجود المشروع، وإثباتين للإقامة في إلينوي. المصدر: صفحتا CDL/CLP والوجود القانوني على ilsos.gov."},"35":{"q":"كم عدد إثباتات الإقامة في إلينوي التي يتطلبها وزير الخارجية لطلب CDL/CLP؟","options":["اثنان","واحد","ثلاثة","لا شيء"],"explanation":"تتطلب إلينوي إثباتين مقبولين للإقامة في إلينوي، إضافةً إلى إثبات الهوية ورقم الضمان الاجتماعي والوجود المشروع. المصدر: متطلبات مستندات رخصة القيادة/CDL على ilsos.gov."},"36":{"q":"عند التقدّم بطلب للحصول على CDL في إلينوي، أي فئة من فئات الإقرار الذاتي تتطلب من السائق تقديم شهادة فاحص طبي فيدرالية سارية من DOT؟","options":["غير المستثنى بين الولايات (NI)","المستثنى ضمن الولاية (EA)","المستثنى بين الولايات (EI)","غير المستثنى ضمن الولاية (NA)"],"explanation":"تعترف إلينوي بأربع فئات للإقرار الذاتي (NI وEI وNA وEA). ويجب على السائق غير المستثنى بين الولايات (NI) استيفاء المعايير الطبية الفيدرالية من DOT وتقديم شهادة فاحص طبي (النموذج MCSA-5876). المصدر: صفحة CDL على ilsos.gov؛ 92 Ill. Admin. Code 1030.22."},"37":{"q":"أي قائمة تسمّي بشكل صحيح فئات الإقرار الذاتي الطبي الأربع التي يجب على مقدّمي طلبات CDL/CLP في إلينوي الاختيار من بينها؟","options":["غير المستثنى بين الولايات، والمستثنى بين الولايات، وغير المستثنى ضمن الولاية، والمستثنى ضمن الولاية","بين الولايات، وضمن الولاية، والمزرعة، والعسكري","الفئة A، والفئة B، والفئة C، والفئة D","محلي، وإقليمي، ووطني، ودولي"],"explanation":"تستخدم إلينوي فئات الإقرار الذاتي الفيدرالية الأربع: غير المستثنى بين الولايات (NI)، والمستثنى بين الولايات (EI)، وغير المستثنى ضمن الولاية (NA)، والمستثنى ضمن الولاية (EA). المصدر: صفحة CDL على ilsos.gov؛ 92 Ill. Admin. Code 1030.22."},"38":{"q":"بالنسبة لحامل CDL في إلينوي لديه مصادقة المواد الخطرة (H)، كم مرة يجب تجديد التقييم الأمني للتهديدات من TSA للحفاظ على المصادقة؟","options":["كل 5 سنوات","كل سنتين","كل 10 سنوات","مرة واحدة فقط، دون تجديد أبدًا"],"explanation":"يكون التقييم الأمني للتهديدات من TSA لمصادقة المواد الخطرة صالحًا لمدة 5 سنوات؛ وتتطلب إلينوي إجراء التقييم واختبار المعرفة الخاص بالمواد الخطرة عند كل تجديد، وينبغي للسائقين بدء التجديد قبل نحو 60 يومًا من انتهاء الصلاحية. المصدر: مصادقة المواد الخطرة على ilsos.gov؛ 49 CFR 1572."},"39":{"q":"بموجب قانون إلينوي، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز لحامل CDL أن يكون لديه أثناء تشغيل مركبة تجارية آلية (CMV)؟","options":["0.04 percent","0.08 percent","0.02 percent","0.00 percent"],"explanation":"ينص دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1) على أنه لا يجوز لحامل CDL تشغيل CMV بتركيز BAC يبلغ .04 percent أو أكثر، وهو نصف الحد البالغ .08 للمركبات الأخرى. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/11-501."},"40":{"q":"عندما يشغّل سائق مركبة على الطرق السريعة في إلينوي، فإن قانون الموافقة الضمنية في الولاية يعني أن السائق قد وافق مسبقًا على فعل ماذا؟","options":["الخضوع للفحوصات الكيميائية لتحديد تركيز الكحول في الدم","السماح بتفتيش حمولة المركبة في أي وقت","دفع غرامة قبل الاعتراض على أي مخالفة مرورية","تسليم CDL عند أي مخالفة سير"],"explanation":"ينص دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1) على أن السائقين الذين يشغّلون مركبة CMV أو غير CMV على الطرق السريعة قد وافقوا ضمنيًا على الخضوع للفحوصات الكيميائية لتحديد BAC. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/11-501.1."},"41":{"q":"في إلينوي، السائق الذي يرفض الخضوع للفحص الكيميائي أو يأتي فحصه فوق الحد القانوني يواجه إيقافًا عن الأهلية لمدة لا تقل عن كم لأول مخالفة (لغير المواد الخطرة)؟","options":["12 شهرًا","60 يومًا","6 أشهر","3 سنوات"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1): أي سائق يرفض الفحص الكيميائي أو يأتي فحصه أعلى من الحد القانوني يُوقَف عن الأهلية لمدة 12 شهرًا كحد أدنى. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"42":{"q":"إذا ارتكب سائق أول مخالفة كحول كبرى أثناء نقل مواد خطرة تحمل لافتات، فما هو الحد الأدنى لفترة الإيقاف عن الأهلية في إلينوي؟","options":["3 سنوات","سنة واحدة","5 سنوات","مدى الحياة"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1): إذا وقعت المخالفة أثناء نقل مواد خطرة تحمل لافتات، يُوقَف السائق عن الأهلية لمدة لا تقل عن ثلاث سنوات. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"43":{"q":"يرتكب سائق مخالفتين كبيرتين منفصلتين (مثل قيادتين تحت تأثير الكحول) ناشئتين عن حادثتين أو أكثر. ما هو الإيقاف عن الأهلية الناتج في إلينوي؟","options":["إيقاف عن الأهلية مدى الحياة","إيقاف عن الأهلية لمدة ثلاث سنوات","إيقاف عن الأهلية لمدة خمس سنوات","إيقاف عن الأهلية لمدة 120 يومًا"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1): أي سائق يرتكب اثنتين من المخالفات الكبرى المدرجة، ناشئتين عن حادثتين أو أكثر، يُوقَف عن الأهلية مدى الحياة. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"44":{"q":"في إلينوي، أي حامل CDL يشغّل CMV ويُكتشف أن لديه أي كحول في جسمه (أقل من 0.04) يُوضع خارج الخدمة لمدة لا تقل عن كم؟","options":["24 hours","1 hour","12 hours","72 hours"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1): أي حامل CDL يشغّل CMV ويُكتشف أن لديه أي كحول في جسمه يُوضع خارج الخدمة لمدة لا تقل عن 24 hours. المصدر: دليل دراسة CDL في إلينوي؛ 49 CFR 392.5."},"45":{"q":"ما هو الحد الأقصى المسموح به لتركيز BAC لسائق حافلة مدرسية يشغّل حافلة مدرسية في إلينوي؟","options":["0.00 percent","0.04 percent","0.02 percent","0.08 percent"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.1): لا يجوز لسائق الحافلة المدرسية تشغيل حافلة مدرسية بتركيز BAC يزيد على .00 percent. المصدر: دليل دراسة CDL في إلينوي."},"46":{"q":"مغادرة مكان الحادث عن علم وقصد أثناء تشغيل CMV تؤدي إلى إيقاف عن الأهلية في إلينوي لمدة لا تقل عن كم؟","options":["12 شهرًا","60 يومًا","120 يومًا","3 سنوات"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.2): مغادرة مكان الحادث عن علم وقصد أثناء تشغيل مركبة CMV أو غير CMV تؤدي إلى إيقاف عن الأهلية لمدة لا تقل عن 12 شهرًا. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"47":{"q":"استخدام مركبة آلية تجارية أو غير تجارية لارتكاب جناية تتضمّن تصنيع مادة خاضعة للرقابة أو توزيعها يؤدي إلى أي عقوبة في إلينوي؟","options":["إيقاف عن الأهلية مدى الحياة","إيقاف عن الأهلية لمدة سنة واحدة","إيقاف عن الأهلية لمدة ثلاث سنوات","إيقاف عن الأهلية لمدة 120 يومًا"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.2): استخدام مركبة CMV أو غير CMV في جناية تتضمّن تصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يؤدي إلى إيقاف عن الأهلية مدى الحياة. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"48":{"q":"بالنسبة لأول إدانة بمخالفة لوائح معابر السكك الحديدية والطرق السريعة في مركبة CMV، ما هي فترة الإيقاف عن الأهلية في إلينوي؟","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.2): أول إدانة بمخالفة معبر السكك الحديدية والطريق السريع تعني إيقافًا عن الأهلية لمدة 60 يومًا. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"49":{"q":"مخالفة ثانية لمعبر السكك الحديدية والطريق السريع خلال فترة ثلاث سنوات تؤدي إلى أي إيقاف عن الأهلية في إلينوي؟","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.2): الإدانة الثانية بمخالفة معبر السكك الحديدية والطريق السريع خلال ثلاث سنوات تعني إيقافًا عن الأهلية لمدة 120 يومًا. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"50":{"q":"مخالفة ثالثة أو لاحقة لمعبر السكك الحديدية والطريق السريع خلال فترة ثلاث سنوات تؤدي إلى أي إيقاف عن الأهلية في إلينوي؟","options":["سنة واحدة","120 يومًا","60 يومًا","مدى الحياة"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.2): الإدانة الثالثة واللاحقة بمخالفة معبر السكك الحديدية والطريق السريع خلال ثلاث سنوات تعني إيقافًا عن الأهلية لمدة سنة واحدة. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"51":{"q":"كم عدد المخالفات المرورية الجسيمة خلال فترة ثلاث سنوات التي تستوجب إيقافًا عن الأهلية لمدة 60 يومًا في إلينوي؟","options":["اثنتان","ثلاث","واحدة","أربع"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.3): مخالفتان مروريتان جسيمتان خلال فترة ثلاث سنوات تؤديان إلى إيقاف عن الأهلية لمدة 60 يومًا. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"52":{"q":"ثلاث مخالفات مرورية جسيمة خلال فترة ثلاث سنوات تؤدي إلى أي فترة إيقاف عن الأهلية في إلينوي؟","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.3): ثلاث مخالفات مرورية جسيمة خلال فترة ثلاث سنوات تؤدي إلى إيقاف عن الأهلية لمدة 120 يومًا. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"53":{"q":"عند أي سرعة فوق الحد المنشور تُحتسب مخالفة سرعة واحدة بوصفها 'مخالفة مرورية جسيمة' لحامل CDL في إلينوي؟","options":["15 mph أو أكثر فوق الحد","10 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","25 mph أو أكثر فوق الحد"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.3): السرعة المفرطة هي أي مخالفة واحدة تبلغ 15 mph أو أكثر فوق حد السرعة المنشور. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"54":{"q":"أي مما يلي يُصنَّف بوصفه 'مخالفة مرورية جسيمة' لحامل CDL في إلينوي؟","options":["تغيير المسارات المروري غير السليم أو المتقلّب","ملصق تسجيل مركبة منتهي الصلاحية","مخالفة وقوف في وسط المدينة","محور زائد الوزن على حمولة بتصريح"],"explanation":"يدرج دليل دراسة CDL لدى Illinois SOS (القسم 1.5.3) تغيير المسارات غير السليم/المتقلّب، والاقتراب الشديد من المركبة الأمامية، والقيادة المتهوّرة، والسرعة المفرطة، والمراسلة النصية أثناء قيادة CMV بوصفها مخالفات مرورية جسيمة. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"55":{"q":"وفقًا لدليل دراسة CDL في إلينوي، ما هو الإيقاف عن الأهلية لأول مخالفة لأمر إيقاف عن الخدمة؟","options":["90 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل","سنة واحدة على الأقل"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.4): تفقد CDL الخاص بك لمدة 90 يومًا على الأقل لأول مخالفة لأمر إيقاف عن الخدمة. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"56":{"q":"يرتكب سائق ثلاث مخالفات أو أكثر لأوامر الإيقاف عن الخدمة خلال فترة 10 سنوات. ما هو الحد الأدنى للإيقاف عن الأهلية في إلينوي؟","options":["3 سنوات","سنة واحدة","90 يومًا","مدى الحياة"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.4): ثلاث سنوات على الأقل لثلاث مخالفات أو أكثر لأوامر الإيقاف عن الخدمة خلال فترة 10 سنوات (المخالفة الثانية خلال 10 سنوات هي سنة واحدة على الأقل). المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-514."},"57":{"q":"كيف تصنّف إلينوي قيام سائق CMV بالمراسلة النصية أو استخدام هاتف خلوي محمول باليد أثناء قيادة CMV؟","options":["بوصفها مخالفة مرورية جسيمة","بوصفها مخالفة كبرى تسبّب إيقافًا عن الأهلية مدى الحياة","بوصفها مخالفة من نوع الوقوف دون أي أثر على CDL","بوصفها مخالفة لأمر إيقاف عن الخدمة"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.5.3): المراسلة النصية أو استخدام هاتف خلوي محمول باليد أثناء قيادة CMV مخالفة مرورية جسيمة؛ ويمكن أن تصل غرامة السائق من FMCSA إلى $2,750. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/12-610.2؛ 49 CFR 392.80/392.82."},"58":{"q":"ما هي الغرامة القصوى التي يجوز لمحكمة في إلينوي فرضها لقيادة مركبة تجارية آلية دون CDL ساري، أو لحيازة أكثر من رخصة واحدة؟","options":["حتى $5,000 أو السجن","حتى $1,000 فقط","حتى $500 فقط","حتى $10,000 أو السجن"],"explanation":"دليل دراسة CDL لدى Illinois SOS (القسم 1.6): يجوز لمحكمة فرض غرامة تصل إلى $5,000 أو السجن لقيادة CMV دون CDL أو لحيازة أكثر من رخصة واحدة. المصدر: دليل دراسة CDL في إلينوي؛ 625 ILCS 5/6-507."},"59":{"q":"يُلزِم قانون 'إفساح الطريق' في إلينوي (قانون سكوت) السائق الذي يقترب من مركبة طوارئ أو صيانة متوقفة تُظهر أضواء تحذير وامضة بأن يفعل ماذا؟","options":["أن ينتقل إلى مسار غير مجاور إن أمكن، وإلا فعليه أن يُبطئ السرعة ويتابع بحذر","أن يتوقف توقفاً تاماً وينتظر حتى تغادر مركبة الطوارئ","أن يحافظ على السرعة لكنه يُطلق البوق أثناء المرور","أن ينحرف إلى الكتف خلف مركبة الطوارئ ويتوقف"],"explanation":"بموجب قانون سكوت، 625 ILCS 5/11-907(c)، يجب على السائق الذي يقترب من مركبة طوارئ أو صيانة أو قطر متوقفة ذات أضواء وامضة أن ينتقل إلى مسار غير مجاور لها عندما يكون ذلك آمناً، وإذا تعذّر تغيير المسار فعليه أن يُخفّض السرعة ويتابع بحذر. المصدر: 625 ILCS 5/11-907؛ صفحة قانون إفساح الطريق لشرطة ولاية إلينوي (Illinois State Police)."},"60":{"q":"ما الاسم الشائع للقانون المسمّى باسم الملازم سكوت غيلن، الذي يُلزِم سائقي إلينوي بإفساح الطريق لمركبات الطوارئ المتوقفة؟","options":["قانون ستيف","قانون سكوت","قانون دان رايان","قانون الضوء الأصفر"],"explanation":"يُلقّب قانون إفساح الطريق في إلينوي رسمياً بـ'قانون سكوت'، نسبةً إلى الملازم سكوت غيلن من إدارة إطفاء شيكاغو، الذي صُدِم وقُتِل على طريق دان رايان السريع (Dan Ryan Expressway) عام 2000. المصدر: 625 ILCS 5/11-907؛ شرطة ولاية إلينوي (Illinois State Police)."},"61":{"q":"حافلة مدرسية ومركبة تحمل لافتات مواد خطرة يجب أن تتوقفا عند معبر سكة حديد في إلينوي، ضمن أي مسافة من أقرب قضيب يجب أن تتوقفا؟","options":["بين 5 و25 قدماً","بين 10 و35 قدماً","بين 15 و50 قدماً","بين 25 و75 قدماً"],"explanation":"يوجّه دليل إلينوي لرخصة القيادة التجارية (CDL) سائق الحافلة بأن 'يوقف حافلته بين 15 و50 قدماً قبل معابر السكك الحديدية'، وأن المركبة التي تحمل لافتات 'يجب أن تتوقف على مسافة 15 إلى 50 قدماً قبل أقرب قضيب'. المصدر: دليل دراسة CDL لـ Illinois SOS، القسمان 4.3.5 و9.6.12."},"62":{"q":"بموجب قانون إلينوي، ما الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك حمولتها، على أي طريق سريع في الولاية دون تصريح؟","options":["12 قدماً و6 إنشات","13 قدماً و6 إنشات","14 قدماً و0 إنش","13 قدماً و0 إنش"],"explanation":"تُحدّد إلينوي ارتفاع المركبة، مقاساً من أسفل الإطار إلى أعلى المركبة بما في ذلك الحمولة، بـ 13 قدماً و6 إنشات على أي طريق سريع. المصدر: 625 ILCS 5/15-103."},"63":{"q":"عندما يتعيّن على مركبة تجارية أن تتوقف على طريق سريع أحادي الاتجاه أو مقسوم في إلينوي أو بجانبه، على السائق أن يضع أجهزة التحذير الثلاثة على أي مسافات تقريبية باتجاه حركة المرور المقتربة؟","options":["10 و100 و200 قدم","10 و50 و100 قدم","25 و100 و250 قدماً","5 و75 و150 قدماً"],"explanation":"على طريق سريع أحادي الاتجاه أو مقسوم، يُلزِم دليل إلينوي لـ CDL بوضع أجهزة التحذير على مسافات 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 2.5 (أجهزة التحذير)."},"64":{"q":"في مقاطعات كوك ودوبيج وكين وليك وماكهنري وويل، تُقيّد شاحنة من الدرجة الثانية مسجَّلة لأكثر من 8,000 رطل بأي سرعة على الطرق والطرق السريعة والشوارع التي ليست طرقاً سريعة برسوم مرور (tollway interstates)؟","options":["65 ميلاً في الساعة","60 ميلاً في الساعة","55 ميلاً في الساعة","45 ميلاً في الساعة"],"explanation":"في تلك المقاطعات الست، تُقيّد الشاحنات التي تتجاوز 8,000 رطل بحدّ أقصى 60 ميلاً في الساعة على الطرق السريعة برسوم مرور في إلينوي (Illinois Tollway) و55 ميلاً في الساعة على جميع الطرق أو الطرق السريعة أو الشوارع الأخرى. المصدر: 625 ILCS 5/11-601(e)."},"65":{"q":"خارج المنطقة الحضرية على طريق سريع ريفي بين الولايات في إلينوي محدّد بـ 70 ميلاً في الساعة (وخارج مقاطعات شيكاغو الست المحيطة)، بأي سرعة قصوى يجوز لشاحنة كبيرة أن تسير بموجب قانون إلينوي الحالي؟","options":["55 ميلاً في الساعة","60 ميلاً في الساعة","65 ميلاً في الساعة","70 ميلاً في الساعة"],"explanation":"منذ تعديل عام 2014 على 625 ILCS 5/11-601، يجوز للشاحنات على الطرق السريعة الريفية بين الولايات خارج المقاطعات الست المحيطة أن تسير بنفس الحد المحدّد للسيارات، حتى 70 ميلاً في الساعة؛ ولا تخضع لحدود أدنى خاصة بالشاحنات إلا في مقاطعات كوك ودوبيج وكين وليك وماكهنري وويل. المصدر: 625 ILCS 5/11-601(d-1)، (e)."},"66":{"q":"أثناء عبور سكك حديدية في إلينوي، ماذا ينبغي أن يفعل سائق رخصة القيادة التجارية (CDL) من بين ما يلي؟","options":["أن يبدّل إلى تروس أدنى في منتصف العبور للحصول على قوة إضافية","ألّا يبدّل التروس أثناء عبور السكك","أن يبدّل إلى الوضع المحايد ويعبر انزلاقاً","أن يرفع التروس لاجتياز السكك بأسرع ما يمكن"],"explanation":"ينصّ دليل إلينوي لـ CDL بوضوح: 'لا تبدّل التروس أثناء عبور السكك الحديدية'، لأن تبديلاً فائتاً أو محتكّاً قد يُوقف المركبة على السكك. المصدر: دليل دراسة CDL لـ Illinois SOS، القسمان الفرعيان 2.15 و9.6.12."},"67":{"q":"على طريق سريع في إلينوي من أربعة مسارات أو أكثر يسمح بحركة مسارين على الأقل في اتجاهين متعاكسين، السائق الذي يلتقي بحافلة مدرسية متوقفة في الطريق المقابل عليه أن يفعل ماذا؟","options":["أن يتوقف ويبقى متوقفاً حتى تتوقف الأضواء الحمراء للحافلة عن الوميض","أن يتوقف فقط إذا كان الأطفال ظاهرين","ليس عليه التوقف، لكن ينبغي أن يبقى يقظاً","أن يُبطئ إلى 20 ميلاً في الساعة ويتابع بجانب الحافلة"],"explanation":"ينصّ قانون إلينوي على أن السائق على طريق سريع من 4 مسارات أو أكثر يسمح بحركة مسارين على الأقل في اتجاهين متعاكسين ليس مُلزَماً بالتوقف عند الالتقاء بحافلة مدرسية متوقفة في الطريق المقابل. المصدر: 625 ILCS 5/11-1414(e)."},"68":{"q":"باستثناء حالة الطريق السريع المقسوم، عندما تتوقف حافلة مدرسية على طريق في إلينوي وأضواء إشارتها المرئية وامضة لتحميل التلاميذ أو إنزالهم، ماذا يجب أن يفعل السائقون المقتربون؟","options":["أن يتوقفوا قبل الالتقاء بالحافلة أو تجاوزها من أي اتجاه","أن يتوقفوا فقط إذا اقتربوا من خلف الحافلة","أن يمرّوا ببطء على اليسار بسرعة لا تتجاوز 10 أميال في الساعة","أن يتوقفوا فقط عندما يشير لهم حارس عبور بذلك"],"explanation":"تُلزِم إلينوي السائقين بإيقاف المركبة قبل الالتقاء بأي حافلة مدرسية أو تجاوزها، من أي اتجاه، إذا كانت قد توقفت وتُظهر أضواء إشارتها المرئية لاستقبال التلاميذ أو إنزالهم. المصدر: 625 ILCS 5/11-1414(a)."},"69":{"q":"إضافةً إلى المركبات التي تحمل لافتات، أيٌّ مما يلي يجب أن يتوقف دائماً قبل عبور السكك الحديدية في إلينوي؟","options":["أي شاحنة مستقيمة يزيد وزنها عن 10,000 رطل","أي مركبة تحمل أي كمية من الكلور","أي مركبة تجرّ مقطورة مسطحة","أي مركبة مسجّلة خارج الولاية"],"explanation":"يُدرِج دليل إلينوي لـ CDL ثلاث فئات يجب أن تتوقف قبل معبر السكة الحديد: المركبات التي تحمل لافتات، والمركبات التي تحمل أي كمية من الكلور، وصهاريج الشحن (محمَّلة أو فارغة) المستخدمة للمواد الخطرة. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 9.6.12."},"70":{"q":"ما الحد الأقصى القانوني للعرض (باستثناء المرايا وبعض أجهزة السلامة) لمركبة أو حمولتها على الطرق السريعة في إلينوي دون تصريح؟","options":["8 أقدام و0 إنش","8 أقدام و6 إنشات","9 أقدام و0 إنش","10 أقدام و0 إنش"],"explanation":"تُحدّد إلينوي إجمالي العرض الخارجي لمركبة أو حمولة بـ 8 أقدام و6 إنشات؛ وأي شيء أعرض من ذلك يتطلب تصريحاً للحجم الزائد من IDOT. المصدر: 625 ILCS 5/15-102."},"71":{"q":"عندما يتعيّن على سائق رخصة القيادة التجارية (CDL) أن يتوقف على الكتف أو على طريق أي طريق سريع في إلينوي، خلال كم دقيقة يجب وضع أجهزة التحذير من الطوارئ؟","options":["5 دقائق","10 دقائق","15 دقيقة","30 دقيقة"],"explanation":"يُلزِم دليل إلينوي لـ CDL بوضع أجهزة التحذير خلال 10 دقائق من التوقف على الطريق أو الكتف. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 2.5."},"72":{"q":"كم عدد مثلثات التحذير العاكسة الحمراء التي يجب أن تحملها مركبة تجارية لاستيفاء شرط أجهزة التحذير في إلينوي؟","options":["اثنان","ثلاثة","أربعة","ستة"],"explanation":"يُلزِم دليل إلينوي لـ CDL بثلاثة مثلثات تحذير عاكسة (أو بدلاً من ذلك ستة شُعَل أو ثلاث شعلات سائلة الاحتراق) كجزء من معدّات الطوارئ المطلوبة. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 2.1."},"73":{"q":"السائق الذي يحمل مواد خطرة بلافتات ويُدان بمخالفة معبر التقاطع بين السكة الحديد والطريق في إلينوي يواجه أي عاقبة؟","options":["تحذير خطّي فقط","أمر إخراج من الخدمة لمدة 24 ساعة","إسقاط أهلية رخصة القيادة التجارية (CDL)","نقاط لكن دون إسقاط أهلية"],"explanation":"مخالفات معبر التقاطع بين السكة الحديد والطريق هي مخالفات مُسقِطة للأهلية لحاملي CDL في إلينوي، مع فترات إسقاط أهلية متصاعدة (60 يوماً، ثم 120 يوماً، ثم سنة واحدة) للمخالفات المتكررة خلال ثلاث سنوات. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 1.2 (إسقاط الأهلية)؛ 49 CFR 383.51 بحسب اعتماد إلينوي."},"74":{"q":"مخالفة أولى لقانون سكوت (قانون إفساح الطريق في إلينوي) تستوجب غرامة لا تقل عن كم؟","options":["$100","$250","$500","$1,000"],"explanation":"بعد القانون العام 101-0173، تُعدّ مخالفة قانون سكوت مخالفةً تجارية بغرامة لا تقل عن $250 وتصل إلى $10,000 للمخالفة الأولى. المصدر: 625 ILCS 5/11-907(c)."},"75":{"q":"على طريق ليك شور درايف في شيكاغو، المصنَّف قانونياً كجادّة/متنزّه طرقي، ما الذي يُحظر عموماً؟","options":["المركبات ذات لوحات الشاحنات (التجارية) المصمّمة لنقل البضائع","جميع المركبات أثناء ساعات الذروة في أيام الأسبوع","سيارات الركاب التي تجرّ مقطورات فقط","المركبات التي لا تحمل جهاز إرسال I-PASS الخاص بإلينوي"],"explanation":"ليك شور درايف مُصنَّف كجادّة، وتُمنع منه المركبات التي تحمل لوحات شاحنات مصمّمة لنقل البضائع أو السلع التجارية، وهو قيد توجيهي مميّز في شيكاغو متجذّر في أصوله كـ'طريق للنزهة'. المصدر: قيود الجادّات في مدونة شيكاغو البلدية؛ إرشادات تصريح مرور الشاحنات على ليك شور درايف من CDOT."},"76":{"q":"عند معبر سكة حديد يُطلب فيه التوقف عادةً، لا يتعيّن على سائق حافلة في إلينوي أن يتوقف توقفاً تاماً، لكن عليه أن يُبطئ ويتفحّص بعناية، في أي حالة؟","options":["عندما يكون المعبر على طريق حصوي","عندما يوجّه ضابط شرطة أو موجِّه إشارات حركة المرور","عندما تكون الحافلة خالية من الركاب","عندما يزيد طول الحافلة عن 40 قدماً"],"explanation":"ينصّ دليل إلينوي لـ CDL على أن الحافلة لا يلزمها التوقف، لكن عليها أن تُبطئ وتتفحّص بعناية، عند معابر الترام، أو حيث يوجّه شرطي أو موجِّه إشارات حركة المرور، أو عندما تُظهِر إشارة المرور اللون الأخضر. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 4.3.5."},"77":{"q":"لأن تضاريس إلينوي مسطّحة إلى حد كبير، فإن منحدرات الهروب التقليدية للشاحنات المنفلتة بأسلوب الجاذبية نادرة. ماذا يعني هذا لسائق رخصة القيادة التجارية (CDL) الذي ينزل منحدراً طويلاً أو مقترَب جسر في إلينوي؟","options":["يمكنهم الاعتماد على إيجاد منحدر هروب أسفل أي انحدار","ينبغي ألّا يعتمدوا على منحدر هروب وعليهم التحكم في السرعة بكبح وتعشيق سليمين","يحظر قانون إلينوي استخدام مكابح المحرك على جميع الانحدارات","منحدرات الهروب إلزامية على كل انحدار في الطرق السريعة بين الولايات في إلينوي"],"explanation":"بخلاف الولايات الجبلية، فإن تضاريس إلينوي المسطّحة تعني أن منحدرات الهروب نادرة، لذا على السائقين إدارة الانحدارات بتروس منخفضة سليمة وتقنية كبح صحيحة بدلاً من توقّع منحدر للمنفلتة. المصدر: دليل دراسة CDL لـ Illinois SOS، القسم الفرعي 2.16 (القيادة الجبلية / التحكم في السرعة على الانحدارات)."},"78":{"q":"سائق في إلينوي يقترب من حافلة مدرسية متوقفة على طريق سريع ثنائي المسار غير مقسوم، مسافراً في أي من الاتجاهين، ماذا يجب أن يفعل؟","options":["أن يتابع بسرعة مخفّضة بجانب الحافلة","أن يتوقف قبل بلوغ الحافلة ويبقى متوقفاً حتى تُطفأ الإشارات","أن يتوقف فقط إذا اقترب من نفس اتجاه الحافلة","أن يمرّ على اليسار بعد إطلاق البوق"],"explanation":"على طريق سريع ثنائي المسار غير مقسوم لا ينطبق استثناء الطريق المقسوم، لذا يجب على السائقين المقتربين من أي اتجاه التوقف قبل الالتقاء بحافلة مدرسية تُظهر إشاراتها الحمراء أو تجاوزها، والبقاء متوقفين حتى تتوقف الإشارات وتستأنف الحافلة حركتها. المصدر: 625 ILCS 5/11-1414(a) و(b)."},"79":{"q":"في إلينوي، أي وكالة حكومية تُصدِر رخص القيادة التجارية وتدير اختبارات المعرفة والمهارات لرخصة القيادة التجارية (CDL)؟","options":["وزير خارجية إلينوي (Illinois Secretary of State)","إدارة النقل في إلينوي (IDOT)","شرطة ولاية إلينوي (Illinois State Police)","إدارة المركبات الآلية في إلينوي"],"explanation":"لا تملك إلينوي 'DMV'؛ فمكتب وزير خارجية إلينوي (SOS) هو سلطة ترخيص السائقين في الولاية التي تُصدِر رخص CDL وتدير الاختبارات في مرافق CDL التابعة لخدمات السائقين لديها. المصدر: دليل دراسة CDL لـ Illinois SOS (DSD CDL) وصفحات CDL على ilsos.gov."},"80":{"q":"أين يؤدّي المتقدّم في إلينوي اختبارات معرفة CDL واختبار المهارات (القيادة)؟","options":["في مرفق CDL التابع لخدمات السائقين لوزير الخارجية (Secretary of State Driver Services)","في أي مركز محلي لشرطة ولاية إلينوي","فقط في مركز اختبار اتحادي تابع لـ FMCSA","في محطة وزن تابعة لإدارة النقل في إلينوي"],"explanation":"يُجرى اختبار CDL الكتابي والمهاري من قِبل وزير الخارجية في مرافق CDL المخصّصة التابعة لخدمات السائقين. المصدر: دليل دراسة CDL لـ Illinois SOS وصفحات اختبار/جدولة CDL على ilsos.gov."},"81":{"q":"كم عدد فئات الإقرار الذاتي التي يجب على المتقدّم لـ CDL/CLP في إلينوي أن يختار منها عند إعلان نوع التجارة التي يعمل فيها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"تتّبع إلينوي القاعدة الاتحادية لـ CDL التي تُلزِم السائقين بالإقرار الذاتي ضمن إحدى أربع فئات: غير مُستثناة بين الولايات، ومُستثناة بين الولايات، وغير مُستثناة داخل الولاية، ومُستثناة داخل الولاية. المصدر: دليل دراسة CDL لـ Illinois SOS؛ 49 CFR 383.71."},"82":{"q":"السائق في إلينوي الذي يعمل عبر حدود الولايات وليس مُعفىً من القواعد الاتحادية للتأهيل البدني يجب أن يُقرّ ذاتياً بأنه من أي فئة؟","options":["غير مُستثنى بين الولايات (NI)","مُستثنى بين الولايات (EI)","غير مُستثنى داخل الولاية (NA)","مُستثنى داخل الولاية (EA)"],"explanation":"السائق في التجارة بين الولايات الذي يجب أن يستوفي المعايير الطبية الاتحادية لـ DOT يُقرّ ذاتياً بأنه غير مُستثنى بين الولايات (NI) ويجب أن يحتفظ بشهادة فاحص طبي سارية. المصدر: دليل دراسة CDL لـ Illinois SOS؛ 49 CFR 383.71."},"83":{"q":"أي فئة من فئات الإقرار الذاتي تنطبق على سائق في إلينوي يعمل داخل إلينوي فقط وغير مُلزَم باستيفاء متطلبات الشهادة الطبية؟","options":["مُستثنى داخل الولاية (EA)","غير مُستثنى بين الولايات (NI)","مُستثنى بين الولايات (EI)","غير مُستثنى داخل الولاية (NA)"],"explanation":"السائق الذي يعمل حصرياً في التجارة داخل الولاية (داخل إلينوي) وليس مُلزَماً باستيفاء متطلبات الشهادة الطبية يُقرّ ذاتياً بأنه مُستثنى داخل الولاية (EA). المصدر: دليل دراسة CDL لـ Illinois SOS؛ 49 CFR 383.71."},"84":{"q":"أي نموذج اتحادي هو شهادة الفاحص الطبي التي يجب على حامل CDL غير المُستثنى بين الولايات في إلينوي أن يبقيها سارية؟","options":["النموذج MCSA-5876","النموذج MCSA-5875","النموذج SS-CDL-2","النموذج DL-180"],"explanation":"شهادة الفاحص الطبي الرسمية هي نموذج FMCSA رقم MCSA-5876، الصادر عن فاحص طبي معتمد. ويجب على السائقين غير المُستثنين الاحتفاظ بشهادة سارية مودعة لدى الولاية. المصدر: FMCSA؛ صفحات CDL لـ Illinois SOS."},"85":{"q":"اعتباراً من تغيير عام 2025 في إلينوي، كيف تصل شهادة الفاحص الطبي لحامل CDL عادةً إلى وزير الخارجية (Secretary of State)؟","options":["يقدّمها الفاحص الطبي المعتمد إلكترونياً عبر السجل الوطني لـ FMCSA","يرسل السائق نسخة ورقية بالبريد إلى وزير الخارجية","يرسلها السائق بالفاكس إلى مرفق CDL خلال 15 يوماً","يسلّمها السائق باليد بطاقةً ورقية في أي مرفق CDL"],"explanation":"بدءاً من انضمام إلينوي إلى تكامل السجل الوطني لـ FMCSA (منتصف 2025)، يرسل الفاحصون الطبيون المعتمدون نتائج الفحص إلكترونياً إلى FMCSA، التي توفّرها لـ SOS؛ ولم تعد الولاية تقبل البطاقات الطبية الورقية في مرافق CDL. المصدر: صفحات CDL لـ Illinois SOS؛ السجل الوطني لـ FMCSA."},"86":{"q":"كم مرة يجب على حامل CDL غير المُستثنى بين الولايات في إلينوي عموماً أن يُحدّث الإقرار الذاتي ويقدّم شهادة طبية سارية؟","options":["كل سنتين على الأقل (أو أقرب إذا كان انتهاء صلاحية الشهادة أقصر)","كل 5 سنوات مع تجديد الرخصة","كل 4 سنوات مع تجديد الرخصة","مرة واحدة فقط، عند الترخيص الأولي"],"explanation":"شهادة الفاحص الطبي سارية لمدة أقصاها سنتان (أقل إذا حدّد الفاحص ذلك)، لذا يجب على السائقين غير المُستثنين بين الولايات إبقاء الشهادة الطبية سارية بدورة لا تتجاوز سنتين، بصرف النظر عن دورة الرخصة البالغة 4 سنوات. المصدر: صفحات CDL لـ Illinois SOS؛ 49 CFR 391.45."},"87":{"q":"قبل تحديد موعد اختبار مهارات CDL في إلينوي، على المتقدّم لرخصة الفئة A أو الفئة B الأولية أن يُكمل أي متطلب تدريبي؟","options":["تدريب السائقين المبتدئين (ELDT) من مزوّد مسجَّل لدى FMCSA","دورة قيادة دفاعية في إلينوي مدتها 30 ساعة","ندوة سلامة صفّية تابعة لوزير خارجية إلينوي","تدرّب مهني تديره الولاية مدته 6 أشهر"],"explanation":"تُلزِم قواعد ELDT الاتحادية، المعتمَدة في إلينوي، المتقدّمين الأوليين للفئة A/الفئة B (وبعض الترقيات/التظهيرات) بإكمال تدريب السائقين المبتدئين من مزوّد مدرَج في سجل مزوّدي التدريب لدى FMCSA قبل الاختبار. المصدر: صفحة ELDT لـ Illinois SOS؛ 49 CFR Part 380."},"88":{"q":"بموجب متطلب ELDT في إلينوي، يجب إكمال الجزء النظري من التدريب قبل أي خطوة؟","options":["أداء اختبار معرفة CDL (الكتابي) للفئة أو التظهير الجديد","التقدّم لرخصة قيادة أساسية في إلينوي","تجديد رخصة غير تجارية قائمة","تحديد موعد فحص النظر"],"explanation":"تُلزِم إلينوي المتقدّمين الساعين للحصول على رخصة CDL أولية من الفئة A أو B، أو ترقية، أو تظهير أولي S أو P أو H بإكمال تدريب ELDT النظري من مزوّد مسجَّل قبل أداء اختبار المعرفة ذي الصلة. المصدر: صفحة ELDT لـ Illinois SOS؛ 49 CFR Part 380."},"89":{"q":"أيٌّ من هذه التظهيرات يتطلب إكمال ELDT قبل أن يتمكّن المتقدّم في إلينوي من الاختبار له؟","options":["الركاب (P)، والحافلات المدرسية (S)، والمواد الخطرة (H)","المقطورات المزدوجة/الثلاثية (T) فقط","مركبة الصهريج (N) فقط","لا تتطلب أي تظهيرات ELDT في إلينوي"],"explanation":"ينطبق ELDT على الإصدار الأولي لتظهيرات الحافلات المدرسية (S)، والركاب (P)، والمواد الخطرة (H)، إضافةً إلى رخص الفئة A/B الأولية والترقيات. المصدر: صفحة ELDT لـ Illinois SOS؛ 49 CFR Part 380."},"90":{"q":"ما الذي يجب أن يحصل عليه السائق في إلينوي أولاً كخطوة تتيح التدرّب على القيادة الفعلية قبل أداء اختبار مهارات CDL؟","options":["تصريح متعلّم القيادة التجارية (CLP)","إعفاء مؤقت للعمل بين الولايات","بطاقة تظهير تجاري مؤقت","إعفاء من اختبار الطريق من FMCSA"],"explanation":"بعد اجتياز اختبار (اختبارات) المعرفة المطلوبة، يُصدَر للمتقدّم تصريح متعلّم القيادة التجارية (CLP)، الذي يُجيز التدرّب تحت إشراف في مركبة تمثيلية قبل اختبار المهارات. المصدر: دليل دراسة CDL لـ Illinois SOS؛ 49 CFR 383.25."},"91":{"q":"بعد إصدار تصريح CLP في إلينوي، كم يجب أن ينتظر الحامل قبل أن يُسمح له بأداء اختبار مهارات CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","7 أيام على الأقل","لا توجد فترة انتظار"],"explanation":"يُلزِم القانون الاتحادي المعتمَد من إلينوي بفترة انتظار لا تقل عن 14 يوماً من تاريخ إصدار CLP قبل أن يُجرى اختبار المهارات؛ ويجوز للمتقدّم تحديد موعد مسبقاً لكن لا يمكنه اختيار تاريخ ضمن الـ 14 يوماً. المصدر: صفحات CDL لـ Illinois SOS؛ 49 CFR 383.25."},"92":{"q":"يُجرى اختبار مهارات CDL في إلينوي على ثلاثة أجزاء. ما الترتيب الصحيح الذي تُجرى به؟","options":["فحص ما قبل الرحلة (المركبة)، ثم مهارات التحكم الأساسية، ثم اختبار القيادة على الطريق","اختبار القيادة على الطريق، ثم مهارات التحكم الأساسية، ثم فحص ما قبل الرحلة","مهارات التحكم الأساسية، ثم اختبار القيادة على الطريق، ثم فحص ما قبل الرحلة","فحص ما قبل الرحلة، ثم اختبار القيادة على الطريق، ثم مهارات التحكم الأساسية"],"explanation":"يُجرى اختبار المهارات بالترتيب: (1) فحص ما قبل الرحلة (المركبة)، (2) مهارات التحكم الأساسية، (3) اختبار القيادة على الطريق. المصدر: دليل دراسة CDL لـ Illinois SOS وصفحات CDL على ilsos.gov."},"93":{"q":"أثناء جزء فحص ما قبل الرحلة من اختبار مهارات إلينوي، يجب على المتقدّم بصورة أساسية أن يُظهر القدرة على:","options":["تحديد المكوّنات التي ينبغي فحصها وتفسير سبب أهمية كل منها للتشغيل الآمن","تفكيك نظام المكابح وإعادة تركيبه","تلاوة كامل مدونة مركبات إلينوي عن ظهر قلب","استبدال إطار خلال مهلة زمنية محدّدة"],"explanation":"يتطلب اختبار فحص المركبة من المتقدّم تحديد مواقع العناصر، وذكر ما يجري فحصه، وتفسير سبب أهمية الفحص للتشغيل الآمن. المصدر: دليل دراسة CDL لـ Illinois SOS (القسم 11، اختبار فحص المركبة)."},"94":{"q":"أيٌّ مما يلي جزء من قسم مهارات التحكم الأساسية في اختبار مهارات CDL في إلينوي؟","options":["مناورات الرجوع للخلف المنضبطة مثل الرجوع المستقيم والرجوع المُزاح","الاندماج في طريق سريع بين الولايات بالسرعة الكاملة","الإجابة عن 50 سؤالاً كتابياً من نوع الاختيار من متعدد","ربط لافتة مواد خطرة بالمقطورة"],"explanation":"يقيّم اختبار مهارات التحكم الأساسية التحكم الدقيق في المركبة بسرعة منخفضة من خلال مناورات مثل الرجوع المستقيم، والرجوع المُزاح، والركن، وعادةً على ساحة. المصدر: دليل دراسة CDL لـ Illinois SOS (اختبار مهارات التحكم الأساسي بالمركبة)."},"95":{"q":"ما الحد الأدنى للدرجة التي يجب أن يحقّقها المتقدّم لاجتياز كل اختبار معرفة CDL (كتابي) في إلينوي؟","options":["80% صحيحة","70% صحيحة","75% صحيحة","90% صحيحة"],"explanation":"تتطلب اختبارات معرفة CDL في إلينوي حدّاً أدنى 80% صحيحة للاجتياز، بما يتوافق مع المعيار الاتحادي. المصدر: دليل دراسة CDL لـ Illinois SOS؛ 49 CFR 383.135."},"96":{"q":"ما دورة التجديد القياسية لرخصة القيادة التجارية في إلينوي لسائق في الفئة العمرية المعتادة؟","options":["كل 4 سنوات","كل سنتين","كل 5 سنوات","كل 8 سنوات"],"explanation":"تُصدَر رخصة CDL القياسية في إلينوي بدورة مدتها 4 سنوات، تنتهي عموماً في عيد ميلاد الحامل؛ ويتطلب التجديد أيضاً إقراراً ذاتياً سارياً، وللسائقين غير المُستثنين شهادةً طبية سارية. المصدر: صفحات CDL لـ Illinois SOS ومعلومات تجديد خدمات السائقين."},"97":{"q":"ما الحد الأدنى للسن للتقدّم لرخصة CDL في إلينوي للقيادة في التجارة بين الولايات أو لنقل الركاب، مقابل القيادة داخل الولاية فقط؟","options":["21 للتجارة بين الولايات أو الركاب؛ 18 لداخل الولاية فقط","18 للتجارة بين الولايات أو الركاب؛ 16 لداخل الولاية فقط","25 للتجارة بين الولايات أو الركاب؛ 21 لداخل الولاية فقط","21 لكلٍّ من بين الولايات وداخل الولاية"],"explanation":"يجب أن يكون عمر المتقدّم 21 على الأقل للعمل في التجارة بين الولايات أو نقل الركاب، و18 على الأقل للحصول على CDL/CLP للعمل داخل الولاية فقط. المصدر: دليل دراسة CDL لـ Illinois SOS وصفحات CDL على ilsos.gov."}}};
